{
  "name": "GourmetPOS & Inventory",
  "description": "Un sistema integral de punto de venta y control de inventario para negocios de alimentos, con estadísticas financieras avanzadas y reportes PDF detallados.",
  "requestFramePermissions": ["camera"]
}

export interface Category {
  id: string;
  name: string;
}

export interface Product {
  id: string;
  name: string;
  categoryId: string;
  code: string;
  image: string; // Base64
  costPrice: number;
  salePrice: number;
  stock: number;
}

export interface InventoryMovement {
  id: string;
  productId: string;
  quantity: number;
  type: 'in' | 'out';
  reason: string;
  date: number;
}

export interface SaleItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
}

export interface Sale {
  id: string;
  items: SaleItem[];
  total: number;
  paymentMethod: 'cash' | 'transfer';
  date: number;
}

export interface FinancialSettings {
  initialInvestment: number;
  workerSalaryRate: number; // e.g., 1.5
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, LayoutGrid, BarChart3, Settings, Menu, X, PlusCircle, Trash2, ArrowUpRight, ArrowDownRight, Tag } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Categories from './components/Categories';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'pos' | 'inventory' | 'products' | 'categories' | 'stats'>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
  }, []);

  // Auto-Save Effect
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
  }, [products, categories, sales, movements, financialSettings]);

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      quantity,
      type,
      reason,
      date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);

    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        return { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity };
      }
      return p;
    }));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => {
      addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`);
    });
  }, [addMovement]);

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'categories', icon: LayoutGrid, label: 'Categorías' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">GourmetPOS</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-8">GourmetPOS</h1>
          <nav className="space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as any);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
        <div className="absolute bottom-0 w-full p-6 border-t bg-slate-50/50">
          <p className="text-xs text-slate-400 font-medium uppercase tracking-wider mb-2">Sistema</p>
          <div className="flex items-center space-x-2 text-slate-600">
            <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
            <span className="text-sm">Auto-guardado activo</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && (
            <POS 
              products={products} 
              categories={categories} 
              onCompleteSale={completeSale} 
            />
          )}
          {activeTab === 'products' && (
            <Products 
              products={products} 
              categories={categories} 
              setProducts={setProducts} 
              addMovement={addMovement}
            />
          )}
          {activeTab === 'categories' && (
            <Categories 
              categories={categories} 
              setCategories={setCategories} 
            />
          )}
          {activeTab === 'inventory' && (
            <Inventory 
              movements={movements} 
              products={products} 
              addMovement={addMovement}
            />
          )}
          {activeTab === 'stats' && (
            <Statistics 
              sales={sales} 
              products={products} 
              categories={categories}
              settings={financialSettings}
              setSettings={setFinancialSettings}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, CreditCard, Banknote, Plus, Minus } from 'lucide-react';
import { Product, Category, Sale, SaleItem } from '../types';

interface POSProps {
  products: Product[];
  categories: Category[];
  onCompleteSale: (sale: Sale) => void;
}

const POS: React.FC<POSProps> = ({ products, categories, onCompleteSale }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'cash' | 'transfer'>('cash');

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm);
      const matchesCategory = selectedCategory === 'all' || p.categoryId === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchTerm, selectedCategory]);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) {
      alert("Producto sin stock");
      return;
    }
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      if (existing.quantity >= product.stock) {
        alert("No hay más stock disponible");
        return;
      }
      setCart(cart.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { productId: product.id, name: product.name, price: product.salePrice, quantity: 1 }]);
    }
  };

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.productId === productId) {
        const newQty = item.quantity + delta;
        const product = products.find(p => p.id === productId);
        if (newQty <= 0) return null;
        if (product && newQty > product.stock) {
          alert("Excede el stock disponible");
          return item;
        }
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(Boolean) as SaleItem[]);
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;
    const newSale: Sale = {
      id: Math.random().toString(36).substr(2, 9),
      items: [...cart],
      total: cartTotal,
      paymentMethod,
      date: Date.now()
    };
    onCompleteSale(newSale);
    setCart([]);
    alert("Venta realizada con éxito");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
      {/* Product Selection */}
      <div className="lg:col-span-8 flex flex-col space-y-4">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar producto o código..." 
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="px-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            <option value="all">Todas las categorías</option>
            {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto no-scrollbar">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              className={`bg-white p-3 rounded-2xl shadow-sm border border-slate-100 hover:border-emerald-300 transition-all text-left group flex flex-col ${product.stock <= 0 ? 'opacity-50 grayscale' : ''}`}
            >
              <div className="aspect-square rounded-xl bg-slate-100 mb-3 overflow-hidden relative">
                {product.image ? (
                  <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-slate-300">
                    <ShoppingCart size={32} />
                  </div>
                )}
                <div className="absolute bottom-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded-lg text-xs font-bold text-emerald-600">
                  Stock: {product.stock}
                </div>
              </div>
              <h3 className="font-semibold text-slate-800 line-clamp-1">{product.name}</h3>
              <p className="text-emerald-600 font-bold mt-1">${product.salePrice.toLocaleString()}</p>
            </button>
          ))}
        </div>
      </div>

      {/* Cart Panel */}
      <div className="lg:col-span-4 bg-white rounded-3xl shadow-xl border border-slate-100 flex flex-col h-[calc(100vh-8rem)] sticky top-8">
        <div className="p-6 border-b">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <ShoppingCart className="text-emerald-600" />
            Carrito de Compra
          </h2>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-50 space-y-2">
              <ShoppingCart size={48} />
              <p>El carrito está vacío</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.productId} className="flex items-center gap-3 p-3 bg-slate-50 rounded-2xl">
                <div className="flex-1">
                  <h4 className="font-medium text-slate-800 line-clamp-1">{item.name}</h4>
                  <p className="text-emerald-600 font-bold">${(item.price * item.quantity).toLocaleString()}</p>
                </div>
                <div className="flex items-center gap-2 bg-white rounded-xl border border-slate-200 p-1">
                  <button onClick={() => updateCartQuantity(item.productId, -1)} className="p-1 hover:text-emerald-600 transition-colors">
                    <Minus size={16} />
                  </button>
                  <span className="w-6 text-center font-bold">{item.quantity}</span>
                  <button onClick={() => updateCartQuantity(item.productId, 1)} className="p-1 hover:text-emerald-600 transition-colors">
                    <Plus size={16} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-slate-50 rounded-b-3xl space-y-4">
          <div className="flex items-center justify-between text-slate-500 text-sm">
            <span>Subtotal</span>
            <span>${cartTotal.toLocaleString()}</span>
          </div>
          <div className="flex items-center justify-between font-bold text-xl text-slate-800">
            <span>Total</span>
            <span>${cartTotal.toLocaleString()}</span>
          </div>

          <div className="grid grid-cols-2 gap-3 pt-2">
            <button 
              onClick={() => setPaymentMethod('cash')}
              className={`flex flex-col items-center justify-center p-3 rounded-2xl border-2 transition-all ${paymentMethod === 'cash' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-white border-transparent text-slate-500'}`}
            >
              <Banknote size={24} />
              <span className="text-xs font-bold mt-1">Efectivo</span>
            </button>
            <button 
              onClick={() => setPaymentMethod('transfer')}
              className={`flex flex-col items-center justify-center p-3 rounded-2xl border-2 transition-all ${paymentMethod === 'transfer' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-white border-transparent text-slate-500'}`}
            >
              <CreditCard size={24} />
              <span className="text-xs font-bold mt-1">Transferencia</span>
            </button>
          </div>

          <button 
            disabled={cart.length === 0}
            onClick={handleCheckout}
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50 disabled:grayscale"
          >
            Completar Venta
          </button>
        </div>
      </div>
    </div>
  );
};

export default POS;

import React, { useState } from 'react';
import { Plus, Search, Edit2, Trash2, Camera, X } from 'lucide-react';
import { Product, Category } from '../types';

interface ProductsProps {
  products: Product[];
  categories: Category[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  addMovement: (productId: string, quantity: number, type: 'in' | 'out', reason: string) => void;
}

const Products: React.FC<ProductsProps> = ({ products, categories, setProducts, addMovement }) => {
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    categoryId: '',
    code: '',
    image: '',
    costPrice: 0,
    salePrice: 0,
    stock: 0
  });

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.categoryId) return alert("Selecciona una categoría");

    if (editingId) {
      setProducts(prev => prev.map(p => p.id === editingId ? { ...formData, id: editingId } : p));
    } else {
      const newProduct: Product = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      };
      setProducts(prev => [...prev, newProduct]);
      if (newProduct.stock > 0) {
        addMovement(newProduct.id, newProduct.stock, 'in', 'Carga inicial de inventario');
      }
    }
    closeModal();
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingId(null);
    setFormData({ name: '', categoryId: '', code: '', image: '', costPrice: 0, salePrice: 0, stock: 0 });
  };

  const openEdit = (product: Product) => {
    setEditingId(product.id);
    setFormData(product);
    setShowModal(true);
  };

  const deleteProduct = (id: string) => {
    if (window.confirm("¿Eliminar este producto?")) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-3xl font-bold text-slate-800">Productos</h2>
        <button 
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-3 rounded-2xl hover:bg-emerald-700 transition-all font-bold"
        >
          <Plus size={20} />
          Nuevo Producto
        </button>
      </div>

      <div className="bg-white p-4 rounded-3xl shadow-sm border border-slate-100">
        <div className="relative mb-6">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Buscar por nombre o código..." 
            className="w-full pl-12 pr-6 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-emerald-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-sm font-semibold border-b">
                <th className="pb-4 pl-4">Producto</th>
                <th className="pb-4">Código</th>
                <th className="pb-4">Categoría</th>
                <th className="pb-4 text-right">Costo</th>
                <th className="pb-4 text-right">Precio Venta</th>
                <th className="pb-4 text-center">Stock</th>
                <th className="pb-4 pr-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredProducts.map(p => (
                <tr key={p.id} className="group hover:bg-slate-50 transition-colors">
                  <td className="py-4 pl-4">
                    <div className="flex items-center gap-3">
                      <div className="w-12 h-12 rounded-xl bg-slate-100 overflow-hidden flex-shrink-0">
                        {p.image ? <img src={p.image} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-300"><Camera size={16}/></div>}
                      </div>
                      <span className="font-semibold text-slate-700">{p.name}</span>
                    </div>
                  </td>
                  <td className="py-4 text-slate-500 font-mono text-sm">{p.code}</td>
                  <td className="py-4">
                    <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-bold uppercase">
                      {categories.find(c => c.id === p.categoryId)?.name || 'Sin Categoría'}
                    </span>
                  </td>
                  <td className="py-4 text-right text-slate-500">${p.costPrice.toLocaleString()}</td>
                  <td className="py-4 text-right font-bold text-emerald-600">${p.salePrice.toLocaleString()}</td>
                  <td className="py-4 text-center">
                    <span className={`font-bold ${p.stock <= 5 ? 'text-red-500' : 'text-slate-700'}`}>
                      {p.stock}
                    </span>
                  </td>
                  <td className="py-4 pr-4 text-right space-x-2">
                    <button onClick={() => openEdit(p)} className="p-2 text-slate-400 hover:text-emerald-600 transition-colors"><Edit2 size={18} /></button>
                    <button onClick={() => deleteProduct(p.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-bold text-slate-800">{editingId ? 'Editar Producto' : 'Crear Nuevo Producto'}</h3>
              <button onClick={closeModal} className="p-2 hover:bg-slate-200 rounded-full transition-colors"><X size={20}/></button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="md:col-span-2">
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Nombre del Producto</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
                    value={formData.name}
                    onChange={e => setFormData(prev => ({ ...prev, name: e.target.value }))}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Categoría</label>
                  <select 
                    required
                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                    value={formData.categoryId}
                    onChange={e => setFormData(prev => ({ ...prev, categoryId: e.target.value }))}
                  >
                    <option value="">Seleccionar...</option>
                    {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Código/SKU</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
                    value={formData.code}
                    onChange={e => setFormData(prev => ({ ...prev, code: e.target.value }))}
                  />
                </div>
                <div className="md:col-span-2">
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Imagen del Producto</label>
                  <div className="flex items-center gap-4">
                    <div className="w-24 h-24 rounded-2xl bg-slate-100 border-2 border-dashed border-slate-200 overflow-hidden flex items-center justify-center relative group">
                      {formData.image ? (
                        <>
                          <img src={formData.image} className="w-full h-full object-cover" />
                          <button type="button" onClick={() => setFormData(prev => ({...prev, image: ''}))} className="absolute inset-0 bg-red-500/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white"><Trash2 size={24}/></button>
                        </>
                      ) : (
                        <Camera className="text-slate-300" size={32} />
                      )}
                    </div>
                    <label className="flex-1 cursor-pointer bg-slate-50 hover:bg-slate-100 border border-slate-200 border-dashed rounded-2xl p-6 text-center transition-colors">
                      <span className="text-sm text-slate-500 font-medium">Subir foto o arrastrar archivo</span>
                      <input type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
                    </label>
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Precio de Costo</label>
                  <input 
                    required 
                    type="number" 
                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
                    value={formData.costPrice}
                    onChange={e => setFormData(prev => ({ ...prev, costPrice: Number(e.target.value) }))}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Precio de Venta</label>
                  <input 
                    required 
                    type="number" 
                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
                    value={formData.salePrice}
                    onChange={e => setFormData(prev => ({ ...prev, salePrice: Number(e.target.value) }))}
                  />
                </div>
                {!editingId && (
                  <div>
                    <label className="block text-sm font-semibold text-slate-600 mb-2">Stock Inicial</label>
                    <input 
                      required 
                      type="number" 
                      className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
                      value={formData.stock}
                      onChange={e => setFormData(prev => ({ ...prev, stock: Number(e.target.value) }))}
                    />
                  </div>
                )}
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={closeModal} className="flex-1 px-6 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-all">Cancelar</button>
                <button type="submit" className="flex-[2] px-6 py-4 bg-emerald-600 text-white font-bold rounded-2xl hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition-all">
                  {editingId ? 'Guardar Cambios' : 'Crear Producto'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Products;

import React, { useState } from 'react';
import { Plus, Trash2, Edit2, LayoutGrid } from 'lucide-react';
import { Category } from '../types';

interface CategoriesProps {
  categories: Category[];
  setCategories: React.Dispatch<React.SetStateAction<Category[]>>;
}

const Categories: React.FC<CategoriesProps> = ({ categories, setCategories }) => {
  const [newName, setNewName] = useState('');

  const addCategory = () => {
    if (!newName.trim()) return;
    const newCategory: Category = {
      id: Math.random().toString(36).substr(2, 9),
      name: newName
    };
    setCategories([...categories, newCategory]);
    setNewName('');
  };

  const removeCategory = (id: string) => {
    if (window.confirm("¿Eliminar categoría? Los productos de esta categoría quedarán sin ella.")) {
      setCategories(categories.filter(c => c.id !== id));
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold text-slate-800">Categorías</h2>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <div className="flex gap-4 mb-8">
          <input 
            type="text" 
            placeholder="Nombre de la nueva categoría..." 
            className="flex-1 px-6 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-emerald-500"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && addCategory()}
          />
          <button 
            onClick={addCategory}
            className="bg-emerald-600 text-white px-8 py-4 rounded-2xl hover:bg-emerald-700 font-bold flex items-center gap-2 transition-all shadow-lg shadow-emerald-100"
          >
            <Plus size={20} />
            Agregar
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {categories.map(category => (
            <div key={category.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-transparent hover:border-emerald-200 transition-all group">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-emerald-100 flex items-center justify-center text-emerald-600">
                  <LayoutGrid size={20} />
                </div>
                <span className="font-semibold text-slate-700">{category.name}</span>
              </div>
              <button 
                onClick={() => removeCategory(category.id)}
                className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
              >
                <Trash2 size={18} />
              </button>
            </div>
          ))}
          {categories.length === 0 && (
            <div className="col-span-2 py-12 text-center text-slate-400">
              No hay categorías registradas. Comience agregando una arriba.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Categories;

import React, { useState } from 'react';
import { ArrowUpRight, ArrowDownRight, Package, Plus, Filter } from 'lucide-react';
import { InventoryMovement, Product } from '../types';

interface InventoryProps {
  movements: InventoryMovement[];
  products: Product[];
  addMovement: (productId: string, quantity: number, type: 'in' | 'out', reason: string) => void;
}

const Inventory: React.FC<InventoryProps> = ({ movements, products, addMovement }) => {
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({
    productId: '',
    quantity: 1,
    type: 'in' as 'in' | 'out',
    reason: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.productId || !formData.reason) return alert("Completa todos los campos");

    if (formData.type === 'out') {
      const p = products.find(prod => prod.id === formData.productId);
      if (p && p.stock < formData.quantity) {
        alert("Stock insuficiente para realizar esta salida");
        return;
      }
    }

    addMovement(formData.productId, formData.quantity, formData.type, formData.reason);
    setShowModal(false);
    setFormData({ productId: '', quantity: 1, type: 'in', reason: '' });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold text-slate-800">Movimientos de Inventario</h2>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-slate-800 text-white px-6 py-3 rounded-2xl flex items-center gap-2 hover:bg-slate-700 transition-all font-bold"
        >
          <Plus size={20} />
          Ajustar Inventario
        </button>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50">
            <tr className="text-slate-500 text-sm font-semibold">
              <th className="px-6 py-4">Fecha</th>
              <th className="px-6 py-4">Producto</th>
              <th className="px-6 py-4">Tipo</th>
              <th className="px-6 py-4 text-center">Cantidad</th>
              <th className="px-6 py-4">Motivo</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {movements.map(m => {
              const p = products.find(prod => prod.id === m.productId);
              return (
                <tr key={m.id} className="hover:bg-slate-50/50">
                  <td className="px-6 py-4 text-sm text-slate-500">
                    {new Date(m.date).toLocaleString()}
                  </td>
                  <td className="px-6 py-4">
                    <span className="font-semibold text-slate-700">{p?.name || 'Producto Eliminado'}</span>
                  </td>
                  <td className="px-6 py-4">
                    <div className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-bold uppercase ${m.type === 'in' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                      {m.type === 'in' ? <ArrowUpRight size={14}/> : <ArrowDownRight size={14}/>}
                      {m.type === 'in' ? 'Entrada' : 'Salida'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-center font-bold">
                    {m.quantity}
                  </td>
                  <td className="px-6 py-4 text-slate-500 text-sm">
                    {m.reason}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl animate-in zoom-in duration-200">
            <div className="p-6 border-b flex justify-between items-center bg-slate-50 rounded-t-3xl">
              <h3 className="text-xl font-bold">Ajuste de Inventario</h3>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                <Plus size={20} className="rotate-45" />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div>
                <label className="block text-sm font-semibold text-slate-600 mb-2">Producto</label>
                <select 
                  className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                  value={formData.productId}
                  onChange={e => setFormData(prev => ({ ...prev, productId: e.target.value }))}
                >
                  <option value="">Seleccionar...</option>
                  {products.map(p => <option key={p.id} value={p.id}>{p.name} (Stock: {p.stock})</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Tipo</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                    value={formData.type}
                    onChange={e => setFormData(prev => ({ ...prev, type: e.target.value as 'in' | 'out' }))}
                  >
                    <option value="in">Entrada</option>
                    <option value="out">Salida</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">Cantidad</label>
                  <input 
                    type="number" 
                    min="1"
                    className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
                    value={formData.quantity}
                    onChange={e => setFormData(prev => ({ ...prev, quantity: Number(e.target.value) }))}
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-600 mb-2">Motivo</label>
                <input 
                  type="text" 
                  placeholder="Ej: Compra a proveedor, Mermas..."
                  className="w-full px-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
                  value={formData.reason}
                  onChange={e => setFormData(prev => ({ ...prev, reason: e.target.value }))}
                />
              </div>
              <button type="submit" className="w-full py-4 bg-emerald-600 text-white font-bold rounded-2xl hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition-all">
                Registrar Movimiento
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { FileText, Download, TrendingUp, Wallet, Users, AlertCircle, Edit3 } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, Category, FinancialSettings } from '../types';

interface StatsProps {
  sales: Sale[];
  products: Product[];
  categories: Category[];
  settings: FinancialSettings;
  setSettings: React.Dispatch<React.SetStateAction<FinancialSettings>>;
}

const Statistics: React.FC<StatsProps> = ({ sales, products, categories, settings, setSettings }) => {
  const totalRevenue = useMemo(() => sales.reduce((acc, s) => acc + s.total, 0), [sales]);
  const cashSales = useMemo(() => sales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0), [sales]);
  const transferSales = useMemo(() => sales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0), [sales]);

  // Financial calculations based on user requirements
  const recovery40 = totalRevenue * 0.40;
  const reinvestment20 = totalRevenue * 0.20;
  const profit38 = totalRevenue * 0.38;
  const salary15 = totalRevenue * (settings.workerSalaryRate / 100);
  const inspector05 = totalRevenue * 0.005;

  const chartData = [
    { name: 'Efectivo', value: cashSales, color: '#10b981' },
    { name: 'Transferencia', value: transferSales, color: '#3b82f6' },
  ];

  const distributionData = [
    { name: 'Recuperación (40%)', value: recovery40, color: '#6366f1' },
    { name: 'Reinversión (20%)', value: reinvestment20, color: '#f59e0b' },
    { name: 'Ganancia (38%)', value: profit38, color: '#10b981' },
    { name: 'Salario (Variable)', value: salary15, color: '#ec4899' },
    { name: 'Inspector (0.5%)', value: inspector05, color: '#64748b' },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    const now = new Date().toLocaleString();

    // Title and Header
    doc.setFontSize(22);
    doc.setTextColor(16, 185, 129); // Emerald-600
    doc.text("Reporte Financiero GourmetPOS", 14, 20);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Fecha de generación: ${now}`, 14, 28);

    // Financial Overview
    doc.setFontSize(14);
    doc.setTextColor(30);
    doc.text("Resumen Financiero", 14, 40);

    const financialRows = [
      ["Concepto", "Porcentaje", "Monto"],
      ["Ventas Totales", "100%", `$${totalRevenue.toLocaleString()}`],
      ["Recuperación Inv. Inicial", "40%", `$${recovery40.toLocaleString()}`],
      ["Inversión Secundaria (Reinversión)", "20%", `$${reinvestment20.toLocaleString()}`],
      ["Ganancia Neta", "38%", `$${profit38.toLocaleString()}`],
      [`Salario Trabajador`, `${settings.workerSalaryRate}%`, `$${salary15.toLocaleString()}`],
      ["Gato, Inspector", "0.5%", `$${inspector05.toLocaleString()}`],
    ];

    autoTable(doc, {
      startY: 45,
      head: [financialRows[0]],
      body: financialRows.slice(1),
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] }
    });

    // Inversión Inicial Reference
    doc.setFontSize(10);
    doc.text(`(Inversión Inicial de referencia: $${settings.initialInvestment.toLocaleString()})`, 14, (doc as any).lastAutoTable.finalY + 10);

    // Inventory by Category
    doc.setFontSize(14);
    doc.text("Inventario Actual por Categoría", 14, (doc as any).lastAutoTable.finalY + 25);

    categories.forEach((cat, index) => {
      const catProducts = products.filter(p => p.categoryId === cat.id);
      if (catProducts.length === 0) return;

      doc.setFontSize(11);
      doc.text(`Categoría: ${cat.name}`, 14, (doc as any).lastAutoTable.finalY + 35 + (index * 5));

      const tableData = catProducts.map(p => [
        p.name,
        p.code,
        `$${p.costPrice}`,
        `$${p.salePrice}`,
        p.stock.toString()
      ]);

      autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY + 5,
        head: [['Producto', 'Código', 'Costo', 'Precio', 'Stock']],
        body: tableData,
        margin: { left: 20 },
        theme: 'grid',
        headStyles: { fillColor: [71, 85, 105] }
      });
    });

    doc.save(`Reporte_GourmetPOS_${Date.now()}.pdf`);
  };

  return (
    <div className="space-y-8 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800">Estadísticas</h2>
          <p className="text-slate-500">Analiza el rendimiento financiero de tu negocio</p>
        </div>
        <button 
          onClick={exportPDF}
          className="flex items-center gap-2 bg-slate-800 text-white px-6 py-4 rounded-2xl hover:bg-slate-700 transition-all font-bold shadow-xl"
        >
          <Download size={20} />
          Exportar Informe PDF
        </button>
      </div>

      {/* Settings Bar */}
      <div className="bg-emerald-600 rounded-3xl p-6 text-white flex flex-col md:flex-row gap-8 items-center">
        <div className="flex-1 flex items-center gap-4">
          <div className="p-3 bg-white/20 rounded-2xl">
            <Edit3 size={24} />
          </div>
          <div>
            <p className="text-emerald-100 text-sm font-medium">Inversión Inicial</p>
            <div className="flex items-center gap-2">
              <span className="text-2xl font-bold">$</span>
              <input 
                type="number" 
                className="bg-transparent border-b border-emerald-300 focus:border-white text-2xl font-bold w-32 outline-none"
                value={settings.initialInvestment}
                onChange={e => setSettings(prev => ({ ...prev, initialInvestment: Number(e.target.value) }))}
              />
            </div>
          </div>
        </div>
        <div className="flex-1 flex items-center gap-4">
          <div className="p-3 bg-white/20 rounded-2xl">
            <Users size={24} />
          </div>
          <div>
            <p className="text-emerald-100 text-sm font-medium">Salario Trabajador (%)</p>
            <div className="flex items-center gap-2">
              <input 
                type="number" 
                step="0.1"
                className="bg-transparent border-b border-emerald-300 focus:border-white text-2xl font-bold w-20 outline-none"
                value={settings.workerSalaryRate}
                onChange={e => setSettings(prev => ({ ...prev, workerSalaryRate: Number(e.target.value) }))}
              />
              <span className="text-2xl font-bold">%</span>
            </div>
          </div>
        </div>
      </div>

      {/* Main Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-sm font-semibold mb-1 uppercase tracking-wider">Ventas Totales</p>
          <h4 className="text-3xl font-bold text-slate-800">${totalRevenue.toLocaleString()}</h4>
          <div className="mt-4 flex items-center gap-2 text-emerald-600 text-sm font-bold">
            <TrendingUp size={16} />
            <span>Actualizado</span>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-sm font-semibold mb-1 uppercase tracking-wider">En Efectivo</p>
          <h4 className="text-3xl font-bold text-slate-800">${cashSales.toLocaleString()}</h4>
          <div className="mt-4 w-full bg-slate-100 h-2 rounded-full">
            <div className="bg-emerald-500 h-2 rounded-full" style={{ width: `${(cashSales/totalRevenue)*100 || 0}%` }}></div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-sm font-semibold mb-1 uppercase tracking-wider">Transferencias</p>
          <h4 className="text-3xl font-bold text-slate-800">${transferSales.toLocaleString()}</h4>
          <div className="mt-4 w-full bg-slate-100 h-2 rounded-full">
            <div className="bg-blue-500 h-2 rounded-full" style={{ width: `${(transferSales/totalRevenue)*100 || 0}%` }}></div>
          </div>
        </div>
        <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100">
          <p className="text-emerald-600 text-sm font-semibold mb-1 uppercase tracking-wider">Ganancia Neta (38%)</p>
          <h4 className="text-3xl font-bold text-emerald-700">${profit38.toLocaleString()}</h4>
          <p className="mt-2 text-xs text-emerald-500 font-medium italic">Basado en facturación total</p>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
            <Wallet className="text-emerald-500" />
            Métodos de Pago
          </h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center gap-8 mt-4">
            {chartData.map(d => (
              <div key={d.name} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: d.color }}></div>
                <span className="text-sm font-medium text-slate-600">{d.name}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
            <AlertCircle className="text-emerald-500" />
            Distribución de Ingresos
          </h3>
          <div className="space-y-4">
            {distributionData.map(item => (
              <div key={item.name} className="space-y-1">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-600 font-medium">{item.name}</span>
                  <span className="text-slate-900 font-bold">${item.value.toLocaleString()}</span>
                </div>
                <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                  <div 
                    className="h-full transition-all duration-1000" 
                    style={{ 
                      backgroundColor: item.color, 
                      width: `${(item.value / totalRevenue) * 100 || 0}%` 
                    }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Statistics;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Download, Wallet, Users, AlertCircle, Edit3, TrendingUp } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, Category, FinancialSettings } from '../types';

interface StatsProps {
  sales: Sale[];
  products: Product[];
  categories: Category[];
  settings: FinancialSettings;
  setSettings: React.Dispatch<React.SetStateAction<FinancialSettings>>;
}

const Statistics: React.FC<StatsProps> = ({ sales, products, categories, settings, setSettings }) => {
  const totalRevenue = useMemo(() => sales.reduce((acc, s) => acc + s.total, 0), [sales]);
  const cashSales = useMemo(() => sales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0), [sales]);
  const transferSales = useMemo(() => sales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0), [sales]);

  // Financial percentages from requirements
  const recoveryRate = 0.40;
  const reinvestmentRate = 0.20;
  const inspectorRate = 0.005;
  const salaryRate = settings.workerSalaryRate / 100;

  // Net Profit adjusts dynamically to total 100% distribution
  const profitRate = 1 - recoveryRate - reinvestmentRate - inspectorRate - salaryRate;

  const recoveryAmount = totalRevenue * recoveryRate;
  const reinvestmentAmount = totalRevenue * reinvestmentRate;
  const inspectorAmount = totalRevenue * inspectorRate;
  const salaryAmount = totalRevenue * salaryRate;
  const profitAmount = totalRevenue * profitRate;

  const chartData = [
    { name: 'Efectivo', value: cashSales, color: '#10b981' },
    { name: 'Transferencia', value: transferSales, color: '#3b82f6' },
  ];

  const distributionData = [
    { name: 'Recuperación (40%)', value: recoveryAmount, color: '#6366f1' },
    { name: 'Inversión Secundaria (20%)', value: reinvestmentAmount, color: '#f59e0b' },
    { name: 'Ganancia Neta', value: profitAmount, color: '#10b981', percentage: (profitRate * 100).toFixed(1) + '%' },
    { name: `Salario (${settings.workerSalaryRate}%)`, value: salaryAmount, color: '#ec4899' },
    { name: 'Inspector (0.5%)', value: inspectorAmount, color: '#64748b' },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    const now = new Date().toLocaleString();

    // PDF Styling
    doc.setFontSize(22);
    doc.setTextColor(16, 185, 129); 
    doc.text("Informe Financiero GourmetPOS", 14, 20);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Generado: ${now}`, 14, 28);

    doc.setFontSize(14);
    doc.setTextColor(30);
    doc.text("Distribución de Ingresos", 14, 40);

    const financialRows = [
      ["Concepto", "Porcentaje", "Monto"],
      ["Ventas Totales", "100%", `$${totalRevenue.toLocaleString()}`],
      ["Recuperación de Inversión", "40%", `$${recoveryAmount.toLocaleString()}`],
      ["Inversión Secundaria (Reinversión)", "20%", `$${reinvestmentAmount.toLocaleString()}`],
      ["Ganancia Neta", `${(profitRate * 100).toFixed(1)}%`, `$${profitAmount.toLocaleString()}`],
      ["Salario de Trabajador", `${settings.workerSalaryRate}%`, `$${salaryAmount.toLocaleString()}`],
      ["Inspector (Gato)", "0.5%", `$${inspectorAmount.toLocaleString()}`],
    ];

    autoTable(doc, {
      startY: 45,
      head: [financialRows[0]],
      body: financialRows.slice(1),
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] },
      styles: { fontSize: 10 }
    });

    const finalY = (doc as any).lastAutoTable.finalY;
    doc.setFontSize(9);
    doc.setTextColor(120);
    doc.text(`(Inversión Inicial de Referencia: $${settings.initialInvestment.toLocaleString()})`, 14, finalY + 10);

    // Group products by category as requested
    doc.setFontSize(14);
    doc.setTextColor(30);
    doc.text("Inventario Actual por Categoría", 14, finalY + 25);

    let currentY = finalY + 30;

    categories.forEach((cat) => {
      const catProducts = products.filter(p => p.categoryId === cat.id);
      if (catProducts.length === 0) return;

      if (currentY > 250) {
        doc.addPage();
        currentY = 20;
      }

      doc.setFontSize(12);
      doc.setTextColor(16, 185, 129);
      doc.text(`Categoría: ${cat.name}`, 14, currentY);

      const tableData = catProducts.map(p => [
        p.name,
        p.code,
        `$${p.costPrice.toLocaleString()}`,
        `$${p.salePrice.toLocaleString()}`,
        p.stock.toString()
      ]);

      autoTable(doc, {
        startY: currentY + 5,
        head: [['Producto', 'Código', 'P. Costo', 'P. Venta', 'Stock']],
        body: tableData,
        theme: 'grid',
        headStyles: { fillColor: [71, 85, 105] },
        styles: { fontSize: 9 },
        margin: { left: 14 }
      });

      currentY = (doc as any).lastAutoTable.finalY + 15;
    });

    doc.save(`GourmetPOS_Reporte_${Date.now()}.pdf`);
  };

  return (
    <div className="space-y-8 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Panel de Estadísticas</h2>
          <p className="text-slate-500 font-medium">Control financiero y análisis de rentabilidad</p>
        </div>
        <button 
          onClick={exportPDF}
          className="flex items-center gap-2 bg-emerald-600 text-white px-8 py-4 rounded-2xl hover:bg-emerald-700 transition-all font-bold shadow-xl shadow-emerald-100"
        >
          <Download size={20} />
          Exportar Informe PDF
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-6">
          <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600">
            <Edit3 size={32} />
          </div>
          <div className="flex-1">
            <p className="text-slate-400 text-xs font-black uppercase tracking-widest mb-1">Inversión Inicial</p>
            <div className="flex items-center gap-2">
              <span className="text-2xl font-black text-slate-800">$</span>
              <input 
                type="number" 
                className="text-2xl font-black text-slate-800 w-full focus:outline-none focus:text-blue-600 border-b border-dashed border-slate-200"
                value={settings.initialInvestment}
                onChange={e => setSettings(prev => ({ ...prev, initialInvestment: Number(e.target.value) }))}
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-6">
          <div className="w-16 h-16 bg-pink-50 rounded-2xl flex items-center justify-center text-pink-600">
            <Users size={32} />
          </div>
          <div className="flex-1">
            <p className="text-slate-400 text-xs font-black uppercase tracking-widest mb-1">Salario Trabajador (%)</p>
            <div className="flex items-center gap-2">
              <input 
                type="number" 
                step="0.1"
                className="text-2xl font-black text-slate-800 w-24 focus:outline-none focus:text-pink-600 border-b border-dashed border-slate-200"
                value={settings.workerSalaryRate}
                onChange={e => setSettings(prev => ({ ...prev, workerSalaryRate: Number(e.target.value) }))}
              />
              <span className="text-2xl font-black text-slate-800">%</span>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-900 p-6 rounded-3xl shadow-xl">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Ventas Totales</p>
          <h4 className="text-3xl font-black text-white">${totalRevenue.toLocaleString()}</h4>
          <div className="mt-4 flex items-center gap-2 text-emerald-400 text-xs font-bold bg-white/10 w-fit px-3 py-1 rounded-full">
            <TrendingUp size={14} />
            <span>Actualizado</span>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Ganancia Neta ({(profitRate * 100).toFixed(1)}%)</p>
          <h4 className="text-3xl font-black text-emerald-600">${profitAmount.toLocaleString()}</h4>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">En Efectivo</p>
          <h4 className="text-3xl font-black text-slate-800">${cashSales.toLocaleString()}</h4>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Transferencias</p>
          <h4 className="text-3xl font-black text-slate-800">${transferSales.toLocaleString()}</h4>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
            <Wallet className="text-emerald-500" />
            Ventas por Método
          </h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ borderRadius: '1rem', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                  formatter={(value: number) => `$${value.toLocaleString()}`}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
            <AlertCircle className="text-emerald-500" />
            Distribución de Capital
          </h3>
          <div className="space-y-5">
            {distributionData.map(item => (
              <div key={item.name} className="space-y-1">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-600 font-bold">{item.name}</span>
                  <span className="text-slate-900 font-black">${item.value.toLocaleString()}</span>
                </div>
                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div 
                    className="h-full transition-all duration-1000 ease-out" 
                    style={{ 
