import React, { useState, useRef } from 'react';
import { Plus, Search, Edit2, Trash2, Camera, X, Check } from 'lucide-react';
import { Product, Category } from '../types';

interface ProductsProps {
  products: Product[];
  categories: Category[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  addMovement: (productId: string, quantity: number, type: 'in' | 'out', reason: string) => void;
}

const Products: React.FC<ProductsProps> = ({ products, categories, setProducts, addMovement }) => {
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const [formData, setFormData] = useState({
    name: '',
    categoryId: '',
    code: '',
    image: '',
    costPrice: 0,
    salePrice: 0,
    stock: 0
  });

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const startCamera = async () => {
    setIsCameraActive(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      alert("Acceso a cámara denegado o no disponible");
      setIsCameraActive(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current?.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setIsCameraActive(false);
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0);
        setFormData(prev => ({ ...prev, image: canvas.toDataURL('image/jpeg') }));
        stopCamera();
      }
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.categoryId) return alert("Selecciona una categoría");

    if (editingId) {
      setProducts(prev => prev.map(p => p.id === editingId ? { ...formData, id: editingId } : p));
    } else {
      const newProduct: Product = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      };
      setProducts(prev => [...prev, newProduct]);
      if (newProduct.stock > 0) {
        addMovement(newProduct.id, newProduct.stock, 'in', 'Carga inicial');
      }
    }
    closeModal();
  };

  const closeModal = () => {
    stopCamera();
    setShowModal(false);
    setEditingId(null);
    setFormData({ name: '', categoryId: '', code: '', image: '', costPrice: 0, salePrice: 0, stock: 0 });
  };

  const openEdit = (product: Product) => {
    setEditingId(product.id);
    setFormData(product);
    setShowModal(true);
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Catálogo</h2>
          <p className="text-slate-500 font-medium">Gestión integral de productos y existencias</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-emerald-600 text-white px-8 py-4 rounded-2xl hover:bg-emerald-700 transition-all font-bold shadow-xl shadow-emerald-100"
        >
          <Plus size={24} />
          Nuevo Producto
        </button>
      </div>

      <div className="bg-white p-4 rounded-[2rem] shadow-sm border border-slate-100">
        <div className="relative mb-6">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Buscar por nombre, código o SKU..." 
            className="w-full pl-12 pr-6 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 transition-all font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto rounded-2xl">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-50">
                <th className="pb-4 pl-6">Producto</th>
                <th className="pb-4">SKU</th>
                <th className="pb-4">Categoría</th>
                <th className="pb-4 text-right">Costo</th>
                <th className="pb-4 text-right">Venta</th>
                <th className="pb-4 text-center">Stock</th>
                <th className="pb-4 pr-6 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredProducts.map(p => (
                <tr key={p.id} className="group hover:bg-slate-50/50 transition-colors">
                  <td className="py-4 pl-6">
                    <div className="flex items-center gap-4">
                      <div className="w-14 h-14 rounded-2xl bg-slate-100 overflow-hidden flex-shrink-0 border-2 border-white shadow-sm">
                        {p.image ? <img src={p.image} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-300"><Camera size={20}/></div>}
                      </div>
                      <span className="font-black text-slate-700">{p.name}</span>
                    </div>
                  </td>
                  <td className="py-4 text-slate-400 font-mono text-xs">{p.code}</td>
                  <td className="py-4">
                    <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-black uppercase">
                      {categories.find(c => c.id === p.categoryId)?.name || 'Sin Cat.'}
                    </span>
                  </td>
                  <td className="py-4 text-right text-slate-400 font-bold">${p.costPrice.toLocaleString()}</td>
                  <td className="py-4 text-right font-black text-slate-800">${p.salePrice.toLocaleString()}</td>
                  <td className="py-4 text-center">
                    <span className={`inline-flex items-center justify-center min-w-[32px] px-2 py-1 rounded-lg font-black text-xs ${p.stock <= 5 ? 'bg-red-50 text-red-500' : 'bg-slate-100 text-slate-600'}`}>
                      {p.stock}
                    </span>
                  </td>
                  <td className="py-4 pr-6 text-right space-x-1">
                    <button onClick={() => openEdit(p)} className="p-3 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all"><Edit2 size={18} /></button>
                    <button onClick={() => setProducts(prev => prev.filter(item => item.id !== p.id))} className="p-3 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <h3 className="text-2xl font-black text-slate-800">{editingId ? 'Editar Detalle' : 'Nuevo Producto'}</h3>
              <button onClick={closeModal} className="p-3 hover:bg-white rounded-2xl transition-all"><X size={24}/></button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto no-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nombre del Producto</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 font-bold"
                    value={formData.name}
                    onChange={e => setFormData(prev => ({ ...prev, name: e.target.value }))}
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoría</label>
                  <select 
                    required
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 outline-none font-bold"
                    value={formData.categoryId}
                    onChange={e => setFormData(prev => ({ ...prev, categoryId: e.target.value }))}
                  >
                    <option value="">Seleccionar...</option>
                    {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Código / SKU</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 font-mono font-bold"
                    value={formData.code}
                    onChange={e => setFormData(prev => ({ ...prev, code: e.target.value }))}
                  />
                </div>

                <div className="md:col-span-2 space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Foto del Producto</label>
                  <div className="flex flex-col md:flex-row gap-6">
                    <div className="w-32 h-32 rounded-3xl bg-slate-50 border-4 border-white shadow-inner overflow-hidden flex items-center justify-center relative group">
                      {formData.image ? (
                        <>
                          <img src={formData.image} className="w-full h-full object-cover" />
                          <button type="button" onClick={() => setFormData(prev => ({...prev, image: ''}))} className="absolute inset-0 bg-red-500/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white"><Trash2 size={24}/></button>
                        </>
                      ) : (
                        <Camera className="text-slate-200" size={32} />
                      )}
                    </div>
                    <div className="flex-1 space-y-4">
                      {!isCameraActive ? (
                        <div className="flex gap-4">
                          <button 
                            type="button" 
                            onClick={startCamera}
                            className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-600 font-black px-4 py-3 rounded-2xl transition-all text-[10px] tracking-widest uppercase"
                          >
                            Usar Cámara
                          </button>
                          <label className="flex-1 cursor-pointer bg-slate-100 hover:bg-slate-200 text-slate-600 font-black px-4 py-3 rounded-2xl transition-all text-[10px] tracking-widest uppercase text-center flex items-center justify-center">
                            Cargar Archivo
                            <input type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
                          </label>
                        </div>
                      ) : (
                        <div className="relative rounded-2xl overflow-hidden bg-black aspect-video flex items-center justify-center">
                          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                          <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-4">
                            <button type="button" onClick={capturePhoto} className="bg-emerald-500 text-white p-3 rounded-full shadow-xl"><Check size={24}/></button>
                            <button type="button" onClick={stopCamera} className="bg-red-500 text-white p-3 rounded-full shadow-xl"><X size={24}/></button>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Precio Costo</label>
                  <input 
                    required 
                    type="number" 
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 font-bold"
                    value={formData.costPrice}
                    onChange={e => setFormData(prev => ({ ...prev, costPrice: Number(e.target.value) }))}
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Precio Venta</label>
                  <input 
                    required 
                    type="number" 
                    className="w-full px-5 py-4 bg-emerald-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-200 font-black text-emerald-600"
                    value={formData.salePrice}
                    onChange={e => setFormData(prev => ({ ...prev, salePrice: Number(e.target.value) }))}
                  />
                </div>
              </div>

              <div className="flex gap-4 pt-6 border-t border-slate-50">
                <button type="button" onClick={closeModal} className="flex-1 px-8 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">Cancelar</button>
                <button type="submit" className="flex-[2] px-8 py-5 bg-emerald-600 text-white font-black rounded-3xl hover:bg-emerald-700 shadow-xl shadow-emerald-100 transition-all uppercase tracking-widest text-xs">
                  {editingId ? 'Guardar Cambios' : 'Crear Producto'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Products;

import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, LayoutGrid, BarChart3, Menu, X, Tag } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'pos' | 'inventory' | 'products' | 'stats'>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
  }, []);

  // Auto-Save Effect
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
  }, [products, categories, sales, movements, financialSettings]);

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      quantity,
      type,
      reason,
      date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);

    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        return { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity };
      }
      return p;
    }));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => {
      addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`);
    });
  }, [addMovement]);

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">GourmetPOS</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-8 tracking-tighter">GourmetPOS</h1>
          <nav className="space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as any);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
        <div className="absolute bottom-0 w-full p-6 border-t bg-slate-50/50">
          <p className="text-xs text-slate-400 font-medium uppercase tracking-wider mb-2">Sistema</p>
          <div className="flex items-center space-x-2 text-slate-600">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span className="text-xs font-bold uppercase tracking-widest">Auto-guardado activo</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && (
            <POS 
              products={products} 
              categories={categories} 
              onCompleteSale={completeSale} 
            />
          )}
          {activeTab === 'products' && (
            <Products 
              products={products} 
              categories={categories} 
              setProducts={setProducts} 
              setCategories={setCategories}
              addMovement={addMovement}
            />
          )}
          {activeTab === 'inventory' && (
            <Inventory 
              movements={movements} 
              products={products} 
              addMovement={addMovement}
            />
          )}
          {activeTab === 'stats' && (
            <Statistics 
              sales={sales} 
              products={products} 
              categories={categories}
              settings={financialSettings}
              setSettings={setFinancialSettings}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Plus, Search, Edit2, Trash2, Camera, X, Check, FolderPlus } from 'lucide-react';
import { Product, Category } from '../types';

interface ProductsProps {
  products: Product[];
  categories: Category[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  setCategories: React.Dispatch<React.SetStateAction<Category[]>>;
  addMovement: (productId: string, quantity: number, type: 'in' | 'out', reason: string) => void;
}

const Products: React.FC<ProductsProps> = ({ products, categories, setProducts, setCategories, addMovement }) => {
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const videoRef = useRef<HTMLVideoElement>(null);

  const [formData, setFormData] = useState({
    name: '',
    categoryId: '',
    code: '',
    image: '',
    costPrice: 0,
    salePrice: 0,
    stock: 0
  });

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const startCamera = async () => {
    setIsCameraActive(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      alert("Acceso a cámara denegado o no disponible");
      setIsCameraActive(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current?.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setIsCameraActive(false);
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0);
        setFormData(prev => ({ ...prev, image: canvas.toDataURL('image/jpeg') }));
        stopCamera();
      }
    }
  };

  const handleCreateCategory = () => {
    if (!newCategoryName.trim()) return;
    const newCat: Category = {
      id: Math.random().toString(36).substr(2, 9),
      name: newCategoryName
    };
    setCategories(prev => [...prev, newCat]);
    setFormData(prev => ({ ...prev, categoryId: newCat.id }));
    setNewCategoryName('');
    setIsAddingCategory(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.categoryId) return alert("Selecciona una categoría");

    if (editingId) {
      setProducts(prev => prev.map(p => p.id === editingId ? { ...formData, id: editingId } : p));
    } else {
      const newProduct: Product = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      };
      setProducts(prev => [...prev, newProduct]);
      if (newProduct.stock > 0) {
        addMovement(newProduct.id, newProduct.stock, 'in', 'Carga inicial');
      }
    }
    closeModal();
  };

  const closeModal = () => {
    stopCamera();
    setShowModal(false);
    setEditingId(null);
    setIsAddingCategory(false);
    setNewCategoryName('');
    setFormData({ name: '', categoryId: '', code: '', image: '', costPrice: 0, salePrice: 0, stock: 0 });
  };

  const openEdit = (product: Product) => {
    setEditingId(product.id);
    setFormData(product);
    setShowModal(true);
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Catálogo</h2>
          <p className="text-slate-500 font-medium">Gestión integral de productos y existencias</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-emerald-600 text-white px-8 py-4 rounded-2xl hover:bg-emerald-700 transition-all font-bold shadow-xl shadow-emerald-100"
        >
          <Plus size={24} />
          Nuevo Producto
        </button>
      </div>

      <div className="bg-white p-4 rounded-[2rem] shadow-sm border border-slate-100">
        <div className="relative mb-6">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Buscar por nombre, código o SKU..." 
            className="w-full pl-12 pr-6 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 transition-all font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto rounded-2xl">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-50">
                <th className="pb-4 pl-6">Producto</th>
                <th className="pb-4">SKU</th>
                <th className="pb-4">Categoría</th>
                <th className="pb-4 text-right">Costo</th>
                <th className="pb-4 text-right">Venta</th>
                <th className="pb-4 text-center">Stock</th>
                <th className="pb-4 pr-6 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredProducts.map(p => (
                <tr key={p.id} className="group hover:bg-slate-50/50 transition-colors">
                  <td className="py-4 pl-6">
                    <div className="flex items-center gap-4">
                      <div className="w-14 h-14 rounded-2xl bg-slate-100 overflow-hidden flex-shrink-0 border-2 border-white shadow-sm">
                        {p.image ? <img src={p.image} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-300"><Camera size={20}/></div>}
                      </div>
                      <span className="font-black text-slate-700">{p.name}</span>
                    </div>
                  </td>
                  <td className="py-4 text-slate-400 font-mono text-xs">{p.code}</td>
                  <td className="py-4">
                    <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-black uppercase">
                      {categories.find(c => c.id === p.categoryId)?.name || 'Sin Cat.'}
                    </span>
                  </td>
                  <td className="py-4 text-right text-slate-400 font-bold">${p.costPrice.toLocaleString()}</td>
                  <td className="py-4 text-right font-black text-slate-800">${p.salePrice.toLocaleString()}</td>
                  <td className="py-4 text-center">
                    <span className={`inline-flex items-center justify-center min-w-[32px] px-2 py-1 rounded-lg font-black text-xs ${p.stock <= 5 ? 'bg-red-50 text-red-500' : 'bg-slate-100 text-slate-600'}`}>
                      {p.stock}
                    </span>
                  </td>
                  <td className="py-4 pr-6 text-right space-x-1">
                    <button onClick={() => openEdit(p)} className="p-3 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all"><Edit2 size={18} /></button>
                    <button onClick={() => setProducts(prev => prev.filter(item => item.id !== p.id))} className="p-3 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <h3 className="text-2xl font-black text-slate-800">{editingId ? 'Editar Detalle' : 'Nuevo Producto'}</h3>
              <button onClick={closeModal} className="p-3 hover:bg-white rounded-2xl transition-all"><X size={24}/></button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[75vh] overflow-y-auto no-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nombre del Producto</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 font-bold"
                    value={formData.name}
                    onChange={e => setFormData(prev => ({ ...prev, name: e.target.value }))}
                  />
                </div>

                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoría</label>
                  {!isAddingCategory ? (
                    <div className="flex gap-2">
                      <select 
                        required
                        className="flex-1 px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 outline-none font-bold"
                        value={formData.categoryId}
                        onChange={e => setFormData(prev => ({ ...prev, categoryId: e.target.value }))}
                      >
                        <option value="">Seleccionar...</option>
                        {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                      <button 
                        type="button"
                        onClick={() => setIsAddingCategory(true)}
                        className="p-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl transition-all"
                        title="Nueva Categoría"
                      >
                        <FolderPlus size={24} />
                      </button>
                    </div>
                  ) : (
                    <div className="flex gap-2 animate-in slide-in-from-right-2 duration-200">
                      <input 
                        type="text"
                        placeholder="Nombre de la nueva categoría..."
                        className="flex-1 px-5 py-4 bg-emerald-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-200 font-bold"
                        value={newCategoryName}
                        onChange={e => setNewCategoryName(e.target.value)}
                        autoFocus
                      />
                      <button 
                        type="button"
                        onClick={handleCreateCategory}
                        className="p-4 bg-emerald-600 text-white rounded-2xl hover:bg-emerald-700 transition-all"
                      >
                        <Check size={24} />
                      </button>
                      <button 
                        type="button"
                        onClick={() => setIsAddingCategory(false)}
                        className="p-4 bg-slate-100 text-slate-500 rounded-2xl hover:bg-slate-200 transition-all"
                      >
                        <X size={24} />
                      </button>
                    </div>
                  )}
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Código / SKU</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 font-mono font-bold"
                    value={formData.code}
                    onChange={e => setFormData(prev => ({ ...prev, code: e.target.value }))}
                  />
                </div>

                <div className="md:col-span-2 space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Foto del Producto</label>
                  <div className="flex flex-col md:flex-row gap-6">
                    <div className="w-32 h-32 rounded-3xl bg-slate-50 border-4 border-white shadow-inner overflow-hidden flex items-center justify-center relative group">
                      {formData.image ? (
                        <>
                          <img src={formData.image} className="w-full h-full object-cover" />
                          <button type="button" onClick={() => setFormData(prev => ({...prev, image: ''}))} className="absolute inset-0 bg-red-500/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white"><Trash2 size={24}/></button>
                        </>
                      ) : (
                        <Camera className="text-slate-200" size={32} />
                      )}
                    </div>
                    <div className="flex-1 space-y-4">
                      {!isCameraActive ? (
                        <div className="flex gap-4">
                          <button 
                            type="button" 
                            onClick={startCamera}
                            className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-600 font-black px-4 py-3 rounded-2xl transition-all text-[10px] tracking-widest uppercase"
                          >
                            Usar Cámara
                          </button>
                          <label className="flex-1 cursor-pointer bg-slate-100 hover:bg-slate-200 text-slate-600 font-black px-4 py-3 rounded-2xl transition-all text-[10px] tracking-widest uppercase text-center flex items-center justify-center">
                            Cargar Archivo
                            <input type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
                          </label>
                        </div>
                      ) : (
                        <div className="relative rounded-2xl overflow-hidden bg-black aspect-video flex items-center justify-center">
                          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                          <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-4">
                            <button type="button" onClick={capturePhoto} className="bg-emerald-500 text-white p-3 rounded-full shadow-xl"><Check size={24}/></button>
                            <button type="button" onClick={stopCamera} className="bg-red-500 text-white p-3 rounded-full shadow-xl"><X size={24}/></button>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Precio Costo</label>
                  <input 
                    required 
                    type="number" 
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 font-bold"
                    value={formData.costPrice}
                    onChange={e => setFormData(prev => ({ ...prev, costPrice: Number(e.target.value) }))}
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Precio Venta</label>
                  <input 
                    required 
                    type="number" 
                    className="w-full px-5 py-4 bg-emerald-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-200 font-black text-emerald-600"
                    value={formData.salePrice}
                    onChange={e => setFormData(prev => ({ ...prev, salePrice: Number(e.target.value) }))}
                  />
                </div>
              </div>

              {!editingId && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Stock Inicial</label>
                  <input 
                    required 
                    type="number" 
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 font-bold"
                    value={formData.stock}
                    onChange={e => setFormData(prev => ({ ...prev, stock: Number(e.target.value) }))}
                  />
                </div>
              )}

              <div className="flex gap-4 pt-6 border-t border-slate-50">
                <button type="button" onClick={closeModal} className="flex-1 px-8 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">Cancelar</button>
                <button type="submit" className="flex-[2] px-8 py-5 bg-emerald-600 text-white font-black rounded-3xl hover:bg-emerald-700 shadow-xl shadow-emerald-100 transition-all uppercase tracking-widest text-xs">
                  {editingId ? 'Guardar Cambios' : 'Crear Producto'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Products;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Download, Wallet, Users, AlertCircle, Edit3, TrendingUp, Package } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, Category, FinancialSettings } from '../types';

interface StatsProps {
  sales: Sale[];
  products: Product[];
