import React, { useState, useRef } from 'react';
import { Plus, Search, Edit2, Trash2, Camera, X, Check, FolderPlus, RefreshCcw } from 'lucide-react';
import { Product, Category } from '../types';

interface ProductsProps {
  products: Product[];
  categories: Category[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  setCategories: React.Dispatch<React.SetStateAction<Category[]>>;
  addMovement: (productId: string, quantity: number, type: 'in' | 'out', reason: string) => void;
}

const Products: React.FC<ProductsProps> = ({ products, categories, setProducts, setCategories, addMovement }) => {
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const videoRef = useRef<HTMLVideoElement>(null);

  const [formData, setFormData] = useState({
    name: '',
    categoryId: '',
    code: '',
    image: '',
    costPrice: 0,
    salePrice: 0,
    stock: 0
  });

  const generateSKU = () => {
    return 'GP-' + Math.random().toString(36).substr(2, 7).toUpperCase();
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const startCamera = async () => {
    setIsCameraActive(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      alert("Acceso a cámara denegado o no disponible");
      setIsCameraActive(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current?.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setIsCameraActive(false);
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0);
        setFormData(prev => ({ ...prev, image: canvas.toDataURL('image/jpeg') }));
        stopCamera();
      }
    }
  };

  const handleCreateCategory = () => {
    if (!newCategoryName.trim()) return;
    const newCat: Category = {
      id: Math.random().toString(36).substr(2, 9),
      name: newCategoryName
    };
    setCategories(prev => [...prev, newCat]);
    setFormData(prev => ({ ...prev, categoryId: newCat.id }));
    setNewCategoryName('');
    setIsAddingCategory(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.categoryId) return alert("Selecciona una categoría");

    if (editingId) {
      setProducts(prev => prev.map(p => p.id === editingId ? { ...formData, id: editingId } : p));
    } else {
      const newProduct: Product = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      };
      setProducts(prev => [...prev, newProduct]);
      if (newProduct.stock > 0) {
        addMovement(newProduct.id, newProduct.stock, 'in', 'Carga inicial');
      }
    }
    closeModal();
  };

  const openNewProductModal = () => {
    setEditingId(null);
    setFormData({ 
      name: '', 
      categoryId: '', 
      code: generateSKU(), 
      image: '', 
      costPrice: 0, 
      salePrice: 0, 
      stock: 0 
    });
    setShowModal(true);
  };

  const closeModal = () => {
    stopCamera();
    setShowModal(false);
    setEditingId(null);
    setIsAddingCategory(false);
    setNewCategoryName('');
    setFormData({ name: '', categoryId: '', code: '', image: '', costPrice: 0, salePrice: 0, stock: 0 });
