import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Download, Wallet, Users, AlertCircle, Edit3, TrendingUp, Package, X, Search, ChevronRight, Calendar, Banknote, CreditCard } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, Category, FinancialSettings } from '../types';

interface StatsProps {
  sales: Sale[];
  products: Product[];
  categories: Category[];
  settings: FinancialSettings;
  setSettings: React.Dispatch<React.SetStateAction<FinancialSettings>>;
}

const Statistics: React.FC<StatsProps> = ({ sales, products, categories, settings, setSettings }) => {
  const [isInventoryBreakdownOpen, setIsInventoryBreakdownOpen] = useState(false);
  const [isSalesBreakdownOpen, setIsSalesBreakdownOpen] = useState<{ open: boolean; type: 'cash' | 'transfer' | null }>({ open: false, type: null });
  const [inventorySearch, setInventorySearch] = useState('');

  // Date Range Filtering
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });

  // Filtered Sales based on period
  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).getTime();
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);
    return sales.filter(s => s.date >= start && s.date <= end);
  }, [sales, dateRange]);

  const totalRevenue = useMemo(() => filteredSales.reduce((acc, s) => acc + s.total, 0), [filteredSales]);
  const cashSales = useMemo(() => filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0), [filteredSales]);
  const transferSales = useMemo(() => filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0), [filteredSales]);

  // Calculate total money invested in current stock (Inventory Value)
  const totalInventoryInvestment = useMemo(() => {
    return products.reduce((acc, p) => acc + (p.stock * p.costPrice), 0);
  }, [products]);

  // Inventory Breakdown data
  const inventoryBreakdown = useMemo(() => {
    return products
      .map(p => ({
        ...p,
        totalInvested: p.stock * p.costPrice,
        categoryName: categories.find(c => c.id === p.categoryId)?.name || 'Sin Categoría'
      }))
      .filter(p => p.name.toLowerCase().includes(inventorySearch.toLowerCase()) || p.code.includes(inventorySearch))
      .sort((a, b) => b.totalInvested - a.totalInvested);
  }, [products, categories, inventorySearch]);

  // Financial percentages from requirements
  const recoveryRate = 0.40;
  const reinvestmentRate = 0.20;
  const inspectorRate = 0.005;
  const salaryRate = settings.workerSalaryRate / 100;

  const profitRate = 1 - recoveryRate - reinvestmentRate - inspectorRate - salaryRate;

  const recoveryAmount = totalRevenue * recoveryRate;
  const reinvestmentAmount = totalRevenue * reinvestmentRate;
  const inspectorAmount = totalRevenue * inspectorRate;
  const salaryAmount = totalRevenue * salaryRate;
  const profitAmount = totalRevenue * profitRate;

  const chartData = [
    { name: 'Efectivo', value: cashSales, color: '#10b981' },
    { name: 'Transferencia', value: transferSales, color: '#3b82f6' },
  ];

  const distributionData = [
    { name: 'Recuperación (40%)', value: recoveryAmount, color: '#6366f1' },
    { name: 'Inversión Secundaria (20%)', value: reinvestmentAmount, color: '#f59e0b' },
    { name: 'Ganancia Neta', value: profitAmount, color: '#10b981' },
    { name: `Salario (${settings.workerSalaryRate}%)`, value: salaryAmount, color: '#ec4899' },
    { name: 'Inspector (0.5%)', value: inspectorAmount, color: '#64748b' },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    const now = new Date().toLocaleString();

    doc.setFontSize(22);
    doc.setTextColor(16, 185, 129); 
    doc.text("Informe Financiero GourmetPOS", 14, 20);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periodo: ${dateRange.start} a ${dateRange.end}`, 14, 28);
    doc.text(`Generado: ${now}`, 14, 33);

    doc.setFontSize(14);
    doc.setTextColor(30);
    doc.text("Resumen de Ingresos del Periodo", 14, 45);

    const financialRows = [
      ["Concepto", "Porcentaje", "Monto"],
      ["Ventas Totales", "100%", `$${totalRevenue.toLocaleString()}`],
      ["Recuperación de Inversión", "40%", `$${recoveryAmount.toLocaleString()}`],
      ["Inversión Secundaria (Reinversión)", "20%", `$${reinvestmentAmount.toLocaleString()}`],
      ["Ganancia Neta", `${(profitRate * 100).toFixed(1)}%`, `$${profitAmount.toLocaleString()}`],
      ["Salario de Trabajador", `${settings.workerSalaryRate}%`, `$${salaryAmount.toLocaleString()}`],
      ["Inspector (Gato)", "0.5%", `$${inspectorAmount.toLocaleString()}`],
    ];

    autoTable(doc, {
      startY: 50,
      head: [financialRows[0]],
      body: financialRows.slice(1),
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] },
      styles: { fontSize: 10 }
    });

    const finalY = (doc as any).lastAutoTable.finalY;
    doc.text(`Valor Total de Inversión en Almacén: $${totalInventoryInvestment.toLocaleString()}`, 14, finalY + 15);

    categories.forEach((cat) => {
      const catProducts = products.filter(p => p.categoryId === cat.id);
      if (catProducts.length === 0) return;

      const tableData = catProducts.map(p => [
        p.name,
        p.code,
        `$${p.costPrice.toLocaleString()}`,
        `$${p.salePrice.toLocaleString()}`,
        p.stock.toString()
      ]);

      autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY + 15,
        head: [[{content: `Categoría: ${cat.name}`, colSpan: 5, styles: {fillColor: [71, 85, 105], textColor: 255}}], ['Producto', 'Código', 'P. Costo', 'P. Venta', 'Stock']],
        body: tableData,
        theme: 'grid',
        styles: { fontSize: 8 },
        margin: { left: 14 }
      });
    });

    doc.save(`Reporte_GourmetPOS_${dateRange.start}_${dateRange.end}.pdf`);
  };

  const getSalesBreakdown = (type: 'cash' | 'transfer') => {
    return filteredSales.filter(s => s.paymentMethod === type).sort((a, b) => b.date - a.date);
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Header & Global Filters */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Análisis de Resultados</h2>
          <p className="text-slate-500 font-medium">Control financiero y rentabilidad por periodo</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
