        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Ganancia Neta ({(profitRate * 100).toFixed(1)}%)</p>
          <h4 className="text-3xl font-black text-emerald-600">${profitAmount.toLocaleString()}</h4>
        </div>

        <button 
          onClick={() => setIsSalesBreakdownOpen({ open: true, type: 'cash' })}
          className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 text-left hover:border-emerald-300 transition-all group"
        >
          <div className="flex justify-between items-start mb-1">
