              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Modals: Inventory Breakdown */}
      {isInventoryBreakdownOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 flex flex-col max-h-[90vh]">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Inversión en Almacén</h3>
                <p className="text-sm text-slate-500 font-medium">Valor total del stock actual: <span className="text-emerald-600 font-black">${totalInventoryInvestment.toLocaleString()}</span></p>
              </div>
              <button onClick={() => setIsInventoryBreakdownOpen(false)} className="p-3 hover:bg-white rounded-2xl transition-all shadow-sm"><X size={24}/></button>
            </div>
            <div className="p-6 border-b"><div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} /><input type="text" placeholder="Buscar producto..." className="w-full pl-12 pr-6 py-4 bg-slate-50 border-none rounded-2xl font-bold" value={inventorySearch} onChange={(e) => setInventorySearch(e.target.value)} /></div></div>
            <div className="flex-1 overflow-y-auto p-4 md:p-8 no-scrollbar">
              <table className="w-full text-left">
                <thead><tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50"><th className="pb-4">Producto</th><th className="pb-4 text-center">Stock</th><th className="pb-4 text-right">Costo Unit.</th><th className="pb-4 text-right pr-4">Inversión</th></tr></thead>
