                    <td className="py-4 text-center font-black">{p.stock}</td>
                    <td className="py-4 text-right text-slate-400 font-bold">${p.costPrice.toLocaleString()}</td>
                    <td className="py-4 text-right font-black text-emerald-600 pr-4">${p.totalInvested.toLocaleString()}</td>
                  </tr>
                ))}</tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Modals: Sales Breakdown (Cash/Transfer) */}
      {isSalesBreakdownOpen.open && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 flex flex-col max-h-[90vh]">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
