                <div>
                  <h3 className="text-2xl font-black text-slate-800">Ventas en {isSalesBreakdownOpen.type === 'cash' ? 'Efectivo' : 'Transferencia'}</h3>
                  <p className="text-sm text-slate-500 font-medium">Periodo: {dateRange.start} al {dateRange.end}</p>
                </div>
              </div>
              <button onClick={() => setIsSalesBreakdownOpen({ open: false, type: null })} className="p-3 hover:bg-white rounded-2xl transition-all shadow-sm"><X size={24}/></button>
            </div>

            <div className="bg-slate-50/50 p-6 border-b flex justify-between items-center">
              <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Historial de Transacciones</span>
              <span className={`text-lg font-black ${isSalesBreakdownOpen.type === 'cash' ? 'text-emerald-600' : 'text-blue-600'}`}>
                Total: ${ (isSalesBreakdownOpen.type === 'cash' ? cashSales : transferSales).toLocaleString() }
              </span>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 no-scrollbar">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                    <th className="pb-4 pl-4">ID Venta</th>
                    <th className="pb-4">Fecha & Hora</th>
                    <th className="pb-4 text-center">Items</th>
                    <th className="pb-4 text-right pr-4">Monto Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {getSalesBreakdown(isSalesBreakdownOpen.type!).map(sale => (
                    <tr key={sale.id} className="group hover:bg-slate-50/50 transition-colors">
                      <td className="py-4 pl-4 font-mono font-bold text-slate-400">#{sale.id.slice(-6).toUpperCase()}</td>
                      <td className="py-4">
