                        <p className="text-xs text-slate-400">{new Date(sale.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                      </td>
                      <td className="py-4 text-center">
                        <span className="bg-slate-100 px-2 py-1 rounded-lg text-xs font-black text-slate-600">
                          {sale.items.reduce((acc, i) => acc + i.quantity, 0)} items
