import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, LayoutGrid, BarChart3, Menu, X, Tag, TrendingUp } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';
import Insights from './components/Insights';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'pos' | 'inventory' | 'products' | 'stats' | 'insights'>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
  }, []);

  // Auto-Save Effect
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
  }, [products, categories, sales, movements, financialSettings]);

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      quantity,
      type,
      reason,
      date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);

    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        return { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity };
      }
      return p;
    }));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => {
      addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`);
    });
  }, [addMovement]);

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
    { id: 'insights', icon: TrendingUp, label: 'Inteligencia' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">GourmetPOS</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-8 tracking-tighter">GourmetPOS</h1>
          <nav className="space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as any);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
        <div className="absolute bottom-0 w-full p-6 border-t bg-slate-50/50">
          <p className="text-xs text-slate-400 font-medium uppercase tracking-wider mb-2">Sistema</p>
          <div className="flex items-center space-x-2 text-slate-600">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span className="text-xs font-bold uppercase tracking-widest">Auto-guardado activo</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && (
            <POS 
              products={products} 
              categories={categories} 
              onCompleteSale={completeSale} 
            />
          )}
          {activeTab === 'products' && (
            <Products 
              products={products} 
              categories={categories} 
              setProducts={setProducts} 
              setCategories={setCategories}
              addMovement={addMovement}
            />
          )}
          {activeTab === 'inventory' && (
            <Inventory 
              movements={movements} 
              products={products} 
              addMovement={addMovement}
            />
          )}
          {activeTab === 'stats' && (
            <Statistics 
              sales={sales} 
              products={products} 
              categories={categories}
              settings={financialSettings}
              setSettings={setFinancialSettings}
            />
          )}
          {activeTab === 'insights' && (
            <Insights 
              sales={sales} 
              products={products} 
              categories={categories}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  Cell, PieChart, Pie, AreaChart, Area, Legend, LineChart, Line 
} from 'recharts';
import { 
  TrendingUp, Star, Zap, Target, ArrowUpRight, 
  AlertTriangle, Lightbulb, ShoppingBag, Activity
} from 'lucide-react';
import { Sale, Product, Category } from '../types';

interface InsightsProps {
  sales: Sale[];
  products: Product[];
  categories: Category[];
}

const Insights: React.FC<InsightsProps> = ({ sales, products, categories }) => {

  // 1. Top Products (Revenue Drivers - Pareto Analysis)
  const topProducts = useMemo(() => {
    const productStats: Record<string, { name: string, revenue: number, units: number }> = {};

    sales.forEach(sale => {
      sale.items.forEach(item => {
        if (!productStats[item.productId]) {
          productStats[item.productId] = { name: item.name, revenue: 0, units: 0 };
        }
        productStats[item.productId].revenue += item.price * item.quantity;
        productStats[item.productId].units += item.quantity;
      });
    });

    return Object.values(productStats)
      .sort((a, b) => b.revenue - a.revenue)
      .slice(0, 5);
  }, [sales]);

  // 2. Sales by Category (Market Share)
  const categoryMarketShare = useMemo(() => {
    const catStats: Record<string, number> = {};

    sales.forEach(sale => {
      sale.items.forEach(item => {
        const prod = products.find(p => p.id === item.productId);
        const catId = prod?.categoryId || 'unknown';
        const catName = categories.find(c => c.id === catId)?.name || 'Otros';
        catStats[catName] = (catStats[catName] || 0) + (item.price * item.quantity);
      });
    });

    return Object.entries(catStats).map(([name, value]) => ({ name, value }));
  }, [sales, products, categories]);

  // 3. Peak Sales Hours (Consumer Behavior)
  const hourlyTraffic = useMemo(() => {
    const hours = Array.from({ length: 24 }, (_, i) => ({ 
      hour: `${i}:00`, 
      sales: 0,
      revenue: 0 
    }));

    sales.forEach(sale => {
      const hour = new Date(sale.date).getHours();
      hours[hour].sales += 1;
      hours[hour].revenue += sale.total;
    });

    return hours.filter(h => h.sales > 0 || (parseInt(h.hour) > 8 && parseInt(h.hour) < 22));
  }, [sales]);

  // 4. Strategic Metrics (KPIs)
  const kpis = useMemo(() => {
    const totalRevenue = sales.reduce((acc, s) => acc + s.total, 0);
    const totalCost = sales.reduce((acc, s) => {
      return acc + s.items.reduce((itemAcc, item) => {
        const p = products.find(prod => prod.id === item.productId);
        return itemAcc + ((p?.costPrice || 0) * item.quantity);
      }, 0);
    }, 0);

    const avgTicket = sales.length > 0 ? totalRevenue / sales.length : 0;
    const grossMargin = totalRevenue > 0 ? ((totalRevenue - totalCost) / totalRevenue) * 100 : 0;

    // Inventory Rotation (Sales volume vs Stock)
    const totalSoldUnits = sales.reduce((acc, s) => acc + s.items.reduce((ia, i) => ia + i.quantity, 0), 0);
    const totalStock = products.reduce((acc, p) => acc + p.stock, 0);
    const rotationIndex = totalStock > 0 ? (totalSoldUnits / totalStock) * 100 : 0;

    return { avgTicket, grossMargin, rotationIndex, totalRevenue };
  }, [sales, products]);

  // 5. Intelligent Recommendations
  const recommendations = useMemo(() => {
    const tips = [];

    // Check for high demand low stock
    const hotItemsLowStock = products.filter(p => {
      const sold = sales.reduce((acc, s) => acc + s.items.filter(i => i.productId === p.id).reduce((ia, i) => ia + i.quantity, 0), 0);
      return sold > 5 && p.stock < 10;
    });
    if (hotItemsLowStock.length > 0) {
      tips.push({
        type: 'warning',
        icon: AlertTriangle,
        text: `¡Alerta de Stock! ${hotItemsLowStock[0].name} es un éxito en ventas pero tiene poco inventario.`
      });
    }

    // Peak Hour suggestion
    const peakHour = [...hourlyTraffic].sort((a, b) => b.revenue - a.revenue)[0];
    if (peakHour) {
      tips.push({
        type: 'success',
        icon: Zap,
        text: `Hora Pico Detectada: Las ${peakHour.hour} son tu momento de mayor ingreso. Asegura tener personal suficiente.`
      });
    }

    // High Margin Opportunity
    const highMarginLowSale = products
      .map(p => ({ ...p, margin: ((p.salePrice - p.costPrice) / p.salePrice) * 100 }))
      .filter(p => p.margin > 50)
      .sort((a, b) => b.margin - a.margin)[0];

    if (highMarginLowSale) {
      tips.push({
        type: 'info',
        icon: Lightbulb,
        text: `Oportunidad de Ganancia: ${highMarginLowSale.name} tiene un margen excelente (${highMarginLowSale.margin.toFixed(0)}%). Considera impulsarlo con publicidad.`
      });
    }

    return tips;
  }, [products, sales, hourlyTraffic]);

  const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ec4899', '#6366f1', '#8b5cf6'];

  return (
    <div className="space-y-8 pb-16">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tight">Estudio de Mercado</h2>
        <p className="text-slate-500 font-medium">Análisis profundo del rendimiento de tu negocio</p>
      </header>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center mb-4">
            <ShoppingBag size={24} />
          </div>
          <p className="text-slate-400 text-xs font-black uppercase tracking-widest">Ticket Promedio</p>
          <h4 className="text-2xl font-black text-slate-800">${kpis.avgTicket.toLocaleString()}</h4>
          <p className="text-[10px] text-emerald-500 font-bold mt-1 flex items-center gap-1">
            <ArrowUpRight size={12} /> Basado en {sales.length} ventas
          </p>
        </div>

        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center mb-4">
            <Target size={24} />
          </div>
          <p className="text-slate-400 text-xs font-black uppercase tracking-widest">Margen Bruto</p>
          <h4 className="text-2xl font-black text-slate-800">{kpis.grossMargin.toFixed(1)}%</h4>
          <p className="text-[10px] text-blue-500 font-bold mt-1">Eficiencia de precios</p>
        </div>

        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="w-12 h-12 bg-amber-50 text-amber-600 rounded-2xl flex items-center justify-center mb-4">
            <Activity size={24} />
          </div>
          <p className="text-slate-400 text-xs font-black uppercase tracking-widest">Rotación Stock</p>
          <h4 className="text-2xl font-black text-slate-800">{kpis.rotationIndex.toFixed(1)}%</h4>
          <p className="text-[10px] text-amber-500 font-bold mt-1">Velocidad de salida</p>
        </div>

        <div className="bg-slate-900 p-6 rounded-[2rem] shadow-xl">
          <div className="w-12 h-12 bg-white/10 text-emerald-400 rounded-2xl flex items-center justify-center mb-4">
            <TrendingUp size={24} />
          </div>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Market Score</p>
          <h4 className="text-2xl font-black text-white">Saludable</h4>
          <p className="text-[10px] text-emerald-400 font-bold mt-1">Operación optimizada</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Top Products Chart */}
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <Star className="text-amber-400" fill="currentColor" />
              Top 5 Best Sellers
            </h3>
            <span className="text-[10px] font-black uppercase bg-slate-100 px-3 py-1 rounded-full text-slate-500">Por Ingresos</span>
          </div>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={topProducts} layout="vertical" margin={{ left: 20, right: 30 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis 
                  dataKey="name" 
                  type="category" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 11, fontWeight: 700, fill: '#64748b' }} 
                  width={100}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  contentStyle={{ borderRadius: '1rem', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                  formatter={(value: number) => [`$${value.toLocaleString()}`, 'Ingresos']}
                />
                <Bar dataKey="revenue" radius={[0, 10, 10, 0]} barSize={25}>
                  {topProducts.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Category Distribution */}
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8 flex items-center gap-2">
            <Target className="text-emerald-500" />
            Dominio del Mercado
          </h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryMarketShare}
                  cx="50%"
                  cy="50%"
                  innerRadius={65}
                  outerRadius={90}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {categoryMarketShare.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ borderRadius: '1rem', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                  formatter={(value: number) => [`$${value.toLocaleString()}`, 'Total Ventas']}
                />
                <Legend verticalAlign="bottom" height={36} iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Hourly Traffic - Heatmap */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <Activity className="text-blue-500" />
              Flujo de Clientes (Peak Hours)
            </h3>
            <p className="text-xs text-slate-400 font-bold">Concentración de ventas por hora del día</p>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={hourlyTraffic} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="hour" 
