import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Download, Wallet, Users, AlertCircle, Edit3, TrendingUp, Package, X, Search, ChevronRight, Calendar, Banknote, CreditCard, Box, History } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, Category, FinancialSettings } from '../types';

interface StatsProps {
  sales: Sale[];
  products: Product[];
  categories: Category[];
  settings: FinancialSettings;
  setSettings: React.Dispatch<React.SetStateAction<FinancialSettings>>;
}

const Statistics: React.FC<StatsProps> = ({ sales, products, categories, settings, setSettings }) => {
  const [isInventoryBreakdownOpen, setIsInventoryBreakdownOpen] = useState(false);
  const [isSalesBreakdownOpen, setIsSalesBreakdownOpen] = useState<{ open: boolean; type: 'cash' | 'transfer' | null }>({ open: false, type: null });
  const [selectedProductHistory, setSelectedProductHistory] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [productVolumeSearch, setProductVolumeSearch] = useState('');

  // Date Range Filtering
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });

  // Filtered Sales based on period
  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).getTime();
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);
    return sales.filter(s => s.date >= start && s.date <= end);
  }, [sales, dateRange]);

  // Total Revenue & Payment Methods
  const totalRevenue = useMemo(() => filteredSales.reduce((acc, s) => acc + s.total, 0), [filteredSales]);
  const cashSales = useMemo(() => filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0), [filteredSales]);
  const transferSales = useMemo(() => filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0), [filteredSales]);

  // Product Sales Volume Breakdown
  const productVolumeStats = useMemo(() => {
    const stats: Record<string, { totalUnits: number, daily: Record<string, number> }> = {};

    filteredSales.forEach(sale => {
      const dateStr = new Date(sale.date).toISOString().split('T')[0];
      sale.items.forEach(item => {
        if (!stats[item.productId]) {
          stats[item.productId] = { totalUnits: 0, daily: {} };
        }
        stats[item.productId].totalUnits += item.quantity;
        stats[item.productId].daily[dateStr] = (stats[item.productId].daily[dateStr] || 0) + item.quantity;
      });
    });

    return Object.entries(stats)
      .map(([id, data]) => {
        const product = products.find(p => p.id === id);
        return {
          id,
          name: product?.name || 'Desconocido',
          code: product?.code || '---',
          totalUnits: data.totalUnits,
          daily: data.daily
        };
      })
      .filter(p => p.name.toLowerCase().includes(productVolumeSearch.toLowerCase()))
      .sort((a, b) => b.totalUnits - a.totalUnits);
  }, [filteredSales, products, productVolumeSearch]);

  const totalUnitsSoldInPeriod = useMemo(() => {
    return productVolumeStats.reduce((acc, p) => acc + p.totalUnits, 0);
  }, [productVolumeStats]);

  // Financial percentages
  const recoveryRate = 0.40;
  const reinvestmentRate = 0.20;
  const inspectorRate = 0.005;
  const salaryRate = settings.workerSalaryRate / 100;
  const profitRate = 1 - recoveryRate - reinvestmentRate - inspectorRate - salaryRate;

  const recoveryAmount = totalRevenue * recoveryRate;
  const reinvestmentAmount = totalRevenue * reinvestmentRate;
  const inspectorAmount = totalRevenue * inspectorRate;
  const salaryAmount = totalRevenue * salaryRate;
  const profitAmount = totalRevenue * profitRate;

  const exportPDF = () => {
    const doc = new jsPDF();
    const now = new Date().toLocaleString();

    doc.setFontSize(22);
    doc.setTextColor(16, 185, 129); 
    doc.text("Informe Financiero GourmetPOS", 14, 20);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periodo: ${dateRange.start} a ${dateRange.end}`, 14, 28);
    doc.text(`Generado: ${now}`, 14, 33);

    const financialRows = [
      ["Concepto", "Porcentaje", "Monto"],
      ["Ventas Totales", "100%", `$${totalRevenue.toLocaleString()}`],
      ["Recuperación", "40%", `$${recoveryAmount.toLocaleString()}`],
      ["Ganancia Neta", `${(profitRate * 100).toFixed(1)}%`, `$${profitAmount.toLocaleString()}`],
      ["Salario Trabajador", `${settings.workerSalaryRate}%`, `$${salaryAmount.toLocaleString()}`],
    ];

    autoTable(doc, {
      startY: 40,
      head: [financialRows[0]],
      body: financialRows.slice(1),
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] }
    });

    doc.setFontSize(14);
    doc.setTextColor(30);
    doc.text("Resumen de Unidades Vendidas", 14, (doc as any).lastAutoTable.finalY + 15);

    const volumeRows = productVolumeStats.map(p => [p.name, p.code, p.totalUnits.toString()]);
    autoTable(doc, {
      startY: (doc as any).lastAutoTable.finalY + 20,
      head: [['Producto', 'SKU', 'Unidades Vendidas']],
      body: volumeRows,
      theme: 'grid',
      headStyles: { fillColor: [71, 85, 105] }
    });

    doc.save(`Reporte_POS_${dateRange.start}_${dateRange.end}.pdf`);
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Header & Filters */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Análisis de Resultados</h2>
          <p className="text-slate-500 font-medium">Control financiero y de inventario por periodo</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
          <button 
            onClick={exportPDF}
            className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-4 rounded-2xl hover:bg-emerald-700 transition-all font-bold shadow-xl shadow-emerald-100 whitespace-nowrap w-full sm:w-auto justify-center"
          >
            <Download size={20} />
            Generar Informe PDF
          </button>
        </div>
      </div>

      {/* Primary KPIs */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-900 p-6 rounded-3xl shadow-xl">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Total Ingresos</p>
          <h4 className="text-3xl font-black text-white">${totalRevenue.toLocaleString()}</h4>
          <div className="mt-4 flex items-center gap-2 text-emerald-400 text-xs font-bold bg-white/10 w-fit px-3 py-1 rounded-full">
            <TrendingUp size={14} />
            <span>Actualizado</span>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Unidades Vendidas</p>
          <h4 className="text-3xl font-black text-blue-600">{totalUnitsSoldInPeriod}</h4>
          <p className="text-[10px] text-slate-400 font-bold mt-1">En el periodo seleccionado</p>
        </div>

