import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Download, Wallet, Users, AlertCircle, Edit3, TrendingUp, Package, X, Search, ChevronRight, Calendar, Banknote, CreditCard, Box, History } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Sale, Product, Category, FinancialSettings } from '../types';

interface StatsProps {
  sales: Sale[];
  products: Product[];
  categories: Category[];
  settings: FinancialSettings;
  setSettings: React.Dispatch<React.SetStateAction<FinancialSettings>>;
}

const Statistics: React.FC<StatsProps> = ({ sales, products, categories, settings, setSettings }) => {
  const [isInventoryBreakdownOpen, setIsInventoryBreakdownOpen] = useState(false);
  const [isSalesBreakdownOpen, setIsSalesBreakdownOpen] = useState<{ open: boolean; type: 'cash' | 'transfer' | null }>({ open: false, type: null });
  const [selectedProductHistory, setSelectedProductHistory] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [productVolumeSearch, setProductVolumeSearch] = useState('');

  // Date Range Filtering
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });

  // Filtered Sales based on period
  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).getTime();
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);
    return sales.filter(s => s.date >= start && s.date <= end);
  }, [sales, dateRange]);

  // Total Revenue & Payment Methods
  const totalRevenue = useMemo(() => filteredSales.reduce((acc, s) => acc + s.total, 0), [filteredSales]);
  const cashSales = useMemo(() => filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0), [filteredSales]);
  const transferSales = useMemo(() => filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0), [filteredSales]);

  // Fix: Missing chartData for Payment Methods chart
  const chartData = useMemo(() => [
    { name: 'Efectivo', value: cashSales, color: '#10b981' },
    { name: 'Transferencia', value: transferSales, color: '#3b82f6' }
  ], [cashSales, transferSales]);

  // Product Sales Volume Breakdown
  const productVolumeStats = useMemo(() => {
    const stats: Record<string, { totalUnits: number, daily: Record<string, number> }> = {};

    filteredSales.forEach(sale => {
      const dateStr = new Date(sale.date).toISOString().split('T')[0];
      sale.items.forEach(item => {
        if (!stats[item.productId]) {
          stats[item.productId] = { totalUnits: 0, daily: {} };
        }
        stats[item.productId].totalUnits += item.quantity;
        stats[item.productId].daily[dateStr] = (stats[item.productId].daily[dateStr] || 0) + item.quantity;
      });
    });

    return Object.entries(stats)
      .map(([id, data]) => {
        const product = products.find(p => p.id === id);
        return {
          id,
          name: product?.name || 'Desconocido',
          code: product?.code || '---',
          totalUnits: data.totalUnits,
          daily: data.daily
        };
      })
      .filter(p => p.name.toLowerCase().includes(productVolumeSearch.toLowerCase()))
      .sort((a, b) => b.totalUnits - a.totalUnits);
  }, [filteredSales, products, productVolumeSearch]);

  const totalUnitsSoldInPeriod = useMemo(() => {
    return productVolumeStats.reduce((acc, p) => acc + p.totalUnits, 0);
  }, [productVolumeStats]);

  // Financial percentages
  const recoveryRate = 0.40;
  const reinvestmentRate = 0.20;
  const inspectorRate = 0.005;
  const salaryRate = settings.workerSalaryRate / 100;
  const profitRate = 1 - recoveryRate - reinvestmentRate - inspectorRate - salaryRate;

  const recoveryAmount = totalRevenue * recoveryRate;
  const reinvestmentAmount = totalRevenue * reinvestmentRate;
  const inspectorAmount = totalRevenue * inspectorRate;
  const salaryAmount = totalRevenue * salaryRate;
  const profitAmount = totalRevenue * profitRate;

  const exportPDF = () => {
    const doc = new jsPDF();
    const now = new Date().toLocaleString();

    doc.setFontSize(22);
    doc.setTextColor(16, 185, 129); 
    doc.text("Informe Financiero GourmetPOS", 14, 20);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periodo: ${dateRange.start} a ${dateRange.end}`, 14, 28);
    doc.text(`Generado: ${now}`, 14, 33);

    const financialRows = [
      ["Concepto", "Porcentaje", "Monto"],
      ["Ventas Totales", "100%", `$${totalRevenue.toLocaleString()}`],
      ["Recuperación", "40%", `$${recoveryAmount.toLocaleString()}`],
      ["Ganancia Neta", `${(profitRate * 100).toFixed(1)}%`, `$${profitAmount.toLocaleString()}`],
      ["Salario Trabajador", `${settings.workerSalaryRate}%`, `$${salaryAmount.toLocaleString()}`],
    ];

    autoTable(doc, {
      startY: 40,
      head: [financialRows[0]],
      body: financialRows.slice(1),
      theme: 'striped',
      headStyles: { fillColor: [16, 185, 129] }
    });

    doc.setFontSize(14);
    doc.setTextColor(30);
    doc.text("Resumen de Unidades Vendidas", 14, (doc as any).lastAutoTable.finalY + 15);

    const volumeRows = productVolumeStats.map(p => [p.name, p.code, p.totalUnits.toString()]);
    autoTable(doc, {
      startY: (doc as any).lastAutoTable.finalY + 20,
      head: [['Producto', 'SKU', 'Unidades Vendidas']],
      body: volumeRows,
      theme: 'grid',
      headStyles: { fillColor: [71, 85, 105] }
    });

    doc.save(`Reporte_POS_${dateRange.start}_${dateRange.end}.pdf`);
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Header & Filters */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Análisis de Resultados</h2>
          <p className="text-slate-500 font-medium">Control financiero y de inventario por periodo</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
          <button 
            onClick={exportPDF}
            className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-4 rounded-2xl hover:bg-emerald-700 transition-all font-bold shadow-xl shadow-emerald-100 whitespace-nowrap w-full sm:w-auto justify-center"
          >
            <Download size={20} />
            Generar Informe PDF
          </button>
        </div>
      </div>

      {/* Primary KPIs */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-900 p-6 rounded-3xl shadow-xl">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Total Ingresos</p>
          <h4 className="text-3xl font-black text-white">${totalRevenue.toLocaleString()}</h4>
          <div className="mt-4 flex items-center gap-2 text-emerald-400 text-xs font-bold bg-white/10 w-fit px-3 py-1 rounded-full">
            <TrendingUp size={14} />
            <span>Actualizado</span>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <p className="text-slate-400 text-xs font-bold uppercase mb-1">Unidades Vendidas</p>
          <h4 className="text-3xl font-black text-blue-600">{totalUnitsSoldInPeriod}</h4>
          <p className="text-[10px] text-slate-400 font-bold mt-1">En el periodo seleccionado</p>
        </div>

        <button 
          onClick={() => setIsSalesBreakdownOpen({ open: true, type: 'cash' })}
          className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 text-left hover:border-emerald-300 transition-all group"
        >
          <p className="text-slate-400 text-xs font-bold uppercase mb-1 flex justify-between">
            Efectivo <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-all" />
          </p>
          <h4 className="text-3xl font-black text-slate-800">${cashSales.toLocaleString()}</h4>
        </button>

        <button 
          onClick={() => setIsSalesBreakdownOpen({ open: true, type: 'transfer' })}
          className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 text-left hover:border-blue-300 transition-all group"
        >
          <p className="text-slate-400 text-xs font-bold uppercase mb-1 flex justify-between">
            Transferencia <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-all" />
          </p>
          <h4 className="text-3xl font-black text-slate-800">${transferSales.toLocaleString()}</h4>
        </button>
      </div>

      {/* Main Content Area: Daily Volume Control */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-8 border-b border-slate-50 bg-slate-50/30 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <Box className="text-blue-500" />
              Control de Inventario Diario
            </h3>
            <p className="text-sm text-slate-500 font-medium">Ventas por producto desglosadas por fecha</p>
          </div>
          <div className="relative w-full md:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder="Filtrar producto..." 
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-100 rounded-xl text-sm font-bold focus:ring-2 focus:ring-blue-100 outline-none transition-all"
              value={productVolumeSearch}
              onChange={(e) => setProductVolumeSearch(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                <th className="py-4 pl-8">Producto</th>
                <th className="py-4">SKU</th>
                <th className="py-4 text-center">Unidades Totales</th>
                <th className="py-4 text-right pr-8">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {productVolumeStats.map(p => (
                <tr key={p.id} className="group hover:bg-slate-50/50 transition-colors">
                  <td className="py-4 pl-8">
                    <span className="font-black text-slate-700">{p.name}</span>
                  </td>
                  <td className="py-4 font-mono text-xs text-slate-400">{p.code}</td>
                  <td className="py-4 text-center">
                    <span className="px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-sm font-black">
                      {p.totalUnits}
                    </span>
                  </td>
                  <td className="py-4 text-right pr-8">
                    <button 
                      onClick={() => setSelectedProductHistory(p.id)}
                      className="flex items-center gap-2 text-slate-400 hover:text-blue-600 font-black text-[10px] uppercase tracking-wider ml-auto bg-slate-100 px-4 py-2 rounded-xl transition-all"
                    >
                      <History size={14} />
                      Ver Diario
                    </button>
                  </td>
                </tr>
              ))}
              {productVolumeStats.length === 0 && (
                <tr>
                  <td colSpan={4} className="py-12 text-center text-slate-400 font-medium italic">No hay registros para este periodo</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal: Daily History Breakdown for Single Product */}
      {selectedProductHistory && (() => {
        const prodData = productVolumeStats.find(p => p.id === selectedProductHistory);
        if (!prodData) return null;

        const dailyEntries = Object.entries(prodData.daily)
          .sort((a, b) => new Date(b[0]).getTime() - new Date(a[0]).getTime());

        return (
          <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
            <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 flex flex-col max-h-[80vh]">
              <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
                <div className="flex items-center gap-4">
                  <div className="p-4 rounded-2xl bg-blue-100 text-blue-600">
                    <History size={24} />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-800">{prodData.name}</h3>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{prodData.code}</p>
                  </div>
                </div>
                <button onClick={() => setSelectedProductHistory(null)} className="p-3 hover:bg-white rounded-2xl transition-all shadow-sm"><X size={24}/></button>
              </div>

              <div className="p-6 bg-slate-50/50 border-b flex justify-between items-center">
                <span className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Desglose Diario de Salidas</span>
                <span className="text-sm font-black text-blue-600">Total: {prodData.totalUnits} unidades</span>
              </div>

              <div className="flex-1 overflow-y-auto p-4 md:p-8 no-scrollbar">
                <div className="space-y-4">
                  {dailyEntries.map(([date, units]) => (
                    <div key={date} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:border-blue-200 transition-all">
                      <div className="flex items-center gap-3">
                        <Calendar size={18} className="text-slate-400" />
                        <span className="font-bold text-slate-700">
                          {new Date(date).toLocaleDateString(undefined, { weekday: 'long', day: 'numeric', month: 'long' })}
                        </span>
                      </div>
                      <span className="bg-white px-4 py-2 rounded-xl text-blue-600 font-black text-lg border border-slate-100">
                        {units}
                      </span>
                    </div>
                  ))}
                  {dailyEntries.length === 0 && (
                    <p className="text-center text-slate-400 font-medium py-10">Sin registros diarios</p>
                  )}
                </div>
              </div>

              <div className="p-8 border-t bg-slate-50 text-right">
                <button 
                  onClick={() => setSelectedProductHistory(null)}
                  className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all"
                >
                  Cerrar
                </button>
              </div>
            </div>
          </div>
        );
      })()}

      {/* Existing Sales Breakdown Modals... */}
      {isSalesBreakdownOpen.open && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 flex flex-col max-h-[90vh]">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <div className="flex items-center gap-4">
                <div className={`p-4 rounded-2xl ${isSalesBreakdownOpen.type === 'cash' ? 'bg-emerald-100 text-emerald-600' : 'bg-blue-100 text-blue-600'}`}>
                  {isSalesBreakdownOpen.type === 'cash' ? <Banknote size={24} /> : <CreditCard size={24} />}
                </div>
                <div>
                  <h3 className="text-2xl font-black text-slate-800">Ventas en {isSalesBreakdownOpen.type === 'cash' ? 'Efectivo' : 'Transferencia'}</h3>
                  <p className="text-sm text-slate-500 font-medium">Periodo: {dateRange.start} al {dateRange.end}</p>
                </div>
              </div>
              <button onClick={() => setIsSalesBreakdownOpen({ open: false, type: null })} className="p-3 hover:bg-white rounded-2xl transition-all shadow-sm"><X size={24}/></button>
            </div>
            <div className="flex-1 overflow-y-auto p-4 md:p-8 no-scrollbar">
              {/* Sales List rendering... (Truncated for brevity, remains as original logic) */}
              <table className="w-full text-left">
                <thead><tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50"><th className="pb-4">Fecha</th><th className="pb-4 text-center">Items</th><th className="pb-4 text-right">Total</th></tr></thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredSales.filter(s => s.paymentMethod === isSalesBreakdownOpen.type).map(sale => (
                    <tr key={sale.id} className="group hover:bg-slate-50/50">
                      <td className="py-4">
                        <p className="font-bold">{new Date(sale.date).toLocaleString()}</p>
                      </td>
                      <td className="py-4 text-center">
                        <span className="px-2 py-1 bg-slate-100 rounded-lg text-xs font-black">{sale.items.length} prod</span>
                      </td>
                      <td className="py-4 text-right font-black">${sale.total.toLocaleString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Secondary Distribution Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
            <Wallet className="text-emerald-500" />
            Ventas por Método (Periodo)
          </h3>
          <div className="h-64">
            {totalRevenue > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={chartData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                  </Pie>
                  <Tooltip formatter={(value: number) => `$${value.toLocaleString()}`} />
                </PieChart>
              </ResponsiveContainer>
            ) : <div className="h-full flex items-center justify-center text-slate-400 italic">Sin datos</div>}
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
            <AlertCircle className="text-emerald-500" />
            Distribución de Ingresos Estimada
          </h3>
          <div className="space-y-5">
            {[
              { name: 'Recuperación (40%)', val: recoveryAmount, col: '#6366f1' },
              { name: 'Reinversión (20%)', val: reinvestmentAmount, col: '#f59e0b' },
              { name: 'Ganancia Neta', val: profitAmount, col: '#10b981' },
              { name: `Salario (${settings.workerSalaryRate}%)`, val: salaryAmount, col: '#ec4899' }
            ].map(item => (
              <div key={item.name} className="space-y-1">
                <div className="flex justify-between text-xs font-bold text-slate-600">
                  <span>{item.name}</span>
                  <span className="text-slate-900">${item.val.toLocaleString()}</span>
                </div>
                <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                  <div className="h-full transition-all duration-1000" style={{ backgroundColor: item.col, width: `${totalRevenue > 0 ? (item.val / totalRevenue) * 100 : 0}%` }} />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Statistics;

import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, LayoutGrid, BarChart3, Menu, X, Tag, TrendingUp, ReceiptText } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';
import Insights from './components/Insights';
import SalesHistory from './components/SalesHistory';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'pos' | 'inventory' | 'products' | 'stats' | 'insights' | 'sales-history'>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
  }, []);

  // Auto-Save Effect
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
  }, [products, categories, sales, movements, financialSettings]);

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      quantity,
      type,
      reason,
      date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);

    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        return { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity };
      }
      return p;
    }));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => {
      addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`);
    });
  }, [addMovement]);

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'sales-history', icon: ReceiptText, label: 'Historial' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
    { id: 'insights', icon: TrendingUp, label: 'Inteligencia' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">GourmetPOS</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-8 tracking-tighter">GourmetPOS</h1>
          <nav className="space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as any);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
        <div className="absolute bottom-0 w-full p-6 border-t bg-slate-50/50">
          <p className="text-xs text-slate-400 font-medium uppercase tracking-wider mb-2">Sistema</p>
          <div className="flex items-center space-x-2 text-slate-600">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span className="text-xs font-bold uppercase tracking-widest">Auto-guardado activo</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && (
            <POS 
              products={products} 
              categories={categories} 
              onCompleteSale={completeSale} 
            />
          )}
          {activeTab === 'sales-history' && (
            <SalesHistory 
              sales={sales} 
            />
          )}
          {activeTab === 'products' && (
            <Products 
              products={products} 
              categories={categories} 
              setProducts={setProducts} 
              setCategories={setCategories}
              addMovement={addMovement}
            />
          )}
          {activeTab === 'inventory' && (
            <Inventory 
              movements={movements} 
              products={products} 
              addMovement={addMovement}
            />
          )}
          {activeTab === 'stats' && (
            <Statistics 
              sales={sales} 
              products={products} 
              categories={categories}
              settings={financialSettings}
              setSettings={setFinancialSettings}
            />
          )}
          {activeTab === 'insights' && (
            <Insights 
              sales={sales} 
              products={products} 
              categories={categories}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Calendar, Search, Banknote, CreditCard, ChevronRight, ChevronDown, ReceiptText, FileSpreadsheet, Download } from 'lucide-react';
import { Sale } from '../types';

interface SalesHistoryProps {
  sales: Sale[];
}

const SalesHistory: React.FC<SalesHistoryProps> = ({ sales }) => {
  const [expandedSale, setExpandedSale] = useState<string | null>(null);
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().setHours(0,0,0,0)).toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });
  const [searchTerm, setSearchTerm] = useState('');

  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).getTime();
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);

    return sales.filter(s => {
      const matchesDate = s.date >= start && s.date <= end;
      const matchesSearch = s.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           s.items.some(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
      return matchesDate && matchesSearch;
    }).sort((a, b) => b.date - a.date);
  }, [sales, dateRange, searchTerm]);

  const stats = useMemo(() => {
    const total = filteredSales.reduce((acc, s) => acc + s.total, 0);
    const cash = filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0);
    const transfer = filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0);
    const productsCount = filteredSales.reduce((acc, s) => acc + s.items.reduce((sum, item) => sum + item.quantity, 0), 0);

    return { total, cash, transfer, productsCount };
  }, [filteredSales]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ReceiptText className="text-emerald-600" size={32} />
            Historial de Ventas
          </h2>
          <p className="text-slate-500 font-medium">Registro detallado de transacciones y cobros</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
        </div>
      </header>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-900 p-6 rounded-[2rem] shadow-xl text-white">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Total Recaudado</p>
          <h4 className="text-3xl font-black">${stats.total.toLocaleString()}</h4>
          <p className="text-[10px] text-emerald-400 font-bold mt-1 uppercase tracking-wider">{filteredSales.length} ventas realizadas</p>
        </div>

        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center">
            <Banknote size={24} />
          </div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">En Efectivo</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.cash.toLocaleString()}</h4>
          </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center">
            <CreditCard size={24} />
          </div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Transferencia</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.transfer.toLocaleString()}</h4>
          </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center">
            <FileSpreadsheet size={24} />
          </div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Prod. Vendidos</p>
            <h4 className="text-2xl font-black text-slate-800">{stats.productsCount} <span className="text-xs font-medium text-slate-400">unidades</span></h4>
          </div>
        </div>
      </div>

      {/* Sales List */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b flex flex-col md:flex-row justify-between items-center gap-4 bg-slate-50/30">
          <h3 className="text-lg font-black text-slate-700 px-2">Listado de Transacciones</h3>
          <div className="relative w-full md:w-80">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar venta o producto..." 
              className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 font-medium text-sm transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                <th className="py-4 pl-8">ID Venta</th>
                <th className="py-4">Fecha & Hora</th>
                <th className="py-4">Método</th>
                <th className="py-4 text-center">Unidades</th>
                <th className="py-4 text-right pr-8">Monto Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredSales.map(sale => (
                <React.Fragment key={sale.id}>
                  <tr 
                    onClick={() => setExpandedSale(expandedSale === sale.id ? null : sale.id)}
                    className="group hover:bg-slate-50 cursor-pointer transition-colors"
                  >
                    <td className="py-5 pl-8">
                      <div className="flex items-center gap-3">
                        {expandedSale === sale.id ? <ChevronDown size={16} className="text-slate-300" /> : <ChevronRight size={16} className="text-slate-300" />}
                        <span className="font-mono text-xs font-bold text-slate-400 uppercase">#{sale.id.slice(-6)}</span>
                      </div>
                    </td>
                    <td className="py-5">
                      <p className="text-sm font-black text-slate-700">{new Date(sale.date).toLocaleDateString()}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{new Date(sale.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
