import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, LayoutGrid, BarChart3, Menu, X, Tag, TrendingUp, ReceiptText } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';
import Insights from './components/Insights';
import SalesHistory from './components/SalesHistory';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'pos' | 'inventory' | 'products' | 'stats' | 'insights' | 'sales-history'>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
  }, []);

  // Auto-Save Effect
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
  }, [products, categories, sales, movements, financialSettings]);

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      quantity,
      type,
      reason,
      date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);

    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        return { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity };
      }
      return p;
    }));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => {
      addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`);
    });
  }, [addMovement]);

  const deleteSale = useCallback((saleId: string) => {
    const saleToDelete = sales.find(s => s.id === saleId);
    if (!saleToDelete) return;

    if (window.confirm("¿Está seguro de eliminar esta venta? El stock será devuelto al inventario.")) {
      saleToDelete.items.forEach(item => {
        addMovement(item.productId, item.quantity, 'in', `Anulación venta #${saleId.slice(-4)}`);
      });
      setSales(prev => prev.filter(s => s.id !== saleId));
    }
  }, [sales, addMovement]);

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'sales-history', icon: ReceiptText, label: 'Historial' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
    { id: 'insights', icon: TrendingUp, label: 'Inteligencia' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">GourmetPOS</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-8 tracking-tighter">GourmetPOS</h1>
          <nav className="space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as any);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
        <div className="absolute bottom-0 w-full p-6 border-t bg-slate-50/50">
          <p className="text-xs text-slate-400 font-medium uppercase tracking-wider mb-2">Sistema</p>
          <div className="flex items-center space-x-2 text-slate-600">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span className="text-xs font-bold uppercase tracking-widest">Auto-guardado activo</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && (
            <POS 
              products={products} 
              categories={categories} 
              onCompleteSale={completeSale} 
            />
          )}
          {activeTab === 'sales-history' && (
            <SalesHistory 
              sales={sales} 
              products={products}
              movements={movements}
              onDeleteSale={deleteSale}
            />
          )}
          {activeTab === 'products' && (
            <Products 
              products={products} 
              categories={categories} 
              setProducts={setProducts} 
              setCategories={setCategories}
              addMovement={addMovement}
            />
          )}
          {activeTab === 'inventory' && (
            <Inventory 
              movements={movements} 
              products={products} 
              addMovement={addMovement}
            />
          )}
          {activeTab === 'stats' && (
            <Statistics 
              sales={sales} 
              products={products} 
              categories={categories}
              settings={financialSettings}
              setSettings={setFinancialSettings}
            />
          )}
          {activeTab === 'insights' && (
            <Insights 
              sales={sales} 
              products={products} 
              categories={categories}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Calendar, Search, Banknote, CreditCard, ChevronRight, ChevronDown, ReceiptText, FileSpreadsheet, Trash2, X, Box, Info } from 'lucide-react';
import { Sale, Product, InventoryMovement } from '../types';

interface SalesHistoryProps {
  sales: Sale[];
  products: Product[];
  movements: InventoryMovement[];
  onDeleteSale: (id: string) => void;
}

const SalesHistory: React.FC<SalesHistoryProps> = ({ sales, products, movements, onDeleteSale }) => {
  const [expandedSale, setExpandedSale] = useState<string | null>(null);
  const [showInventoryDetail, setShowInventoryDetail] = useState(false);
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().setHours(0,0,0,0)).toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });
  const [searchTerm, setSearchTerm] = useState('');

  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).getTime();
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);

    return sales.filter(s => {
      const matchesDate = s.date >= start && s.date <= end;
      const matchesSearch = s.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           s.items.some(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
      return matchesDate && matchesSearch;
    }).sort((a, b) => b.date - a.date);
  }, [sales, dateRange, searchTerm]);

  const stats = useMemo(() => {
    const total = filteredSales.reduce((acc, s) => acc + s.total, 0);
    const cash = filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0);
    const transfer = filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0);
    const productsCount = filteredSales.reduce((acc, s) => acc + s.items.reduce((sum, item) => sum + item.quantity, 0), 0);

    return { total, cash, transfer, productsCount };
  }, [filteredSales]);

  // Logic for Detailed Inventory Snapshot per product for the selected period
  const productPeriodStats = useMemo(() => {
    const startTs = new Date(dateRange.start).setHours(0,0,0,0);
    const endTs = new Date(dateRange.end).setHours(23,59,59,999);

    // 1. Identify all products involved in movements or currently in stock
    return products.map(product => {
      const movementsInPeriod = movements.filter(m => m.productId === product.id && m.date >= startTs && m.date <= endTs);
      const movementsAfterPeriod = movements.filter(m => m.productId === product.id && m.date > endTs);

      const totalSoldInPeriod = filteredSales.reduce((acc, sale) => {
          const item = sale.items.find(i => i.productId === product.id);
          return acc + (item?.quantity || 0);
      }, 0);

      // Backtrack from current stock to period start
      // Initial Stock at T1 = StockNow + TotalOut(since T1) - TotalIn(since T1)
      const movementsSinceStart = movements.filter(m => m.productId === product.id && m.date >= startTs);
      const totalOutSinceStart = movementsSinceStart.filter(m => m.type === 'out').reduce((sum, m) => sum + m.quantity, 0);
      const totalInSinceStart = movementsSinceStart.filter(m => m.type === 'in').reduce((sum, m) => sum + m.quantity, 0);

      const initialStock = product.stock + totalOutSinceStart - totalInSinceStart;

      // Final Stock at T2 = Initial Stock + InPeriod - OutPeriod
      const inPeriod = movementsInPeriod.filter(m => m.type === 'in').reduce((sum, m) => sum + m.quantity, 0);
      const outPeriod = movementsInPeriod.filter(m => m.type === 'out').reduce((sum, m) => sum + m.quantity, 0);
      const finalStock = initialStock + inPeriod - outPeriod;

      return {
        id: product.id,
        name: product.name,
        code: product.code,
        unitsSold: totalSoldInPeriod,
        initialStock,
        finalStock,
        hasActivity: movementsInPeriod.length > 0
      };
    }).filter(p => p.hasActivity || p.unitsSold > 0).sort((a, b) => b.unitsSold - a.unitsSold);
  }, [dateRange, products, movements, filteredSales]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ReceiptText className="text-emerald-600" size={32} />
            Historial de Ventas
          </h2>
          <p className="text-slate-500 font-medium">Registro detallado de transacciones y cobros</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
        </div>
      </header>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-900 p-6 rounded-[2rem] shadow-xl text-white">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Total Recaudado</p>
          <h4 className="text-3xl font-black">${stats.total.toLocaleString()}</h4>
          <p className="text-[10px] text-emerald-400 font-bold mt-1 uppercase tracking-wider">{filteredSales.length} ventas realizadas</p>
        </div>

        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center">
            <Banknote size={24} />
          </div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">En Efectivo</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.cash.toLocaleString()}</h4>
          </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center">
            <CreditCard size={24} />
          </div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Transferencia</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.transfer.toLocaleString()}</h4>
          </div>
        </div>

        <button 
          onClick={() => setShowInventoryDetail(true)}
          className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5 hover:bg-emerald-50 transition-all text-left group"
        >
          <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
            <FileSpreadsheet size={24} />
          </div>
          <div className="flex-1">
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest flex items-center justify-between">
              Prod. Vendidos <Info size={12} />
            </p>
            <h4 className="text-2xl font-black text-slate-800">{stats.productsCount} <span className="text-xs font-medium text-slate-400">unidades</span></h4>
            <p className="text-[9px] text-emerald-600 font-bold mt-1 uppercase">Clic para ver detalle stock</p>
          </div>
        </button>
      </div>

      {/* Sales List */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b flex flex-col md:flex-row justify-between items-center gap-4 bg-slate-50/30">
          <h3 className="text-lg font-black text-slate-700 px-2">Listado de Transacciones</h3>
          <div className="relative w-full md:w-80">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar venta o producto..." 
              className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 font-medium text-sm transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                <th className="py-4 pl-8">ID Venta</th>
                <th className="py-4">Fecha & Hora</th>
                <th className="py-4">Método</th>
                <th className="py-4 text-center">Unidades</th>
                <th className="py-4 text-right pr-8">Monto Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredSales.map(sale => (
                <React.Fragment key={sale.id}>
                  <tr 
                    onClick={() => setExpandedSale(expandedSale === sale.id ? null : sale.id)}
                    className="group hover:bg-slate-50 cursor-pointer transition-colors"
                  >
                    <td className="py-5 pl-8">
                      <div className="flex items-center gap-3">
                        {expandedSale === sale.id ? <ChevronDown size={16} className="text-slate-300" /> : <ChevronRight size={16} className="text-slate-300" />}
                        <span className="font-mono text-xs font-bold text-slate-400 uppercase">#{sale.id.slice(-6)}</span>
                      </div>
                    </td>
                    <td className="py-5">
                      <p className="text-sm font-black text-slate-700">{new Date(sale.date).toLocaleDateString()}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{new Date(sale.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                    </td>
                    <td className="py-5">
                      <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-wider ${
                        sale.paymentMethod === 'cash' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'
                      }`}>
                        {sale.paymentMethod === 'cash' ? <Banknote size={14} /> : <CreditCard size={14} />}
                        {sale.paymentMethod === 'cash' ? 'Efectivo' : 'Transferencia'}
                      </div>
                    </td>
                    <td className="py-5 text-center font-black text-slate-500">
                      {sale.items.reduce((sum, i) => sum + i.quantity, 0)}
                    </td>
                    <td className="py-5 text-right pr-8">
                      <span className="text-lg font-black text-slate-900">${sale.total.toLocaleString()}</span>
                    </td>
                  </tr>
                  {expandedSale === sale.id && (
                    <tr className="bg-slate-50/50 animate-in slide-in-from-top-1 duration-200">
                      <td colSpan={5} className="py-4 pl-14 pr-8">
                        <div className="bg-white rounded-2xl border border-slate-100 p-6 shadow-sm">
                          <div className="flex justify-between items-center mb-4">
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Detalle de Productos</p>
                            <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                onDeleteSale(sale.id);
                              }}
                              className="flex items-center gap-2 text-red-400 hover:text-red-600 transition-colors font-black text-[10px] uppercase tracking-widest"
                            >
                              <Trash2 size={14} />
                              Eliminar Venta
                            </button>
                          </div>
                          <div className="space-y-3">
                            {sale.items.map((item, idx) => (
                              <div key={idx} className="flex justify-between items-center pb-3 border-b border-slate-50 last:border-0 last:pb-0">
                                <div>
                                  <p className="text-sm font-bold text-slate-700">{item.name}</p>
                                  <p className="text-xs text-slate-400">{item.quantity} x ${item.price.toLocaleString()}</p>
                                </div>
                                <span className="font-black text-slate-800">${(item.quantity * item.price).toLocaleString()}</span>
                              </div>
                            ))}
                          </div>
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
              {filteredSales.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-20 text-center text-slate-400 font-medium italic">No se encontraron ventas para este periodo</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal: Detailed Inventory Snapshot for Period */}
      {showInventoryDetail && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 flex flex-col max-h-[85vh]">
