                <div className="p-4 rounded-2xl bg-amber-100 text-amber-600">
                  <Box size={24} />
                </div>
                <div>
                  <h3 className="text-2xl font-black text-slate-800">Control de Inventario por Periodo</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">
                    Desde: {dateRange.start} Hasta: {dateRange.end}
                  </p>
                </div>
              </div>
              <button onClick={() => setShowInventoryDetail(false)} className="p-3 hover:bg-white rounded-2xl transition-all shadow-sm"><X size={24}/></button>
            </div>

            <div className="p-6 bg-slate-50/50 border-b flex justify-between items-center">
              <span className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Cuadre de existencias (Inicio vs Final)</span>
              <div className="flex gap-4">
                 <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-slate-200"></div>
                    <span className="text-[10px] font-black uppercase text-slate-400">Inicio</span>
                 </div>
                 <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-emerald-500"></div>
                    <span className="text-[10px] font-black uppercase text-slate-400">Final</span>
                 </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 no-scrollbar">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                    <th className="pb-4">Producto</th>
                    <th className="pb-4 text-center">Unid. Vendidas</th>
                    <th className="pb-4 text-center">Stock Inicio</th>
                    <th className="pb-4 text-center">Stock Final</th>
                    <th className="pb-4 text-right">Diferencia</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {productPeriodStats.map((p) => (
                    <tr key={p.id} className="group hover:bg-slate-50/50">
                      <td className="py-4">
                        <p className="font-bold text-slate-700">{p.name}</p>
                        <p className="text-[10px] font-mono text-slate-400 uppercase">{p.code}</p>
                      </td>
                      <td className="py-4 text-center">
                        <span className="px-3 py-1 bg-amber-50 text-amber-600 rounded-lg text-sm font-black">
                          {p.unitsSold}
                        </span>
                      </td>
                      <td className="py-4 text-center">
                        <span className="text-slate-400 font-black">{p.initialStock}</span>
                      </td>
                      <td className="py-4 text-center">
                        <span className="text-emerald-600 font-black">{p.finalStock}</span>
                      </td>
                      <td className="py-4 text-right">
                        <span className={`font-black text-sm ${p.finalStock < p.initialStock ? 'text-red-500' : 'text-emerald-500'}`}>
                          {p.finalStock - p.initialStock > 0 ? '+' : ''}{p.finalStock - p.initialStock}
                        </span>
                      </td>
                    </tr>
                  ))}
                  {productPeriodStats.length === 0 && (
                    <tr>
                      <td colSpan={5} className="py-20 text-center text-slate-400 font-medium italic">
                        No hubo actividad de productos en este periodo
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            <div className="p-8 border-t bg-slate-50 text-right">
              <button 
                onClick={() => setShowInventoryDetail(false)}
                className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all"
              >
                Cerrar Detalle
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

