import React, { useState, useMemo, useEffect } from 'react';
import { Calendar, Search, Banknote, CreditCard, ChevronRight, ChevronDown, ReceiptText, FileSpreadsheet, Trash2, X, Box, Info } from 'lucide-react';
import { Sale, Product, InventoryMovement } from '../types';

interface SalesHistoryProps {
  sales: Sale[];
  products: Product[];
  movements: InventoryMovement[];
  onDeleteSale: (id: string) => void;
}

const SalesHistory: React.FC<SalesHistoryProps> = ({ sales, products, movements, onDeleteSale }) => {
  const [expandedSale, setExpandedSale] = useState<string | null>(null);
  const [showInventoryDetail, setShowInventoryDetail] = useState(false);

  // Date synchronization with PC
  const [dateRange, setDateRange] = useState({
    start: new Date().toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    const today = new Date().toISOString().split('T')[0];
    setDateRange({ start: today, end: today });
  }, []);

  const [searchTerm, setSearchTerm] = useState('');

  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).setHours(0,0,0,0);
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);

    return sales.filter(s => {
      const matchesDate = s.date >= start && s.date <= end;
      const matchesSearch = s.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           s.items.some(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
      return matchesDate && matchesSearch;
    }).sort((a, b) => b.date - a.date);
  }, [sales, dateRange, searchTerm]);

  const stats = useMemo(() => {
    const total = filteredSales.reduce((acc, s) => acc + s.total, 0);
    const cash = filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0);
    const transfer = filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0);
    const productsCount = filteredSales.reduce((acc, s) => acc + s.items.reduce((sum, item) => sum + item.quantity, 0), 0);

    return { total, cash, transfer, productsCount };
  }, [filteredSales]);

  // Logic for Detailed Inventory Snapshot per product for the selected period
  const productPeriodStats = useMemo(() => {
    const startTs = new Date(dateRange.start).setHours(0,0,0,0);
    const endTs = new Date(dateRange.end).setHours(23,59,59,999);

    return products.map(product => {
      // All movements that happened from the start of the selected period until NOW
      const movementsSincePeriodStart = movements.filter(m => m.productId === product.id && m.date >= startTs);

      // Calculate Stock at Start of Period (Initial Stock)
      // Working backwards: InitialStock = CurrentStock + TotalOuts(since then) - TotalIns(since then)
      const outsSinceStart = movementsSincePeriodStart.filter(m => m.type === 'out').reduce((sum, m) => sum + m.quantity, 0);
      const insSinceStart = movementsSincePeriodStart.filter(m => m.type === 'in').reduce((sum, m) => sum + m.quantity, 0);
      const initialStock = product.stock + outsSinceStart - insSinceStart;

      // Calculate Stock at End of Period (Final Stock)
      // FinalStock = InitialStock + InsInPeriod - OutsInPeriod
      const movementsInPeriod = movementsSincePeriodStart.filter(m => m.date <= endTs);
      const insInPeriod = movementsInPeriod.filter(m => m.type === 'in').reduce((sum, m) => sum + m.quantity, 0);
      const outsInPeriod = movementsInPeriod.filter(m => m.type === 'out').reduce((sum, m) => sum + m.quantity, 0);
      const finalStock = initialStock + insInPeriod - outsInPeriod;

      const totalSoldInPeriod = filteredSales.reduce((acc, sale) => {
          const item = sale.items.find(i => i.productId === product.id);
          return acc + (item?.quantity || 0);
      }, 0);

      return {
        id: product.id,
        name: product.name,
        code: product.code,
        unitsSold: totalSoldInPeriod,
        initialStock,
        finalStock,
        hasActivity: movementsInPeriod.length > 0
      };
    }).filter(p => p.hasActivity || p.unitsSold > 0).sort((a, b) => b.unitsSold - a.unitsSold);
  }, [dateRange, products, movements, filteredSales]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ReceiptText className="text-emerald-600" size={32} />
            Historial de Ventas
          </h2>
          <p className="text-slate-500 font-medium">Registro de transacciones y control de existencias</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-900 p-6 rounded-[2rem] shadow-xl text-white">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Total Recaudado</p>
          <h4 className="text-3xl font-black">${stats.total.toLocaleString()}</h4>
        </div>
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center"><Banknote size={24} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Efectivo</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.cash.toLocaleString()}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center"><CreditCard size={24} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Transferencia</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.transfer.toLocaleString()}</h4>
          </div>
        </div>
        <button onClick={() => setShowInventoryDetail(true)} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5 hover:bg-emerald-50 transition-all text-left">
          <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center"><FileSpreadsheet size={24} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Prod. Vendidos</p>
            <h4 className="text-2xl font-black text-slate-800">{stats.productsCount}</h4>
          </div>
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b bg-slate-50/30 flex justify-between items-center">
          <h3 className="text-lg font-black text-slate-700">Listado de Transacciones</h3>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder="Buscar..." 
              className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                <th className="py-4 pl-8">ID</th>
                <th className="py-4">Fecha</th>
                <th className="py-4">Método</th>
                <th className="py-4 text-right pr-8">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredSales.map(sale => (
                <React.Fragment key={sale.id}>
                  <tr onClick={() => setExpandedSale(expandedSale === sale.id ? null : sale.id)} className="hover:bg-slate-50 cursor-pointer transition-colors">
                    <td className="py-5 pl-8 font-mono text-xs text-slate-400">#{sale.id.slice(-6)}</td>
                    <td className="py-5 text-sm font-bold text-slate-700">{new Date(sale.date).toLocaleString()}</td>
                    <td className="py-5">
                      <span className={`px-3 py-1 rounded-xl text-[10px] font-black uppercase ${sale.paymentMethod === 'cash' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                        {sale.paymentMethod === 'cash' ? 'Efectivo' : 'Transferencia'}
                      </span>
                    </td>
                    <td className="py-5 text-right pr-8 font-black text-slate-900">${sale.total.toLocaleString()}</td>
                  </tr>
                  {expandedSale === sale.id && (
                    <tr className="bg-slate-50/50">
                      <td colSpan={4} className="p-4 pl-12 pr-8">
                        <div className="bg-white p-4 rounded-2xl border border-slate-100">
                          <div className="flex justify-between items-center mb-4">
                             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Items</p>
                             <button onClick={() => onDeleteSale(sale.id)} className="text-red-400 hover:text-red-600 text-[10px] font-black uppercase flex items-center gap-1"><Trash2 size={12}/> Eliminar</button>
                          </div>
                          {sale.items.map((item, idx) => (
                            <div key={idx} className="flex justify-between py-2 border-b border-slate-50 last:border-0">
                              <span className="text-sm font-bold text-slate-700">{item.name} x {item.quantity}</span>
                              <span className="font-black">${(item.price * item.quantity).toLocaleString()}</span>
                            </div>
                          ))}
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showInventoryDetail && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 flex flex-col max-h-[85vh]">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <div className="flex items-center gap-4">
                <div className="p-4 rounded-2xl bg-amber-100 text-amber-600"><Box size={24} /></div>
                <div>
                  <h3 className="text-2xl font-black text-slate-800">Cierre de Inventario</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Periodo: {dateRange.start} al {dateRange.end}</p>
                </div>
              </div>
              <button onClick={() => setShowInventoryDetail(false)} className="p-3 hover:bg-white rounded-2xl transition-all"><X size={24}/></button>
            </div>
            <div className="flex-1 overflow-y-auto p-4 md:p-8">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                    <th className="pb-4">Producto</th>
                    <th className="pb-4 text-center">Vendidos</th>
                    <th className="pb-4 text-center">Stock Inicial</th>
                    <th className="pb-4 text-center">Stock Final</th>
                    <th className="pb-4 text-right">Variación</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {productPeriodStats.map(p => (
                    <tr key={p.id} className="group hover:bg-slate-50/50">
                      <td className="py-4"><p className="font-bold text-slate-700">{p.name}</p><p className="text-[10px] font-mono text-slate-400 uppercase">{p.code}</p></td>
