  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // Auto-Save State
  const [autoSaveConfig, setAutoSaveConfig] = useState<AutoSaveConfig>({
    enabled: false,
    lastSaved: null
  });
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [nextSaveIn, setNextSaveIn] = useState(60);

  // Load Data from LocalStorage
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');
    const savedAutoSave = localStorage.getItem('gourmet_autosave_config');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
    if (savedAutoSave) setAutoSaveConfig(JSON.parse(savedAutoSave));
  }, []);

  // Sync LocalStorage
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
    localStorage.setItem('gourmet_autosave_config', JSON.stringify(autoSaveConfig));
  }, [products, categories, sales, movements, financialSettings, autoSaveConfig]);

  // Auto-Save Loop (Every 1 minute)
  useEffect(() => {
    if (!autoSaveConfig.enabled || !directoryHandle) {
      setNextSaveIn(60);
      return;
    }

    const timer = setInterval(() => {
      setNextSaveIn(prev => {
        if (prev <= 1) {
          triggerAutoSave();
          return 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [autoSaveConfig.enabled, directoryHandle, products, categories, sales, movements, financialSettings]);

  const triggerAutoSave = async () => {
    if (!directoryHandle) return;
    setIsSaving(true);
    try {
      const data = {
        products,
        categories,
        sales,
        movements,
        financialSettings,
        exportDate: new Date().toISOString()
      };

      const fileHandle = await directoryHandle.getFileHandle('gourmet_pos_autosave.json', { create: true });
      const writable = await fileHandle.createWritable();
      await writable.write(JSON.stringify(data, null, 2));
      await writable.close();

      setAutoSaveConfig(prev => ({ ...prev, lastSaved: Date.now() }));
    } catch (err) {
      console.error("Error during auto-save:", err);
    } finally {
      setTimeout(() => setIsSaving(false), 2000); // Visual indicator buffer
    }
  };

  const handleImport = (data: any) => {
    if (data.products) setProducts(data.products);
    if (data.categories) setCategories(data.categories);
    if (data.sales) setSales(data.sales);
    if (data.movements) setMovements(data.movements);
    if (data.financialSettings) setFinancialSettings(data.financialSettings);
    alert("Datos restaurados correctamente.");
  };

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      quantity,
      type,
      reason,
      date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);

    setProducts(prev => prev.map(p => {
      if (p.id === productId) {
        return { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity };
      }
      return p;
    }));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => {
      addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`);
    });
  }, [addMovement]);

  const deleteSale = useCallback((saleId: string) => {
    const saleToDelete = sales.find(s => s.id === saleId);
    if (!saleToDelete) return;

    if (window.confirm("¿Está seguro de eliminar esta venta? El stock será devuelto al inventario.")) {
      saleToDelete.items.forEach(item => {
        addMovement(item.productId, item.quantity, 'in', `Anulación venta #${saleId.slice(-4)}`);
      });
      setSales(prev => prev.filter(s => s.id !== saleId));
    }
  }, [sales, addMovement]);

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'sales-history', icon: ReceiptText, label: 'Historial' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
    { id: 'insights', icon: TrendingUp, label: 'Inteligencia' },
    { id: 'settings', icon: SettingsIcon, label: 'Configuración' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">GourmetPOS</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 h-full flex flex-col">
          <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-8 tracking-tighter">GourmetPOS</h1>
          <nav className="space-y-2 flex-1">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as any);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-6 border-t bg-slate-50/50 -mx-6 px-6">
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mb-3">Backup de Datos</p>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${autoSaveConfig.enabled ? (isSaving ? 'bg-amber-500 animate-ping' : 'bg-emerald-500') : 'bg-slate-300'}`}></div>
                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">
                  {isSaving ? 'Guardando...' : (autoSaveConfig.enabled ? 'Auto-Save Activo' : 'Auto-Save Inactivo')}
                </span>
              </div>
              {autoSaveConfig.enabled && !isSaving && (
                <span className="text-[10px] font-black text-slate-400">{nextSaveIn}s</span>
              )}
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && <POS products={products} categories={categories} onCompleteSale={completeSale} />}
          {activeTab === 'sales-history' && <SalesHistory sales={sales} products={products} movements={movements} onDeleteSale={deleteSale} />}
          {activeTab === 'products' && <Products products={products} categories={categories} setProducts={setProducts} setCategories={setCategories} addMovement={addMovement} />}
          {activeTab === 'inventory' && <Inventory movements={movements} products={products} addMovement={addMovement} />}
          {activeTab === 'stats' && <Statistics sales={sales} products={products} categories={categories} settings={financialSettings} setSettings={setFinancialSettings} />}
          {activeTab === 'insights' && <Insights sales={sales} products={products} categories={categories} />}
          {activeTab === 'settings' && (
            <Settings 
              products={products}
              categories={categories}
              sales={sales}
              movements={movements}
              financialSettings={financialSettings}
              onImport={handleImport}
              autoSaveConfig={autoSaveConfig}
              setAutoSaveConfig={setAutoSaveConfig}
              directoryHandle={directoryHandle}
              setDirectoryHandle={setDirectoryHandle}
              isSaving={isSaving}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { Download, Upload, Save, FolderOpen, ShieldCheck, Database, HardDrive, RefreshCw, AlertCircle } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings, AutoSaveConfig } from '../types';

interface SettingsProps {
  products: Product[];
  categories: Category[];
  sales: Sale[];
  movements: InventoryMovement[];
  financialSettings: FinancialSettings;
  autoSaveConfig: AutoSaveConfig;
  setAutoSaveConfig: React.Dispatch<React.SetStateAction<AutoSaveConfig>>;
  directoryHandle: FileSystemDirectoryHandle | null;
  setDirectoryHandle: (handle: FileSystemDirectoryHandle | null) => void;
  onImport: (data: any) => void;
  isSaving: boolean;
}

const Settings: React.FC<SettingsProps> = ({ 
  products, categories, sales, movements, financialSettings, 
  onImport, autoSaveConfig, setAutoSaveConfig, 
  directoryHandle, setDirectoryHandle, isSaving 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const exportData = () => {
    const data = {
      products,
      categories,
      sales,
      movements,
      financialSettings,
      exportDate: new Date().toISOString(),
      version: "1.0"
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `gourmet_pos_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (window.confirm("¿Está seguro de restaurar estos datos? Se sobreescribirá la información actual.")) {
          onImport(json);
        }
      } catch (err) {
        alert("Archivo no válido.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const selectDirectory = async () => {
    try {
      // Use showDirectoryPicker API
      const handle = await (window as any).showDirectoryPicker();
      setDirectoryHandle(handle);
      setAutoSaveConfig(prev => ({ ...prev, enabled: true }));
    } catch (err) {
      console.error("Directory selection cancelled or failed:", err);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
          <Database className="text-emerald-600" />
          Configuración y Datos
        </h2>
        <p className="text-slate-500 font-medium">Gestione la seguridad y el respaldo de su información local</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Manual Backup Card */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 flex flex-col">
          <div className="flex items-center gap-4 mb-8">
            <div className="p-4 bg-emerald-50 text-emerald-600 rounded-3xl">
              <ShieldCheck size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800">Respaldo Manual</h3>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Exportar e Importar Archivos</p>
            </div>
          </div>

          <p className="text-sm text-slate-600 leading-relaxed mb-8">
            Descargue una copia completa de su base de datos en formato JSON para guardarla en una unidad externa o restaurarla en otro equipo.
          </p>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mt-auto">
            <button 
              onClick={exportData}
              className="flex items-center justify-center gap-3 bg-slate-900 text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
            >
              <Download size={18} />
              Exportar Todo
            </button>

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center justify-center gap-3 bg-white text-slate-800 border-2 border-slate-100 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all"
            >
              <Upload size={18} />
              Importar Datos
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".json" 
              onChange={handleFileImport} 
            />
          </div>
        </div>

        {/* Auto-Save Configuration Card */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 flex flex-col relative overflow-hidden">
          {isSaving && (
            <div className="absolute top-0 left-0 right-0 h-1 bg-emerald-500 animate-pulse"></div>
          )}

          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-4">
              <div className="p-4 bg-blue-50 text-blue-600 rounded-3xl">
                <HardDrive size={28} />
              </div>
              <div>
                <h3 className="text-xl font-black text-slate-800">Auto-Guardado Local</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Sincronización cada 1 minuto</p>
              </div>
            </div>

            <label className="relative inline-flex items-center cursor-pointer">
              <input 
                type="checkbox" 
                className="sr-only peer" 
                checked={autoSaveConfig.enabled && !!directoryHandle}
                onChange={() => {
                  if (!directoryHandle) {
                    selectDirectory();
                  } else {
                    setAutoSaveConfig(prev => ({ ...prev, enabled: !prev.enabled }));
                  }
                }}
              />
              <div className="w-14 h-8 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[4px] after:left-[4px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-emerald-500"></div>
            </label>
          </div>

          <p className="text-sm text-slate-600 leading-relaxed mb-6">
            Al seleccionar una carpeta en su ordenador, el sistema guardará automáticamente una copia de seguridad cada 60 segundos, sobreescribiendo el archivo <span className="font-mono text-emerald-600 font-bold text-xs bg-emerald-50 px-1 rounded">gourmet_pos_autosave.json</span>.
          </p>

          <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 mb-8">
            <div className="flex items-center justify-between mb-4">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado de Sincronización</span>
              <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider ${autoSaveConfig.enabled && directoryHandle ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                {autoSaveConfig.enabled && directoryHandle ? 'Sincronizado' : 'Desconectado'}
              </span>
            </div>

            <div className="flex items-center gap-3 mb-6">
              <div className={`p-2 rounded-xl ${directoryHandle ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-400'}`}>
                <FolderOpen size={18} />
              </div>
              <p className="text-xs font-bold text-slate-700 truncate max-w-[250px]">
                {directoryHandle ? `Ruta seleccionada: ${directoryHandle.name}` : 'No se ha seleccionado una carpeta'}
              </p>
            </div>

            <button 
              onClick={selectDirectory}
              className="w-full flex items-center justify-center gap-2 bg-white text-blue-600 border border-blue-100 py-3 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-blue-50 transition-all"
            >
              {directoryHandle ? 'Cambiar Carpeta' : 'Seleccionar Carpeta de Backup'}
            </button>
          </div>

          {autoSaveConfig.lastSaved && (
            <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
              <RefreshCw size={12} className={isSaving ? 'animate-spin' : ''} />
              Último autoguardado: {new Date(autoSaveConfig.lastSaved).toLocaleTimeString()}
            </div>
          )}
        </div>

        {/* Info Card */}
        <div className="lg:col-span-2 bg-amber-50 p-8 rounded-[3rem] border border-amber-100 flex items-start gap-6">
           <div className="p-4 bg-white text-amber-500 rounded-3xl shadow-sm shrink-0">
              <AlertCircle size={32} />
           </div>
           <div>
              <h4 className="text-xl font-black text-amber-900 mb-2">Seguridad de la Información</h4>
              <p className="text-sm text-amber-800/80 leading-relaxed">
                Este sistema utiliza <strong>LocalStorage</strong> como base de datos principal, lo que significa que sus datos se almacenan de forma segura y privada únicamente en su navegador. Sin embargo, borrar el caché o formatear su equipo puede causar la pérdida de datos. Le recomendamos encarecidamente activar el <strong>Auto-Guardado</strong> en una carpeta de su elección o realizar respaldos manuales diarios.
              </p>
           </div>
        </div>
      </div>
    </div>
  );
};

export default Settings;

