import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, BarChart3, Menu, X, Tag, TrendingUp, ReceiptText, Settings as SettingsIcon, LogOut, UserCircle } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings, AutoSaveConfig, Role, User, Permission } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';
import Insights from './components/Insights';
import SalesHistory from './components/SalesHistory';
import Settings from './components/Settings';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Permission>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // User & Roles State
  const [roles, setRoles] = useState<Role[]>([
    { id: 'admin', name: 'Administrador', permissions: ['pos', 'inventory', 'products', 'stats', 'insights', 'sales-history', 'settings'] },
    { id: 'seller', name: 'Vendedor', permissions: ['pos', 'sales-history'] }
  ]);
  const [users, setUsers] = useState<User[]>([
    { id: '1', username: 'admin', roleId: 'admin' }
  ]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Auto-Save State
  const [autoSaveConfig, setAutoSaveConfig] = useState<AutoSaveConfig>({
    enabled: false,
    lastSaved: null
  });
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [nextSaveIn, setNextSaveIn] = useState(60);

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');
    const savedAutoSave = localStorage.getItem('gourmet_autosave_config');
    const savedRoles = localStorage.getItem('gourmet_roles');
    const savedUsers = localStorage.getItem('gourmet_users');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
    if (savedAutoSave) setAutoSaveConfig(JSON.parse(savedAutoSave));
    if (savedRoles) setRoles(JSON.parse(savedRoles));
    if (savedUsers) setUsers(JSON.parse(savedUsers));
  }, []);

  // Sync LocalStorage
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
    localStorage.setItem('gourmet_autosave_config', JSON.stringify(autoSaveConfig));
    localStorage.setItem('gourmet_roles', JSON.stringify(roles));
    localStorage.setItem('gourmet_users', JSON.stringify(users));
  }, [products, categories, sales, movements, financialSettings, autoSaveConfig, roles, users]);

  // Auto-Save Loop
  useEffect(() => {
    if (!autoSaveConfig.enabled || !directoryHandle) {
      setNextSaveIn(60);
      return;
    }
    const timer = setInterval(() => {
      setNextSaveIn(prev => {
        if (prev <= 1) {
          triggerAutoSave();
          return 60;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [autoSaveConfig.enabled, directoryHandle, products, categories, sales, movements, financialSettings]);

  const triggerAutoSave = async () => {
    if (!directoryHandle) return;
    setIsSaving(true);
    try {
      const data = { products, categories, sales, movements, financialSettings, exportDate: new Date().toISOString() };
      const fileHandle = await directoryHandle.getFileHandle('gourmet_pos_autosave.json', { create: true });
      const writable = await fileHandle.createWritable();
      await writable.write(JSON.stringify(data, null, 2));
      await writable.close();
      setAutoSaveConfig(prev => ({ ...prev, lastSaved: Date.now() }));
    } catch (err) {
      console.error("Error during auto-save:", err);
    } finally {
      setTimeout(() => setIsSaving(false), 2000);
    }
  };

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId, quantity, type, reason, date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);
    setProducts(prev => prev.map(p => p.id === productId ? { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity } : p));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`));
  }, [addMovement]);

  const deleteSale = useCallback((saleId: string) => {
    const saleToDelete = sales.find(s => s.id === saleId);
    if (!saleToDelete) return;
    if (window.confirm("¿Está seguro de eliminar esta venta? El stock será devuelto al inventario.")) {
      saleToDelete.items.forEach(item => addMovement(item.productId, item.quantity, 'in', `Anulación venta #${saleId.slice(-4)}`));
      setSales(prev => prev.filter(s => s.id !== saleId));
    }
  }, [sales, addMovement]);

  const handleImport = (data: any) => {
    if (data.products) setProducts(data.products);
    if (data.categories) setCategories(data.categories);
    if (data.sales) setSales(data.sales);
    if (data.movements) setMovements(data.movements);
    if (data.financialSettings) setFinancialSettings(data.financialSettings);
    alert("Datos restaurados correctamente.");
  };

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'sales-history', icon: ReceiptText, label: 'Historial' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
    { id: 'insights', icon: TrendingUp, label: 'Inteligencia' },
    { id: 'settings', icon: SettingsIcon, label: 'Configuración' },
  ];

  const currentRole = roles.find(r => r.id === currentUser?.roleId);
  const filteredNavItems = navItems.filter(item => currentRole?.permissions.includes(item.id as Permission));

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-500">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-black text-emerald-600 tracking-tighter mb-2">GourmetPOS</h1>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Acceso al Sistema</p>
          </div>
          <div className="space-y-4">
            <p className="text-sm font-bold text-slate-500 mb-2">Seleccione Usuario</p>
            {users.map(u => (
              <button
                key={u.id}
                onClick={() => {
                  setCurrentUser(u);
                  const firstPerm = roles.find(r => r.id === u.roleId)?.permissions[0];
                  if (firstPerm) setActiveTab(firstPerm);
                }}
                className="w-full flex items-center justify-between p-5 bg-slate-50 hover:bg-emerald-50 rounded-2xl border-2 border-transparent hover:border-emerald-200 transition-all group"
              >
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-slate-400 group-hover:text-emerald-500 shadow-sm transition-colors">
                    <UserCircle size={24} />
                  </div>
                  <div className="text-left">
                    <p className="font-black text-slate-800 uppercase tracking-tight">{u.username}</p>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{roles.find(r => r.id === u.roleId)?.name}</p>
                  </div>
                </div>
                <div className="w-8 h-8 rounded-full bg-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                  <Menu size={16} className="text-emerald-500" />
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">GourmetPOS</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 h-full flex flex-col">
          <div className="mb-8">
            <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-1 tracking-tighter">GourmetPOS</h1>
            <div className="flex items-center gap-2 px-1">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{currentRole?.name}</span>
            </div>
          </div>

          <nav className="space-y-2 flex-1">
            {filteredNavItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as Permission);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-4 space-y-4">
            <div className="pt-4 border-t bg-slate-50/50 -mx-6 px-6">
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mb-3">Sesión</p>
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center text-slate-400 border border-slate-100">
                    <UserCircle size={18} />
                  </div>
                  <span className="text-xs font-black text-slate-700 uppercase">{currentUser.username}</span>
                </div>
                <button onClick={() => setCurrentUser(null)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                  <LogOut size={18} />
                </button>
              </div>
            </div>

            <div className="pb-6 px-6 -mx-6">
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mb-3">Sincronización</p>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full ${autoSaveConfig.enabled ? (isSaving ? 'bg-amber-500 animate-ping' : 'bg-emerald-500') : 'bg-slate-300'}`}></div>
                  <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">
                    {isSaving ? 'Guardando...' : (autoSaveConfig.enabled ? 'Activo' : 'Inactivo')}
                  </span>
                </div>
                {autoSaveConfig.enabled && !isSaving && <span className="text-[10px] font-black text-slate-400">{nextSaveIn}s</span>}
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && <POS products={products} categories={categories} onCompleteSale={completeSale} />}
          {activeTab === 'sales-history' && <SalesHistory sales={sales} products={products} movements={movements} onDeleteSale={deleteSale} />}
          {activeTab === 'products' && <Products products={products} categories={categories} setProducts={setProducts} setCategories={setCategories} addMovement={addMovement} />}
          {activeTab === 'inventory' && <Inventory movements={movements} products={products} addMovement={addMovement} />}
          {activeTab === 'stats' && <Statistics sales={sales} products={products} categories={categories} settings={financialSettings} setSettings={setFinancialSettings} />}
          {activeTab === 'insights' && <Insights sales={sales} products={products} categories={categories} />}
          {activeTab === 'settings' && (
            <Settings 
              products={products} categories={categories} sales={sales} movements={movements} financialSettings={financialSettings} 
              onImport={handleImport} autoSaveConfig={autoSaveConfig} setAutoSaveConfig={setAutoSaveConfig}
              directoryHandle={directoryHandle} setDirectoryHandle={setDirectoryHandle} isSaving={isSaving}
              roles={roles} setRoles={setRoles} users={users} setUsers={setUsers}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { Download, Upload, FolderOpen, ShieldCheck, Database, HardDrive, RefreshCw, AlertCircle, Users, Shield, Plus, Trash2, CheckSquare, Square, UserPlus } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings, AutoSaveConfig, Role, User, Permission } from '../types';

interface SettingsProps {
  products: Product[];
  categories: Category[];
  sales: Sale[];
  movements: InventoryMovement[];
  financialSettings: FinancialSettings;
  autoSaveConfig: AutoSaveConfig;
  setAutoSaveConfig: React.Dispatch<React.SetStateAction<AutoSaveConfig>>;
  directoryHandle: FileSystemDirectoryHandle | null;
  setDirectoryHandle: (handle: FileSystemDirectoryHandle | null) => void;
  onImport: (data: any) => void;
  isSaving: boolean;
  roles: Role[];
  setRoles: React.Dispatch<React.SetStateAction<Role[]>>;
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
}

const Settings: React.FC<SettingsProps> = ({ 
  products, categories, sales, movements, financialSettings, 
  onImport, autoSaveConfig, setAutoSaveConfig, 
  directoryHandle, setDirectoryHandle, isSaving,
  roles, setRoles, users, setUsers
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeSubTab, setActiveSubTab] = useState<'backup' | 'users'>('backup');

  // Role Creation State
  const [newRoleName, setNewRoleName] = useState('');
  const [selectedPerms, setSelectedPerms] = useState<Permission[]>(['pos']);

  // User Creation State
  const [newUsername, setNewUsername] = useState('');
  const [selectedRoleId, setSelectedRoleId] = useState(roles[0]?.id || '');

  const availablePermissions: { id: Permission, label: string }[] = [
    { id: 'pos', label: 'Punto de Venta' },
    { id: 'sales-history', label: 'Historial' },
    { id: 'products', label: 'Productos' },
    { id: 'inventory', label: 'Inventario' },
    { id: 'stats', label: 'Estadísticas' },
    { id: 'insights', label: 'Inteligencia' },
    { id: 'settings', label: 'Configuración' },
  ];

  const exportData = () => {
    const data = { products, categories, sales, movements, financialSettings, exportDate: new Date().toISOString(), version: "1.0" };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `gourmet_pos_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (window.confirm("¿Está seguro de restaurar estos datos? Se sobreescribirá la información actual.")) {
          onImport(json);
        }
      } catch (err) {
        alert("Archivo no válido.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const selectDirectory = async () => {
    try {
      const handle = await (window as any).showDirectoryPicker();
      setDirectoryHandle(handle);
      setAutoSaveConfig(prev => ({ ...prev, enabled: true }));
    } catch (err) {
      console.error("Directory selection cancelled or failed:", err);
    }
  };

  const createRole = () => {
    if (!newRoleName.trim()) return;
    const newRole: Role = {
      id: Math.random().toString(36).substr(2, 9),
      name: newRoleName,
      permissions: selectedPerms
    };
    setRoles([...roles, newRole]);
    setNewRoleName('');
    setSelectedPerms(['pos']);
  };

  const createUser = () => {
    if (!newUsername.trim() || !selectedRoleId) return;
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      username: newUsername,
      roleId: selectedRoleId
    };
    setUsers([...users, newUser]);
    setNewUsername('');
  };

  const togglePermission = (perm: Permission) => {
    if (selectedPerms.includes(perm)) {
      setSelectedPerms(selectedPerms.filter(p => p !== perm));
    } else {
      setSelectedPerms([...selectedPerms, perm]);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <Database className="text-emerald-600" />
            Configuración y Datos
          </h2>
          <p className="text-slate-500 font-medium">Gestione la seguridad y el acceso de su equipo</p>
        </div>

        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100">
          <button 
            onClick={() => setActiveSubTab('backup')}
            className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'backup' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Datos & Backup
          </button>
          <button 
            onClick={() => setActiveSubTab('users')}
            className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'users' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Usuarios & Roles
          </button>
        </div>
      </header>

      {activeSubTab === 'backup' ? (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Manual Backup Card */}
          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 flex flex-col">
            <div className="flex items-center gap-4 mb-8">
              <div className="p-4 bg-emerald-50 text-emerald-600 rounded-3xl">
                <ShieldCheck size={28} />
              </div>
              <div>
                <h3 className="text-xl font-black text-slate-800">Respaldo Manual</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Exportar e Importar Archivos</p>
              </div>
            </div>
            <p className="text-sm text-slate-600 leading-relaxed mb-8">Descargue una copia completa de su base de datos en formato JSON para guardarla en una unidad externa o restaurarla.</p>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mt-auto">
              <button onClick={exportData} className="flex items-center justify-center gap-3 bg-slate-900 text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"><Download size={18} /> Exportar Todo</button>
              <button onClick={() => fileInputRef.current?.click()} className="flex items-center justify-center gap-3 bg-white text-slate-800 border-2 border-slate-100 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all"><Upload size={18} /> Importar Datos</button>
              <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleFileImport} />
            </div>
          </div>

          {/* Auto-Save Card */}
          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 flex flex-col relative overflow-hidden">
            {isSaving && <div className="absolute top-0 left-0 right-0 h-1 bg-emerald-500 animate-pulse"></div>}
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-4">
                <div className="p-4 bg-blue-50 text-blue-600 rounded-3xl"><HardDrive size={28} /></div>
                <div>
                  <h3 className="text-xl font-black text-slate-800">Auto-Guardado Local</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Sincronización cada 1 minuto</p>
                </div>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input type="checkbox" className="sr-only peer" checked={autoSaveConfig.enabled && !!directoryHandle} onChange={() => !directoryHandle ? selectDirectory() : setAutoSaveConfig(prev => ({ ...prev, enabled: !prev.enabled }))} />
                <div className="w-14 h-8 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[4px] after:left-[4px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-emerald-500"></div>
              </label>
            </div>
            <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 mb-8">
              <div className="flex items-center gap-3 mb-4">
                <FolderOpen size={18} className="text-slate-400" />
                <p className="text-xs font-bold text-slate-700 truncate">{directoryHandle ? `Directorio: ${directoryHandle.name}` : 'No se ha seleccionado carpeta'}</p>
              </div>
              <button onClick={selectDirectory} className="w-full flex items-center justify-center gap-2 bg-white text-blue-600 border border-blue-100 py-3 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-blue-50 transition-all">
                {directoryHandle ? 'Cambiar Carpeta' : 'Seleccionar Carpeta'}
              </button>
            </div>
            {autoSaveConfig.lastSaved && (
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest mt-auto">
                <RefreshCw size={12} className={isSaving ? 'animate-spin' : ''} />
                Último autoguardado: {new Date(autoSaveConfig.lastSaved).toLocaleTimeString()}
              </div>
            )}
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Roles Management */}
          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
            <div className="flex items-center gap-4 mb-8">
              <div className="p-4 bg-amber-50 text-amber-600 rounded-3xl"><Shield size={28} /></div>
              <div>
                <h3 className="text-xl font-black text-slate-800">Gestión de Roles</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Personalizar Permisos</p>
              </div>
            </div>

            <div className="space-y-6">
              <div className="p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Crear Nuevo Rol</p>
                <div className="space-y-4">
                  <input 
                    type="text" placeholder="Nombre del rol (ej: Supervisor)" 
                    className="w-full px-5 py-3 bg-white border-none rounded-xl focus:ring-4 focus:ring-emerald-100 font-bold text-sm"
                    value={newRoleName} onChange={e => setNewRoleName(e.target.value)}
                  />
                  <div className="grid grid-cols-2 gap-2">
                    {availablePermissions.map(p => (
                      <button 
                        key={p.id} onClick={() => togglePermission(p.id)}
                        className={`flex items-center gap-2 p-3 rounded-xl border text-[10px] font-black uppercase tracking-wider transition-all ${selectedPerms.includes(p.id) ? 'bg-emerald-600 border-emerald-600 text-white shadow-md' : 'bg-white border-slate-100 text-slate-400'}`}
                      >
                        {selectedPerms.includes(p.id) ? <CheckSquare size={14}/> : <Square size={14}/>}
                        {p.label}
                      </button>
                    ))}
                  </div>
                  <button onClick={createRole} className="w-full flex items-center justify-center gap-2 bg-emerald-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-100 mt-2">
                    <Plus size={18} /> Guardar Rol
                  </button>
                </div>
              </div>

              <div className="space-y-3">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Roles Existentes</p>
                {roles.map(r => (
                  <div key={r.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl group">
                    <div>
                      <p className="font-black text-slate-800 text-sm uppercase">{r.name}</p>
                      <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{r.permissions.length} permisos activos</p>
                    </div>
                    {r.id !== 'admin' && (
                      <button onClick={() => setRoles(roles.filter(role => role.id !== r.id))} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                        <Trash2 size={16} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Users Management */}
          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
            <div className="flex items-center gap-4 mb-8">
              <div className="p-4 bg-blue-50 text-blue-600 rounded-3xl"><Users size={28} /></div>
              <div>
                <h3 className="text-xl font-black text-slate-800">Cuentas de Usuario</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Gestión de Personal</p>
              </div>
            </div>

            <div className="space-y-6">
              <div className="p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Vincular Nuevo Usuario</p>
                <div className="space-y-4">
                  <input 
                    type="text" placeholder="Nombre de usuario" 
                    className="w-full px-5 py-3 bg-white border-none rounded-xl focus:ring-4 focus:ring-emerald-100 font-bold text-sm"
                    value={newUsername} onChange={e => setNewUsername(e.target.value)}
                  />
                  <select 
                    className="w-full px-5 py-3 bg-white border-none rounded-xl focus:ring-4 focus:ring-emerald-100 font-bold text-sm outline-none"
                    value={selectedRoleId} onChange={e => setSelectedRoleId(e.target.value)}
                  >
                    {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                  </select>
                  <button onClick={createUser} className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-700 transition-all shadow-xl shadow-blue-100">
                    <UserPlus size={18} /> Crear Usuario
                  </button>
                </div>
              </div>

              <div className="space-y-3">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Usuarios en Sistema</p>
                {users.map(u => (
                  <div key={u.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl group">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 border border-slate-100">
                        <Users size={18} />
                      </div>
                      <div>
                        <p className="font-black text-slate-800 text-sm uppercase">{u.username}</p>
                        <p className="text-[9px] text-emerald-600 font-bold uppercase tracking-widest">{roles.find(r => r.id === u.roleId)?.name}</p>
                      </div>
                    </div>
                    {u.id !== '1' && (
                      <button onClick={() => setUsers(users.filter(user => user.id !== u.id))} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                        <Trash2 size={16} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Settings;

export interface Category {
  id: string;
  name: string;
}

export interface Product {
  id: string;
  name: string;
  categoryId: string;
  code: string;
  image: string; // Base64
  costPrice: number;
  salePrice: number;
  stock: number;
}

export interface InventoryMovement {
  id: string;
  productId: string;
  quantity: number;
  type: 'in' | 'out';
  reason: string;
  date: number;
}

export interface SaleItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
}

export interface Sale {
  id: string;
  items: SaleItem[];
  total: number;
  paymentMethod: 'cash' | 'transfer';
  date: number;
}

export interface FinancialSettings {
  businessName: string;
  initialInvestment: number;
  workerSalaryRate: number; // e.g., 1.5
}

export interface AutoSaveConfig {
  enabled: boolean;
  lastSaved: number | null;
}

export type Permission = 'pos' | 'inventory' | 'products' | 'stats' | 'insights' | 'sales-history' | 'settings';

export interface Role {
  id: string;
  name: string;
  permissions: Permission[];
}

export interface User {
  id: string;
  username: string;
  roleId: string;
}

import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingCart, Package, BarChart3, Menu, X, Tag, TrendingUp, ReceiptText, Settings as SettingsIcon, LogOut, UserCircle } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings, AutoSaveConfig, Role, User, Permission } from './types';
import POS from './components/POS';
import Products from './components/Products';
import Inventory from './components/Inventory';
import Statistics from './components/Statistics';
import Insights from './components/Insights';
import SalesHistory from './components/SalesHistory';
import Settings from './components/Settings';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Permission>('pos');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persistence State
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [movements, setMovements] = useState<InventoryMovement[]>([]);
  const [financialSettings, setFinancialSettings] = useState<FinancialSettings>({
    businessName: 'GourmetPOS',
    initialInvestment: 1000,
    workerSalaryRate: 1.5
  });

  // User & Roles State
  const [roles, setRoles] = useState<Role[]>([
    { id: 'admin', name: 'Administrador', permissions: ['pos', 'inventory', 'products', 'stats', 'insights', 'sales-history', 'settings'] },
    { id: 'seller', name: 'Vendedor', permissions: ['pos', 'sales-history'] }
  ]);
  const [users, setUsers] = useState<User[]>([
    { id: '1', username: 'admin', roleId: 'admin' }
  ]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Auto-Save State
  const [autoSaveConfig, setAutoSaveConfig] = useState<AutoSaveConfig>({
    enabled: false,
    lastSaved: null
  });
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [nextSaveIn, setNextSaveIn] = useState(60);

  // Load Data
  useEffect(() => {
    const savedProducts = localStorage.getItem('gourmet_products');
    const savedCategories = localStorage.getItem('gourmet_categories');
    const savedSales = localStorage.getItem('gourmet_sales');
    const savedMovements = localStorage.getItem('gourmet_movements');
    const savedSettings = localStorage.getItem('gourmet_settings');
    const savedAutoSave = localStorage.getItem('gourmet_autosave_config');
    const savedRoles = localStorage.getItem('gourmet_roles');
    const savedUsers = localStorage.getItem('gourmet_users');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedCategories) setCategories(JSON.parse(savedCategories));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedMovements) setMovements(JSON.parse(savedMovements));
    if (savedSettings) setFinancialSettings(JSON.parse(savedSettings));
    if (savedAutoSave) setAutoSaveConfig(JSON.parse(savedAutoSave));
    if (savedRoles) setRoles(JSON.parse(savedRoles));
    if (savedUsers) setUsers(JSON.parse(savedUsers));
  }, []);

  // Sync LocalStorage
  useEffect(() => {
    localStorage.setItem('gourmet_products', JSON.stringify(products));
    localStorage.setItem('gourmet_categories', JSON.stringify(categories));
    localStorage.setItem('gourmet_sales', JSON.stringify(sales));
    localStorage.setItem('gourmet_movements', JSON.stringify(movements));
    localStorage.setItem('gourmet_settings', JSON.stringify(financialSettings));
    localStorage.setItem('gourmet_autosave_config', JSON.stringify(autoSaveConfig));
    localStorage.setItem('gourmet_roles', JSON.stringify(roles));
    localStorage.setItem('gourmet_users', JSON.stringify(users));
  }, [products, categories, sales, movements, financialSettings, autoSaveConfig, roles, users]);

  // Auto-Save Loop
  useEffect(() => {
    if (!autoSaveConfig.enabled || !directoryHandle) {
      setNextSaveIn(60);
      return;
    }
    const timer = setInterval(() => {
      setNextSaveIn(prev => {
        if (prev <= 1) {
          triggerAutoSave();
          return 60;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [autoSaveConfig.enabled, directoryHandle, products, categories, sales, movements, financialSettings]);

  const triggerAutoSave = async () => {
    if (!directoryHandle) return;
    setIsSaving(true);
    try {
      const data = { products, categories, sales, movements, financialSettings, exportDate: new Date().toISOString() };
      const fileHandle = await directoryHandle.getFileHandle('gourmet_pos_autosave.json', { create: true });
      const writable = await fileHandle.createWritable();
      await writable.write(JSON.stringify(data, null, 2));
      await writable.close();
      setAutoSaveConfig(prev => ({ ...prev, lastSaved: Date.now() }));
    } catch (err) {
      console.error("Error during auto-save:", err);
    } finally {
      setTimeout(() => setIsSaving(false), 2000);
    }
  };

  const factoryReset = useCallback(() => {
    if (window.confirm("¿ESTÁ COMPLETAMENTE SEGURO? Esta acción borrará TODOS los datos de la aplicación (productos, ventas, inventario, usuarios) y no se puede deshacer.")) {
      localStorage.clear();
      window.location.reload();
    }
  }, []);

  const addMovement = useCallback((productId: string, quantity: number, type: 'in' | 'out', reason: string) => {
    const newMovement: InventoryMovement = {
      id: Math.random().toString(36).substr(2, 9),
      productId, quantity, type, reason, date: Date.now()
    };
    setMovements(prev => [newMovement, ...prev]);
    setProducts(prev => prev.map(p => p.id === productId ? { ...p, stock: type === 'in' ? p.stock + quantity : p.stock - quantity } : p));
  }, []);

  const completeSale = useCallback((sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => addMovement(item.productId, item.quantity, 'out', `Venta #${sale.id.slice(-4)}`));
  }, [addMovement]);

  const deleteSale = useCallback((saleId: string) => {
    const saleToDelete = sales.find(s => s.id === saleId);
    if (!saleToDelete) return;
    if (window.confirm("¿Está seguro de eliminar esta venta? El stock será devuelto al inventario.")) {
      saleToDelete.items.forEach(item => addMovement(item.productId, item.quantity, 'in', `Anulación venta #${saleId.slice(-4)}`));
      setSales(prev => prev.filter(s => s.id !== saleId));
    }
  }, [sales, addMovement]);

  const handleImport = (data: any) => {
    if (data.products) setProducts(data.products);
    if (data.categories) setCategories(data.categories);
    if (data.sales) setSales(data.sales);
    if (data.movements) setMovements(data.movements);
    if (data.financialSettings) setFinancialSettings(data.financialSettings);
    alert("Datos restaurados correctamente.");
  };

  const navItems = [
    { id: 'pos', icon: ShoppingCart, label: 'Punto de Venta' },
    { id: 'sales-history', icon: ReceiptText, label: 'Historial' },
    { id: 'products', icon: Tag, label: 'Productos' },
    { id: 'inventory', icon: Package, label: 'Inventario' },
    { id: 'stats', icon: BarChart3, label: 'Estadísticas' },
    { id: 'insights', icon: TrendingUp, label: 'Inteligencia' },
    { id: 'settings', icon: SettingsIcon, label: 'Configuración' },
  ];

  const currentRole = roles.find(r => r.id === currentUser?.roleId);
  const filteredNavItems = navItems.filter(item => currentRole?.permissions.includes(item.id as Permission));

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-500">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-black text-emerald-600 tracking-tighter mb-2">{financialSettings.businessName}</h1>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Acceso al Sistema</p>
          </div>
          <div className="space-y-4">
            <p className="text-sm font-bold text-slate-500 mb-2">Seleccione Usuario</p>
            {users.map(u => (
              <button
                key={u.id}
                onClick={() => {
                  setCurrentUser(u);
                  const firstPerm = roles.find(r => r.id === u.roleId)?.permissions[0];
                  if (firstPerm) setActiveTab(firstPerm);
                }}
                className="w-full flex items-center justify-between p-5 bg-slate-50 hover:bg-emerald-50 rounded-2xl border-2 border-transparent hover:border-emerald-200 transition-all group"
              >
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-slate-400 group-hover:text-emerald-500 shadow-sm transition-colors">
                    <UserCircle size={24} />
                  </div>
                  <div className="text-left">
                    <p className="font-black text-slate-800 uppercase tracking-tight">{u.username}</p>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{roles.find(r => r.id === u.roleId)?.name}</p>
                  </div>
                </div>
                <div className="w-8 h-8 rounded-full bg-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                  <Menu size={16} className="text-emerald-500" />
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-bold text-emerald-600">{financialSettings.businessName}</h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 h-full flex flex-col">
          <div className="mb-8">
            <h1 className="text-2xl font-bold text-emerald-600 hidden md:block mb-1 tracking-tighter truncate">{financialSettings.businessName}</h1>
            <div className="flex items-center gap-2 px-1">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{currentRole?.name}</span>
            </div>
          </div>

          <nav className="space-y-2 flex-1">
            {filteredNavItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id as Permission);
                  setIsSidebarOpen(false);
                }}
                className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-emerald-50 text-emerald-700 font-semibold shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                }`}
              >
                <item.icon size={20} />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-4 space-y-4">
            <div className="pt-4 border-t bg-slate-50/50 -mx-6 px-6">
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mb-3">Sesión</p>
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center text-slate-400 border border-slate-100">
                    <UserCircle size={18} />
                  </div>
                  <span className="text-xs font-black text-slate-700 uppercase">{currentUser.username}</span>
                </div>
                <button onClick={() => setCurrentUser(null)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                  <LogOut size={18} />
                </button>
              </div>
            </div>

            <div className="pb-6 px-6 -mx-6">
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mb-3">Sincronización</p>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full ${autoSaveConfig.enabled ? (isSaving ? 'bg-amber-500 animate-ping' : 'bg-emerald-500') : 'bg-slate-300'}`}></div>
                  <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">
                    {isSaving ? 'Guardando...' : (autoSaveConfig.enabled ? 'Activo' : 'Inactivo')}
                  </span>
                </div>
                {autoSaveConfig.enabled && !isSaving && <span className="text-[10px] font-black text-slate-400">{nextSaveIn}s</span>}
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative no-scrollbar">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {activeTab === 'pos' && <POS products={products} categories={categories} onCompleteSale={completeSale} />}
          {activeTab === 'sales-history' && <SalesHistory sales={sales} products={products} movements={movements} onDeleteSale={deleteSale} />}
          {activeTab === 'products' && <Products products={products} categories={categories} setProducts={setProducts} setCategories={setCategories} addMovement={addMovement} />}
          {activeTab === 'inventory' && <Inventory movements={movements} products={products} addMovement={addMovement} />}
          {activeTab === 'stats' && <Statistics sales={sales} products={products} categories={categories} settings={financialSettings} setSettings={setFinancialSettings} />}
          {activeTab === 'insights' && <Insights sales={sales} products={products} categories={categories} />}
          {activeTab === 'settings' && (
            <Settings 
              products={products} categories={categories} sales={sales} movements={movements} financialSettings={financialSettings} setFinancialSettings={setFinancialSettings}
              onImport={handleImport} onFactoryReset={factoryReset} autoSaveConfig={autoSaveConfig} setAutoSaveConfig={setAutoSaveConfig}
              directoryHandle={directoryHandle} setDirectoryHandle={setDirectoryHandle} isSaving={isSaving}
              roles={roles} setRoles={setRoles} users={users} setUsers={setUsers}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { Download, Upload, FolderOpen, ShieldCheck, Database, HardDrive, RefreshCw, AlertCircle, Users, Shield, Plus, Trash2, CheckSquare, Square, UserPlus, Home, RefreshCcw } from 'lucide-react';
import { Product, Category, Sale, InventoryMovement, FinancialSettings, AutoSaveConfig, Role, User, Permission } from '../types';

interface SettingsProps {
  products: Product[];
  categories: Category[];
  sales: Sale[];
  movements: InventoryMovement[];
  financialSettings: FinancialSettings;
  setFinancialSettings: React.Dispatch<React.SetStateAction<FinancialSettings>>;
  autoSaveConfig: AutoSaveConfig;
  setAutoSaveConfig: React.Dispatch<React.SetStateAction<AutoSaveConfig>>;
  directoryHandle: FileSystemDirectoryHandle | null;
  setDirectoryHandle: (handle: FileSystemDirectoryHandle | null) => void;
  onImport: (data: any) => void;
  onFactoryReset: () => void;
  isSaving: boolean;
  roles: Role[];
  setRoles: React.Dispatch<React.SetStateAction<Role[]>>;
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
}

const Settings: React.FC<SettingsProps> = ({ 
  products, categories, sales, movements, financialSettings, setFinancialSettings,
  onImport, onFactoryReset, autoSaveConfig, setAutoSaveConfig, 
  directoryHandle, setDirectoryHandle, isSaving,
  roles, setRoles, users, setUsers
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeSubTab, setActiveSubTab] = useState<'backup' | 'users'>('backup');

  // Role Creation State
  const [newRoleName, setNewRoleName] = useState('');
  const [selectedPerms, setSelectedPerms] = useState<Permission[]>(['pos']);

  // User Creation State
  const [newUsername, setNewUsername] = useState('');
  const [selectedRoleId, setSelectedRoleId] = useState(roles[0]?.id || '');

  const availablePermissions: { id: Permission, label: string }[] = [
    { id: 'pos', label: 'Punto de Venta' },
    { id: 'sales-history', label: 'Historial' },
    { id: 'products', label: 'Productos' },
    { id: 'inventory', label: 'Inventario' },
    { id: 'stats', label: 'Estadísticas' },
    { id: 'insights', label: 'Inteligencia' },
    { id: 'settings', label: 'Configuración' },
  ];

  const exportData = () => {
    const data = { products, categories, sales, movements, financialSettings, exportDate: new Date().toISOString(), version: "1.0" };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${financialSettings.businessName.replace(/\s+/g, '_')}_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (window.confirm("¿Está seguro de restaurar estos datos? Se sobreescribirá la información actual.")) {
          onImport(json);
        }
      } catch (err) {
        alert("Archivo no válido.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const selectDirectory = async () => {
    try {
      const handle = await (window as any).showDirectoryPicker();
      setDirectoryHandle(handle);
      setAutoSaveConfig(prev => ({ ...prev, enabled: true }));
    } catch (err) {
      console.error("Directory selection cancelled or failed:", err);
    }
  };

  const createRole = () => {
    if (!newRoleName.trim()) return;
    const newRole: Role = {
      id: Math.random().toString(36).substr(2, 9),
      name: newRoleName,
      permissions: selectedPerms
    };
    setRoles([...roles, newRole]);
    setNewRoleName('');
    setSelectedPerms(['pos']);
  };

  const createUser = () => {
    if (!newUsername.trim() || !selectedRoleId) return;
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      username: newUsername,
      roleId: selectedRoleId
    };
    setUsers([...users, newUser]);
    setNewUsername('');
  };

  const togglePermission = (perm: Permission) => {
    if (selectedPerms.includes(perm)) {
      setSelectedPerms(selectedPerms.filter(p => p !== perm));
    } else {
      setSelectedPerms([...selectedPerms, perm]);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <Database className="text-emerald-600" />
            Configuración y Datos
          </h2>
          <p className="text-slate-500 font-medium">Gestione la seguridad y el acceso de su equipo</p>
        </div>

        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100">
          <button 
            onClick={() => setActiveSubTab('backup')}
            className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'backup' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Datos & Backup
          </button>
          <button 
            onClick={() => setActiveSubTab('users')}
            className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeSubTab === 'users' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Usuarios & Roles
          </button>
        </div>
      </header>

      {activeSubTab === 'backup' ? (
        <div className="space-y-8">
          {/* General Business Info Card */}
          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
            <div className="flex items-center gap-4 mb-8">
              <div className="p-4 bg-indigo-50 text-indigo-600 rounded-3xl">
                <Home size={28} />
              </div>
              <div>
                <h3 className="text-xl font-black text-slate-800">General</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Información del Negocio</p>
              </div>
            </div>
            <div className="max-w-md">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Nombre del Negocio</label>
              <input 
                type="text" 
                className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-indigo-100 font-black text-slate-700 uppercase tracking-tight"
                value={financialSettings.businessName}
                onChange={e => setFinancialSettings(prev => ({ ...prev, businessName: e.target.value }))}
                placeholder="Ej: MI RESTAURANTE"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Manual Backup Card */}
            <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 flex flex-col">
              <div className="flex items-center gap-4 mb-8">
                <div className="p-4 bg-emerald-50 text-emerald-600 rounded-3xl">
                  <ShieldCheck size={28} />
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-800">Respaldo Manual</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Exportar e Importar Archivos</p>
                </div>
              </div>
