import React, { useState, useMemo } from 'react';
import { Calendar, Search, Banknote, CreditCard, ChevronRight, ChevronDown, ReceiptText, FileSpreadsheet, Trash2, X, Box, Info } from 'lucide-react';
import { Sale, Product, InventoryMovement } from '../types';

interface SalesHistoryProps {
  sales: Sale[];
  products: Product[];
  movements: InventoryMovement[];
  onDeleteSale: (id: string) => void;
  dateRange: { start: string; end: string };
  setDateRange: React.Dispatch<React.SetStateAction<{ start: string; end: string }>>;
}

const SalesHistory: React.FC<SalesHistoryProps> = ({ sales, products, movements, onDeleteSale, dateRange, setDateRange }) => {
  const [expandedSale, setExpandedSale] = useState<string | null>(null);
  const [showInventoryDetail, setShowInventoryDetail] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).setHours(0,0,0,0);
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);

    return sales.filter(s => {
      const matchesDate = s.date >= start && s.date <= end;
      const matchesSearch = s.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           s.items.some(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
      return matchesDate && matchesSearch;
    }).sort((a, b) => b.date - a.date);
  }, [sales, dateRange, searchTerm]);

  const stats = useMemo(() => {
    const total = filteredSales.reduce((acc, s) => acc + s.total, 0);
    const cash = filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0);
    const transfer = filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0);
    const productsCount = filteredSales.reduce((acc, s) => acc + s.items.reduce((sum, item) => sum + item.quantity, 0), 0);

    return { total, cash, transfer, productsCount };
  }, [filteredSales]);

  const productPeriodStats = useMemo(() => {
    const startTs = new Date(dateRange.start).setHours(0,0,0,0);
    const endTs = new Date(dateRange.end).setHours(23,59,59,999);

    return products.map(product => {
      const movementsSincePeriodStart = movements.filter(m => m.productId === product.id && m.date >= startTs);
      const outsSinceStart = movementsSincePeriodStart.filter(m => m.type === 'out').reduce((sum, m) => sum + m.quantity, 0);
      const insSinceStart = movementsSincePeriodStart.filter(m => m.type === 'in').reduce((sum, m) => sum + m.quantity, 0);
      const initialStock = product.stock + outsSinceStart - insSinceStart;

      const movementsInPeriod = movementsSincePeriodStart.filter(m => m.date <= endTs);
      const insInPeriod = movementsInPeriod.filter(m => m.type === 'in').reduce((sum, m) => sum + m.quantity, 0);
      const outsInPeriod = movementsInPeriod.filter(m => m.type === 'out').reduce((sum, m) => sum + m.quantity, 0);
      const finalStock = initialStock + insInPeriod - outsInPeriod;

      const totalSoldInPeriod = filteredSales.reduce((acc, sale) => {
          const item = sale.items.find(i => i.productId === product.id);
          return acc + (item?.quantity || 0);
      }, 0);

      return {
        id: product.id,
        name: product.name,
        code: product.code,
        unitsSold: totalSoldInPeriod,
        initialStock,
        finalStock,
        hasActivity: movementsInPeriod.length > 0
      };
    }).filter(p => p.hasActivity || p.unitsSold > 0).sort((a, b) => b.unitsSold - a.unitsSold);
  }, [dateRange, products, movements, filteredSales]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ReceiptText className="text-emerald-600" size={32} />
            Historial de Ventas
          </h2>
          <p className="text-slate-500 font-medium">Control de transacciones y auditoría de inventario diario</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-900 p-6 rounded-[2rem] shadow-xl text-white">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Total Recaudado</p>
          <h4 className="text-3xl font-black">${stats.total.toLocaleString()}</h4>
        </div>
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center"><Banknote size={24} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Efectivo</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.cash.toLocaleString()}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5">
          <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center"><CreditCard size={24} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Transferencia</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.transfer.toLocaleString()}</h4>
          </div>
        </div>
        <button 
          onClick={() => setShowInventoryDetail(true)}
          className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-5 hover:bg-emerald-50 transition-all text-left group"
        >
          <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center group-hover:scale-105 transition-transform"><FileSpreadsheet size={24} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Auditoría Stock</p>
            <h4 className="text-2xl font-black text-slate-800">{stats.productsCount} <span className="text-xs font-medium text-slate-400">unids.</span></h4>
          </div>
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b bg-slate-50/30 flex justify-between items-center">
          <h3 className="text-lg font-black text-slate-700">Journal de Transacciones</h3>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder="Buscar venta..." 
              className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm font-bold"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                <th className="py-4 pl-8">ID</th>
                <th className="py-4">Fecha & Hora</th>
                <th className="py-4">Pago</th>
                <th className="py-4 text-right pr-8">Monto</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredSales.map(sale => (
                <React.Fragment key={sale.id}>
                  <tr onClick={() => setExpandedSale(expandedSale === sale.id ? null : sale.id)} className="hover:bg-slate-50 cursor-pointer transition-colors">
                    <td className="py-5 pl-8 font-mono text-xs font-bold text-slate-400">#{sale.id.slice(-6)}</td>
                    <td className="py-5 text-sm font-black text-slate-700">{new Date(sale.date).toLocaleString()}</td>
                    <td className="py-5">
                      <span className={`px-3 py-1 rounded-xl text-[10px] font-black uppercase ${sale.paymentMethod === 'cash' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                        {sale.paymentMethod === 'cash' ? 'Efectivo' : 'Transferencia'}
                      </span>
                    </td>
                    <td className="py-5 text-right pr-8 font-black text-slate-900">${sale.total.toLocaleString()}</td>
                  </tr>
                  {expandedSale === sale.id && (
                    <tr className="bg-slate-50/50">
                      <td colSpan={4} className="p-4 pl-12 pr-8">
                        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
                          <div className="flex justify-between items-center mb-4">
                             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Detalle de Compra</p>
                             <button onClick={() => onDeleteSale(sale.id)} className="text-red-400 hover:text-red-600 text-[10px] font-black uppercase flex items-center gap-2 px-3 py-1 bg-red-50 rounded-lg transition-all"><Trash2 size={12}/> Anular Transacción</button>
                          </div>
                          <div className="space-y-2">
                            {sale.items.map((item, idx) => (
                              <div key={idx} className="flex justify-between py-2 border-b border-slate-50 last:border-0">
                                <span className="text-sm font-bold text-slate-700">{item.name} <span className="text-xs text-slate-400">x{item.quantity}</span></span>
                                <span className="font-black text-slate-800">${(item.price * item.quantity).toLocaleString()}</span>
                              </div>
                            ))}
                          </div>
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
              {filteredSales.length === 0 && (
                <tr>
                  <td colSpan={4} className="py-20 text-center text-slate-400 italic">No hay ventas registradas en este periodo</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showInventoryDetail && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-5xl rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 flex flex-col max-h-[85vh]">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <div className="flex items-center gap-4">
                <div className="p-4 rounded-2xl bg-amber-100 text-amber-600"><Box size={24} /></div>
                <div>
                  <h3 className="text-2xl font-black text-slate-800">Cierre de Inventario Diario</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Periodo: {dateRange.start} al {dateRange.end}</p>
                </div>
              </div>
              <button onClick={() => setShowInventoryDetail(false)} className="p-3 hover:bg-white rounded-2xl transition-all shadow-sm"><X size={24}/></button>
            </div>

            <div className="bg-emerald-50 p-4 border-b border-emerald-100">
               <p className="text-xs font-bold text-emerald-800 flex items-center gap-2">
                 <Info size={14} /> El Stock Inicial corresponde a la cantidad al comenzar el periodo.
               </p>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 no-scrollbar">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-50">
                    <th className="pb-4">Producto / SKU</th>
                    <th className="pb-4 text-center">Salidas (Ventas)</th>
                    <th className="pb-4 text-center">Stock Inicio</th>
                    <th className="pb-4 text-center">Stock Final</th>
                    <th className="pb-4 text-right">Diferencia</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {productPeriodStats.map(p => (
                    <tr key={p.id} className="group hover:bg-slate-50/50">
                      <td className="py-4">
                        <p className="font-bold text-slate-700">{p.name}</p>
                        <p className="text-[10px] font-mono text-slate-400 uppercase">{p.code}</p>
                      </td>
                      <td className="py-4 text-center"><span className="px-3 py-1 bg-amber-50 text-amber-600 rounded-lg text-sm font-black">{p.unitsSold}</span></td>
                      <td className="py-4 text-center text-slate-500 font-black">{p.initialStock}</td>
                      <td className="py-4 text-center text-emerald-600 font-black">{p.finalStock}</td>
                      <td className={`py-4 text-right font-black text-sm ${p.finalStock - p.initialStock < 0 ? 'text-red-500' : 'text-emerald-500'}`}>
                        {p.finalStock - p.initialStock > 0 ? '+' : ''}{p.finalStock - p.initialStock}
                      </td>
                    </tr>
                  ))}
                  {productPeriodStats.length === 0 && (
                    <tr>
                      <td colSpan={5} className="py-20 text-center text-slate-400 font-medium italic">No hay actividad registrada para este periodo</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
            <div className="p-8 border-t bg-slate-50 text-right">
              <button 
                onClick={() => setShowInventoryDetail(false)}
                className="px-12 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all"
              >
                Cerrar Auditoría
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SalesHistory;

export type ProductUnit = 'unit' | 'kg' | 'g' | 'lb' | 'l' | 'ml';

export interface Category {
  id: string;
  name: string;
}

export interface Product {
  id: string;
  name: string;
  categoryId: string;
  code: string;
  image: string; // Base64
  costPrice: number;
  salePrice: number;
  stock: number;
  unit: ProductUnit;
  expiryDate?: string; // YYYY-MM-DD
}

export interface InventoryMovement {
  id: string;
  productId: string;
  quantity: number;
  type: 'in' | 'out';
  reason: string;
  date: number;
}

export interface SaleItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
  unit: ProductUnit;
}

export interface Sale {
  id: string;
  items: SaleItem[];
  total: number;
  paymentMethod: 'cash' | 'transfer';
  date: number;
}

export interface FinancialSettings {
  businessName: string;
  initialInvestment: number;
  workerSalaryRate: number; // e.g., 1.5
}

export interface AutoSaveConfig {
  enabled: boolean;
  lastSaved: number | null;
}

export type Permission = 'pos' | 'inventory' | 'products' | 'stats' | 'insights' | 'sales-history' | 'settings';

export interface Role {
  id: string;
  name: string;
  permissions: Permission[];
}

export interface User {
  id: string;
  username: string;
  roleId: string;
}

import React, { useState, useRef } from 'react';
import { Plus, Search, Edit2, Trash2, Camera, X, Check, FolderPlus, RefreshCcw, Calendar, Scale } from 'lucide-react';
import { Product, Category, ProductUnit } from '../types';

interface ProductsProps {
  products: Product[];
  categories: Category[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  setCategories: React.Dispatch<React.SetStateAction<Category[]>>;
  addMovement: (productId: string, quantity: number, type: 'in' | 'out', reason: string) => void;
}

const Products: React.FC<ProductsProps> = ({ products, categories, setProducts, setCategories, addMovement }) => {
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const videoRef = useRef<HTMLVideoElement>(null);

  const [formData, setFormData] = useState<{
    name: string;
    categoryId: string;
    code: string;
    image: string;
    costPrice: number;
    salePrice: number;
    stock: number;
    unit: ProductUnit;
    expiryDate: string;
  }>({
    name: '',
    categoryId: '',
    code: '',
    image: '',
    costPrice: 0,
    salePrice: 0,
    stock: 0,
    unit: 'unit',
    expiryDate: ''
  });

  const generateSKU = () => {
    return 'GP-' + Math.random().toString(36).substr(2, 7).toUpperCase();
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const startCamera = async () => {
    setIsCameraActive(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      alert("Acceso a cámara denegado o no disponible");
      setIsCameraActive(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current?.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setIsCameraActive(false);
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0);
        setFormData(prev => ({ ...prev, image: canvas.toDataURL('image/jpeg') }));
        stopCamera();
      }
    }
  };

  const handleCreateCategory = () => {
    if (!newCategoryName.trim()) return;
    const newCat: Category = {
      id: Math.random().toString(36).substr(2, 9),
      name: newCategoryName
    };
    setCategories(prev => [...prev, newCat]);
    setFormData(prev => ({ ...prev, categoryId: newCat.id }));
    setNewCategoryName('');
    setIsAddingCategory(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.categoryId) return alert("Selecciona una categoría");

    if (editingId) {
      setProducts(prev => prev.map(p => p.id === editingId ? { ...formData, id: editingId } : p));
    } else {
      const newProduct: Product = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      };
      setProducts(prev => [...prev, newProduct]);
      if (newProduct.stock > 0) {
        addMovement(newProduct.id, newProduct.stock, 'in', 'Carga inicial');
      }
    }
    closeModal();
  };

  const openNewProductModal = () => {
    setEditingId(null);
    setFormData({ 
      name: '', 
      categoryId: '', 
      code: generateSKU(), 
      image: '', 
      costPrice: 0, 
      salePrice: 0, 
      stock: 0,
      unit: 'unit',
      expiryDate: ''
    });
    setShowModal(true);
  };

  const closeModal = () => {
    stopCamera();
    setShowModal(false);
    setEditingId(null);
    setIsAddingCategory(false);
    setNewCategoryName('');
    setFormData({ name: '', categoryId: '', code: '', image: '', costPrice: 0, salePrice: 0, stock: 0, unit: 'unit', expiryDate: '' });
  };

  const openEdit = (product: Product) => {
    setEditingId(product.id);
    setFormData({
      ...product,
      expiryDate: product.expiryDate || ''
    });
    setShowModal(true);
  };

  const getExpiryStatus = (date?: string) => {
    if (!date) return null;
    const expiry = new Date(date).getTime();
    const today = new Date().getTime();
    const diff = expiry - today;
    const days = Math.ceil(diff / (1000 * 60 * 60 * 24));

    if (days < 0) return { label: 'Vencido', color: 'bg-red-50 text-red-600' };
    if (days <= 7) return { label: `Vence en ${days}d`, color: 'bg-amber-50 text-amber-600' };
    return { label: `Vence ${date}`, color: 'bg-slate-50 text-slate-500' };
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Catálogo de Alimentos</h2>
          <p className="text-slate-500 font-medium">Gestión de productos, unidades y fechas de vencimiento</p>
        </div>
        <button 
          onClick={openNewProductModal}
          className="flex items-center gap-2 bg-emerald-600 text-white px-8 py-4 rounded-2xl hover:bg-emerald-700 transition-all font-bold shadow-xl shadow-emerald-100"
        >
          <Plus size={24} />
          Nuevo Producto
        </button>
      </div>

      <div className="bg-white p-4 rounded-[2rem] shadow-sm border border-slate-100">
        <div className="relative mb-6">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Buscar por nombre, código o SKU..." 
            className="w-full pl-12 pr-6 py-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-emerald-100 transition-all font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto rounded-2xl">
          <table className="w-full text-left">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-50">
                <th className="pb-4 pl-6">Producto</th>
                <th className="pb-4">SKU / Venc.</th>
                <th className="pb-4">Categoría</th>
                <th className="pb-4 text-right">Venta</th>
                <th className="pb-4 text-center">Stock</th>
                <th className="pb-4 pr-6 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredProducts.map(p => {
                const expiry = getExpiryStatus(p.expiryDate);
                return (
                  <tr key={p.id} className="group hover:bg-slate-50/50 transition-colors">
                    <td className="py-4 pl-6">
                      <div className="flex items-center gap-4">
                        <div className="w-14 h-14 rounded-2xl bg-slate-100 overflow-hidden flex-shrink-0 border-2 border-white shadow-sm">
                          {p.image ? <img src={p.image} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-300"><Camera size={20}/></div>}
                        </div>
                        <div>
                          <p className="font-black text-slate-700">{p.name}</p>
                          <p className="text-[10px] text-slate-400 font-bold uppercase">Unidad: {p.unit}</p>
                        </div>
                      </div>
                    </td>
                    <td className="py-4">
                      <p className="text-slate-400 font-mono text-xs mb-1">{p.code}</p>
                      {expiry && (
                        <span className={`px-2 py-0.5 rounded-md text-[9px] font-black uppercase ${expiry.color}`}>
                          {expiry.label}
                        </span>
                      )}
                    </td>
                    <td className="py-4">
                      <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-black uppercase">
                        {categories.find(c => c.id === p.categoryId)?.name || 'Sin Cat.'}
                      </span>
                    </td>
                    <td className="py-4 text-right font-black text-slate-800">${p.salePrice.toLocaleString()}</td>
                    <td className="py-4 text-center">
                      <span className={`inline-flex items-center justify-center min-w-[32px] px-2 py-1 rounded-lg font-black text-xs ${p.stock <= 5 ? 'bg-red-50 text-red-500' : 'bg-slate-100 text-slate-600'}`}>
                        {p.stock} {p.unit !== 'unit' ? p.unit : ''}
                      </span>
                    </td>
                    <td className="py-4 pr-6 text-right space-x-1">
                      <button onClick={() => openEdit(p)} className="p-3 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all"><Edit2 size={18} /></button>
                      <button onClick={() => setProducts(prev => prev.filter(item => item.id !== p.id))} className="p-3 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={18} /></button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
