import React, { useState, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, CreditCard, Banknote, Plus, Minus, Calendar } from 'lucide-react';
import { Product, Category, Sale, SaleItem } from '../types';

interface POSProps {
  products: Product[];
  categories: Category[];
  onCompleteSale: (sale: Sale) => void;
}

const POS: React.FC<POSProps> = ({ products, categories, onCompleteSale }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'cash' | 'transfer'>('cash');

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm);
      const matchesCategory = selectedCategory === 'all' || p.categoryId === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchTerm, selectedCategory]);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) {
      alert("Producto sin stock");
      return;
    }
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      if (existing.quantity >= product.stock) {
        alert("No hay más stock disponible");
        return;
      }
      setCart(cart.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { 
        productId: product.id, 
        name: product.name, 
        price: product.salePrice, 
        quantity: 1,
        unit: product.unit
      }]);
    }
  };

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.productId === productId) {
        const newQty = item.quantity + delta;
        const product = products.find(p => p.id === productId);
        if (newQty <= 0) return null;
        if (product && newQty > product.stock) {
          alert("Excede el stock disponible");
          return item;
        }
        return { ...item, quantity: parseFloat(newQty.toFixed(2)) };
      }
      return item;
    }).filter(Boolean) as SaleItem[]);
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;
    const newSale: Sale = {
      id: Math.random().toString(36).substr(2, 9),
      items: [...cart],
      total: cartTotal,
      paymentMethod,
      date: Date.now()
    };
    onCompleteSale(newSale);
    setCart([]);
    alert("Venta realizada con éxito");
  };

  const isNearExpiry = (date?: string) => {
    if (!date) return false;
    const expiry = new Date(date).getTime();
    const diff = expiry - new Date().getTime();
    return diff < (1000 * 60 * 60 * 24 * 7); // 7 days
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
      {/* Product Selection */}
      <div className="lg:col-span-8 flex flex-col space-y-4">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar producto o código..." 
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="px-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            <option value="all">Todas las categorías</option>
            {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto no-scrollbar">
          {filteredProducts.map(product => {
            const nearExpiry = isNearExpiry(product.expiryDate);
            return (
              <button
                key={product.id}
                onClick={() => addToCart(product)}
                className={`bg-white p-3 rounded-2xl shadow-sm border-2 transition-all text-left group flex flex-col ${product.stock <= 0 ? 'opacity-50 grayscale border-transparent' : 'border-transparent hover:border-emerald-300'} ${nearExpiry && product.stock > 0 ? 'border-amber-200' : ''}`}
              >
                <div className="aspect-square rounded-xl bg-slate-100 mb-3 overflow-hidden relative">
                  {product.image ? (
                    <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-slate-300">
                      <ShoppingCart size={32} />
                    </div>
                  )}
                  <div className="absolute bottom-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded-lg text-[10px] font-bold text-emerald-600 shadow-sm">
                    Stock: {product.stock} {product.unit !== 'unit' ? product.unit : ''}
                  </div>
                  {nearExpiry && product.stock > 0 && (
                    <div className="absolute top-2 left-2 bg-amber-500 text-white px-2 py-1 rounded-lg text-[9px] font-black uppercase flex items-center gap-1">
                      <Calendar size={10} /> Proximo a Vencer
                    </div>
                  )}
                </div>
                <h3 className="font-semibold text-slate-800 line-clamp-1 leading-tight">{product.name}</h3>
                <div className="flex justify-between items-end mt-auto pt-2">
                  <p className="text-emerald-600 font-bold">${product.salePrice.toLocaleString()}</p>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{product.unit}</p>
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {/* Cart Panel */}
      <div className="lg:col-span-4 bg-white rounded-3xl shadow-xl border border-slate-100 flex flex-col h-[calc(100vh-8rem)] sticky top-8">
        <div className="p-6 border-b">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <ShoppingCart className="text-emerald-600" />
            Venta Actual
          </h2>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-50 space-y-2">
              <ShoppingCart size={48} />
              <p className="font-bold uppercase tracking-widest text-xs">Carrito vacío</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.productId} className="flex items-center gap-3 p-3 bg-slate-50 rounded-2xl">
                <div className="flex-1">
                  <h4 className="font-medium text-slate-800 line-clamp-1">{item.name}</h4>
                  <p className="text-emerald-600 font-bold text-sm">${(item.price * item.quantity).toLocaleString()}</p>
                </div>
                <div className="flex items-center gap-2 bg-white rounded-xl border border-slate-200 p-1">
                  <button onClick={() => updateCartQuantity(item.productId, -1)} className="p-1 hover:text-emerald-600 transition-colors">
                    <Minus size={14} />
                  </button>
                  <div className="flex flex-col items-center">
                    <span className="w-10 text-center font-black text-sm">{item.quantity}</span>
                    <span className="text-[8px] font-bold text-slate-400 uppercase">{item.unit}</span>
                  </div>
                  <button onClick={() => updateCartQuantity(item.productId, 1)} className="p-1 hover:text-emerald-600 transition-colors">
                    <Plus size={14} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-slate-50 rounded-b-3xl space-y-4 border-t">
          <div className="flex items-center justify-between text-slate-500 text-sm">
            <span className="font-bold uppercase tracking-widest text-[10px]">Subtotal</span>
            <span className="font-bold">${cartTotal.toLocaleString()}</span>
          </div>
          <div className="flex items-center justify-between font-black text-2xl text-slate-800">
            <span>Total</span>
            <span>${cartTotal.toLocaleString()}</span>
          </div>

          <div className="grid grid-cols-2 gap-3 pt-2">
            <button 
              onClick={() => setPaymentMethod('cash')}
              className={`flex flex-col items-center justify-center p-3 rounded-2xl border-2 transition-all ${paymentMethod === 'cash' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-white border-transparent text-slate-400'}`}
            >
              <Banknote size={20} />
              <span className="text-[10px] font-black mt-1 uppercase tracking-widest">Efectivo</span>
            </button>
            <button 
              onClick={() => setPaymentMethod('transfer')}
              className={`flex flex-col items-center justify-center p-3 rounded-2xl border-2 transition-all ${paymentMethod === 'transfer' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-white border-transparent text-slate-400'}`}
            >
              <CreditCard size={20} />
              <span className="text-[10px] font-black mt-1 uppercase tracking-widest">Transfer</span>
            </button>
          </div>

          <button 
            disabled={cart.length === 0}
            onClick={handleCheckout}
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 rounded-2xl shadow-lg shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50 disabled:grayscale"
          >
            CONFIRMAR PAGO
          </button>
        </div>
      </div>
    </div>
  );
};

export default POS;

import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  Cell, PieChart, Pie, AreaChart, Area, Legend, LineChart, Line 
} from 'recharts';
import { 
  TrendingUp, Star, Zap, Target, ArrowUpRight, 
  AlertTriangle, Lightbulb, ShoppingBag, Activity, Calendar
} from 'lucide-react';
import { Sale, Product, Category } from '../types';

interface InsightsProps {
  sales: Sale[];
  products: Product[];
  categories: Category[];
}

const Insights: React.FC<InsightsProps> = ({ sales, products, categories }) => {

  // 1. Top Products (Revenue Drivers)
  const topProducts = useMemo(() => {
    const productStats: Record<string, { name: string, revenue: number, units: number }> = {};

    sales.forEach(sale => {
      sale.items.forEach(item => {
        if (!productStats[item.productId]) {
          productStats[item.productId] = { name: item.name, revenue: 0, units: 0 };
        }
        productStats[item.productId].revenue += item.price * item.quantity;
        productStats[item.productId].units += item.quantity;
      });
    });

    return Object.values(productStats)
      .sort((a, b) => b.revenue - a.revenue)
      .slice(0, 5);
  }, [sales]);

  // 2. Sales by Category
  const categoryMarketShare = useMemo(() => {
    const catStats: Record<string, number> = {};

    sales.forEach(sale => {
      sale.items.forEach(item => {
        const prod = products.find(p => p.id === item.productId);
        const catId = prod?.categoryId || 'unknown';
        const catName = categories.find(c => c.id === catId)?.name || 'Otros';
        catStats[catName] = (catStats[catName] || 0) + (item.price * item.quantity);
      });
    });

    return Object.entries(catStats).map(([name, value]) => ({ name, value }));
  }, [sales, products, categories]);

  // 3. Peak Sales Hours
  const hourlyTraffic = useMemo(() => {
    const hours = Array.from({ length: 24 }, (_, i) => ({ 
      hour: `${i}:00`, 
      sales: 0,
      revenue: 0 
    }));

    sales.forEach(sale => {
      const hour = new Date(sale.date).getHours();
      hours[hour].sales += 1;
      hours[hour].revenue += sale.total;
    });

    return hours.filter(h => h.sales > 0 || (parseInt(h.hour) > 8 && parseInt(h.hour) < 22));
  }, [sales]);

  // 4. Expiry Risk
  const expiryRiskData = useMemo(() => {
    const today = new Date().getTime();
    const weekFromNow = today + (7 * 24 * 60 * 60 * 1000);
    const monthFromNow = today + (30 * 24 * 60 * 60 * 1000);

    const expired = products.filter(p => p.expiryDate && new Date(p.expiryDate).getTime() < today);
    const critical = products.filter(p => p.expiryDate && new Date(p.expiryDate).getTime() >= today && new Date(p.expiryDate).getTime() <= weekFromNow);
    const warning = products.filter(p => p.expiryDate && new Date(p.expiryDate).getTime() > weekFromNow && new Date(p.expiryDate).getTime() <= monthFromNow);

    return [
      { name: 'Vencidos', value: expired.length, color: '#ef4444' },
      { name: 'Críticos (7d)', value: critical.length, color: '#f59e0b' },
      { name: 'Próximos (30d)', value: warning.length, color: '#3b82f6' }
    ].filter(d => d.value > 0);
  }, [products]);

  // 5. Strategic Metrics
  const kpis = useMemo(() => {
    const totalRevenue = sales.reduce((acc, s) => acc + s.total, 0);
    const totalCost = sales.reduce((acc, s) => {
      return acc + s.items.reduce((itemAcc, item) => {
        const p = products.find(prod => prod.id === item.productId);
        return itemAcc + ((p?.costPrice || 0) * item.quantity);
      }, 0);
    }, 0);

    const avgTicket = sales.length > 0 ? totalRevenue / sales.length : 0;
    const grossMargin = totalRevenue > 0 ? ((totalRevenue - totalCost) / totalRevenue) * 100 : 0;
    const totalSoldUnits = sales.reduce((acc, s) => acc + s.items.reduce((ia, i) => ia + i.quantity, 0), 0);
    const totalStock = products.reduce((acc, p) => acc + p.stock, 0);
    const rotationIndex = totalStock > 0 ? (totalSoldUnits / totalStock) * 100 : 0;

    return { avgTicket, grossMargin, rotationIndex, totalRevenue };
  }, [sales, products]);

  // 6. Intelligent Recommendations
  const recommendations = useMemo(() => {
    const tips = [];

    // Check for high demand low stock
    const hotItemsLowStock = products.filter(p => {
      const sold = sales.reduce((acc, s) => acc + s.items.filter(i => i.productId === p.id).reduce((ia, i) => ia + i.quantity, 0), 0);
      return sold > 5 && p.stock < 10;
    });
    if (hotItemsLowStock.length > 0) {
      tips.push({
        type: 'warning',
        icon: AlertTriangle,
        text: `¡Stock Crítico! "${hotItemsLowStock[0].name}" tiene alta rotación pero pocas existencias.`
      });
    }

    // Expiry warning
    const today = new Date().getTime();
    const nearExpiry = products.filter(p => p.expiryDate && new Date(p.expiryDate).getTime() < today + (1000 * 60 * 60 * 24 * 7));
    if (nearExpiry.length > 0) {
      tips.push({
        type: 'danger',
        icon: Calendar,
        text: `Pérdida Potencial: Tienes ${nearExpiry.length} productos que vencerán esta semana. Considera una oferta relámpago.`
      });
    }

    // Peak Hour suggestion
    const peakHour = [...hourlyTraffic].sort((a, b) => b.revenue - a.revenue)[0];
    if (peakHour) {
      tips.push({
        type: 'success',
        icon: Zap,
        text: `Oportunidad Horaria: Las ${peakHour.hour} concentran la mayor demanda de alimentos.`
      });
    }

    return tips;
  }, [products, sales, hourlyTraffic]);

  const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ec4899', '#6366f1', '#8b5cf6'];

  return (
