import React, { useState, useMemo } from 'react';
import { Calendar, Search, Banknote, CreditCard, ChevronRight, ChevronDown, ReceiptText, FileSpreadsheet, Trash2, X, Box, Info, Clock, CalendarDays } from 'lucide-react';
import { Sale, Product, InventoryMovement } from '../types';

interface SalesHistoryProps {
  sales: Sale[];
  products: Product[];
  movements: InventoryMovement[];
  onDeleteSale: (id: string) => void;
  dateRange: { start: string; end: string };
  setDateRange: React.Dispatch<React.SetStateAction<{ start: string; end: string }>>;
}

const SalesHistory: React.FC<SalesHistoryProps> = ({ sales, products, movements, onDeleteSale, dateRange, setDateRange }) => {
  const [expandedSale, setExpandedSale] = useState<string | null>(null);
  const [showInventoryDetail, setShowInventoryDetail] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const setQuickRange = (range: 'today' | 'yesterday' | 'week' | 'month') => {
    const today = new Date().toISOString().split('T')[0];
    const yesterdayDate = new Date();
    yesterdayDate.setDate(yesterdayDate.getDate() - 1);
    const yesterday = yesterdayDate.toISOString().split('T')[0];

    const lastWeek = new Date();
    lastWeek.setDate(lastWeek.getDate() - 7);

    const lastMonth = new Date();
    lastMonth.setDate(lastMonth.getDate() - 30);

    switch(range) {
      case 'today': setDateRange({ start: today, end: today }); break;
      case 'yesterday': setDateRange({ start: yesterday, end: yesterday }); break;
      case 'week': setDateRange({ start: lastWeek.toISOString().split('T')[0], end: today }); break;
      case 'month': setDateRange({ start: lastMonth.toISOString().split('T')[0], end: today }); break;
    }
  };

  const filteredSales = useMemo(() => {
    const start = new Date(dateRange.start).setHours(0,0,0,0);
    const end = new Date(dateRange.end).setHours(23, 59, 59, 999);

    return sales.filter(s => {
      const matchesDate = s.date >= start && s.date <= end;
      const matchesSearch = s.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           s.items.some(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));
      return matchesDate && matchesSearch;
    }).sort((a, b) => b.date - a.date);
  }, [sales, dateRange, searchTerm]);

  // Agrupar ventas por día
  const groupedSales = useMemo(() => {
    const groups: Record<string, { sales: Sale[], total: number }> = {};
    filteredSales.forEach(sale => {
      const dateKey = new Date(sale.date).toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
      if (!groups[dateKey]) groups[dateKey] = { sales: [], total: 0 };
      groups[dateKey].sales.push(sale);
      groups[dateKey].total += sale.total;
    });
    return groups;
  }, [filteredSales]);

  const stats = useMemo(() => {
    const total = filteredSales.reduce((acc, s) => acc + s.total, 0);
    const cash = filteredSales.filter(s => s.paymentMethod === 'cash').reduce((acc, s) => acc + s.total, 0);
    const transfer = filteredSales.filter(s => s.paymentMethod === 'transfer').reduce((acc, s) => acc + s.total, 0);
    return { total, cash, transfer };
  }, [filteredSales]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ReceiptText className="text-emerald-600" size={32} />
            Control de Ventas
          </h2>
          <p className="text-slate-500 font-medium">Historial diario y reportes por periodo</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 w-full xl:w-auto">
          <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto overflow-x-auto no-scrollbar">
            <button onClick={() => setQuickRange('today')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${dateRange.start === dateRange.end && dateRange.start === new Date().toISOString().split('T')[0] ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:bg-slate-50'}`}>Hoy</button>
            <button onClick={() => setQuickRange('yesterday')} className="px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50 whitespace-nowrap">Ayer</button>
            <button onClick={() => setQuickRange('week')} className="px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50 whitespace-nowrap">7 Días</button>
            <button onClick={() => setQuickRange('month')} className="px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50 whitespace-nowrap">Mes</button>
          </div>
          <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100 w-full sm:w-auto">
            <Calendar size={18} className="text-slate-400 ml-2" />
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700 w-full sm:w-auto"
              value={dateRange.start}
              onChange={e => setDateRange(prev => ({ ...prev, start: e.target.value }))}
            />
            <span className="text-slate-300">|</span>
            <input 
              type="date" 
              className="bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-700 w-full sm:w-auto"
              value={dateRange.end}
              onChange={e => setDateRange(prev => ({ ...prev, end: e.target.value }))}
            />
          </div>
        </div>
      </header>

      {/* Stats Summary Panel */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-xl text-white flex justify-between items-center overflow-hidden relative">
          <div className="relative z-10">
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Total del Periodo</p>
            <h4 className="text-4xl font-black">${stats.total.toLocaleString()}</h4>
          </div>
          <div className="bg-white/10 p-4 rounded-3xl relative z-10"><Banknote size={32} className="text-emerald-400" /></div>
          <div className="absolute -right-4 -bottom-4 opacity-5 rotate-12"><ReceiptText size={160} /></div>
        </div>
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex items-center gap-6">
          <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-3xl flex items-center justify-center shrink-0"><Banknote size={28} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Efectivo</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.cash.toLocaleString()}</h4>
          </div>
        </div>
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex items-center gap-6">
          <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center shrink-0"><CreditCard size={28} /></div>
          <div>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Transferencia</p>
            <h4 className="text-2xl font-black text-slate-800">${stats.transfer.toLocaleString()}</h4>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="flex justify-between items-center px-4">
          <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
            <Clock className="text-emerald-500" />
            Línea de Tiempo
          </h3>
          <div className="relative max-w-xs w-full">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder="Buscar por ID o producto..." 
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm font-bold shadow-sm focus:ring-4 focus:ring-emerald-50"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {Object.keys(groupedSales).length > 0 ? (
          /* Cast Object.entries result to resolve 'unknown' property access errors on 'data' */
          (Object.entries(groupedSales) as [string, { sales: Sale[], total: number }][]).map(([dateLabel, data]) => (
            <div key={dateLabel} className="space-y-3">
              <div className="flex items-center gap-4 px-4 py-2 bg-slate-100/50 rounded-2xl border border-slate-100/80">
                <CalendarDays className="text-slate-400" size={18} />
                <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest flex-1">{dateLabel}</h4>
                <p className="text-xs font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-lg">SUBTOTAL: ${data.total.toLocaleString()}</p>
              </div>
              <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <tbody className="divide-y divide-slate-50">
                      {data.sales.map(sale => (
                        <React.Fragment key={sale.id}>
                          <tr onClick={() => setExpandedSale(expandedSale === sale.id ? null : sale.id)} className="hover:bg-slate-50 cursor-pointer transition-colors group">
                            <td className="py-5 pl-8 font-mono text-xs font-bold text-slate-400 w-32">#{sale.id.slice(-6)}</td>
                            <td className="py-5 text-sm font-black text-slate-700">
                               <span className="flex items-center gap-2">
                                 <Clock size={14} className="text-slate-300" />
                                 {new Date(sale.date).toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}
                               </span>
                            </td>
                            <td className="py-5">
                              <span className={`px-3 py-1 rounded-xl text-[10px] font-black uppercase ${sale.paymentMethod === 'cash' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                                {sale.paymentMethod === 'cash' ? 'Efectivo' : 'Transferencia'}
                              </span>
                            </td>
                            <td className="py-5 text-right pr-8 font-black text-slate-900 text-lg">${sale.total.toLocaleString()}</td>
                            <td className="py-5 pr-8 w-10">
                              <ChevronDown className={`text-slate-300 transition-transform ${expandedSale === sale.id ? 'rotate-180' : ''}`} size={20} />
                            </td>
                          </tr>
                          {expandedSale === sale.id && (
                            <tr className="bg-slate-50/50">
                              <td colSpan={5} className="p-4 pl-12 pr-8">
                                <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm animate-in slide-in-from-top-2 duration-300">
                                  <div className="flex justify-between items-center mb-6">
                                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Contenido de la Transacción</p>
                                     <button onClick={() => onDeleteSale(sale.id)} className="text-red-400 hover:text-white hover:bg-red-500 text-[10px] font-black uppercase flex items-center gap-2 px-4 py-2 border border-red-100 rounded-xl transition-all"><Trash2 size={12}/> Anular Venta</button>
                                  </div>
                                  <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-3">
                                    {sale.items.map((item, idx) => (
                                      <div key={idx} className="flex justify-between py-3 border-b border-slate-50 last:border-0 md:last:border-b">
                                        <div className="flex flex-col">
                                          <span className="text-sm font-bold text-slate-700">{item.name}</span>
                                          <span className="text-[10px] font-black text-slate-400 uppercase">Cantidad: {item.quantity} {item.unit}</span>
                                        </div>
                                        <span className="font-black text-slate-800 self-center">${(item.price * item.quantity).toLocaleString()}</span>
                                      </div>
                                    ))}
                                  </div>
                                </div>
                              </td>
                            </tr>
                          )}
                        </React.Fragment>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-24 flex flex-col items-center justify-center text-slate-300 bg-white rounded-[3rem] border border-slate-100 border-dashed">
            <ReceiptText size={64} className="mb-4 opacity-20" />
            <p className="font-black uppercase tracking-widest text-xs">No hay ventas en este periodo</p>
            <p className="text-xs font-medium text-slate-400 mt-2">Prueba seleccionando otro rango de fechas arriba</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SalesHistory;
